{
  "name": "LinenLogic - Skincare Towel Business Manager",
  "description": "A comprehensive inventory and sales management system for a wholesale/retail towel business. Tracks stock, sales, profits, and expenses with intelligent pricing insights and JSONBin.io integration."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  description: string;
  buyPrice: number;
  sellPrice: number;
  stock: number;
  minStock: number;
  category: string;
}

export interface CartItem extends Product {
  quantity: number;
  discount: number; // Percentage
}

export enum PaymentMethod {
  CASH = 'CASH',
  MOMO = 'MOMO',
  BANK_TRANSFER = 'BANK_TRANSFER',
  OTHER = 'OTHER'
}

export interface Transaction {
  id: string;
  type: 'SALE' | 'PURCHASE'; // Purchase = buying from wholesaler, Sale = selling to customer
  items: {
    productId: string;
    productName: string;
    quantity: number;
    priceAtMoment: number;
    buyPriceAtMoment: number; // To calculate profit later even if prices change
    discount: number;
  }[];
  totalAmount: number;
  profit: number; // Calculated field
  paymentMethod: PaymentMethod;
  date: string;
  notes?: string;
}

export interface Expense {
  id: string;
  description: string;
  amount: number;
  category: 'TRANSPORT' | 'PACKAGING' | 'MARKETING' | 'UTILITIES' | 'OTHER';
  date: string;
}

export interface AppData {
  products: Product[];
  transactions: Transaction[];
  expenses: Expense[];
}

export interface Settings {
  jsonBinId: string;
  jsonBinKey: string;
  currency: string;
}

import { AppData, Settings } from '../types';

const LS_KEY_DATA = 'linen_logic_data';
const LS_KEY_SETTINGS = 'linen_logic_settings';

export const getStoredSettings = (): Settings => {
  const stored = localStorage.getItem(LS_KEY_SETTINGS);
  return stored ? JSON.parse(stored) : { jsonBinId: '', jsonBinKey: '', currency: 'GHS' };
};

export const saveSettings = (settings: Settings) => {
  localStorage.setItem(LS_KEY_SETTINGS, JSON.stringify(settings));
};

export const getInitialData = (): AppData => {
  // Return empty structure, actual load happens in App provider
  return { products: [], transactions: [], expenses: [] };
};

export const loadData = async (settings: Settings): Promise<AppData | null> => {
  // If JSONBin configured, try fetch
  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        headers: {
          'X-Master-Key': settings.jsonBinKey,
        },
      });
      if (!response.ok) throw new Error('Failed to fetch from JSONBin');
      const json = await response.json();
      return json.record as AppData;
    } catch (e) {
      console.error("JSONBin load failed, falling back to local:", e);
    }
  }

  // Fallback to LocalStorage
  const local = localStorage.getItem(LS_KEY_DATA);
  return local ? JSON.parse(local) : null;
};

export const saveData = async (data: AppData, settings: Settings): Promise<boolean> => {
  // Always save local first for speed/backup
  localStorage.setItem(LS_KEY_DATA, JSON.stringify(data));

  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'X-Master-Key': settings.jsonBinKey,
        },
        body: JSON.stringify(data),
      });
      return response.ok;
    } catch (e) {
      console.error("JSONBin save failed:", e);
      return false;
    }
  }
  return true;
};

import { GoogleGenAI } from "@google/genai";
import { AppData } from "../types";

// NOTE: In a real production app, you would proxy this through a backend.
// For this demo, we assume the user might not have set the env var, 
// so we'll check if the key is available. If not, we return a mock/error.

export const generateBusinessInsight = async (data: AppData, apiKey: string): Promise<string> => {
  if (!apiKey) {
    return "Please configure your Google Gemini API Key in the code environment variables (process.env.API_KEY) or Settings to use AI features.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Prepare a summary to reduce token usage
    const productSummary = data.products.map(p => 
      `${p.name}: Stock ${p.stock}, Buy ${p.buyPrice}, Sell ${p.sellPrice}`
    ).join('\n');

    const recentSales = data.transactions
      .filter(t => t.type === 'SALE')
      .slice(0, 20)
      .map(t => `Date: ${t.date}, Profit: ${t.profit}, Total: ${t.totalAmount}`)
      .join('\n');

    const expenses = data.expenses
      .slice(0, 10)
      .map(e => `${e.category}: ${e.amount}`)
      .join('\n');

    const prompt = `
      Act as a senior business consultant for a skincare towel business.
      Analyze the following data snapshot:

      Current Inventory:
      ${productSummary}

      Recent Sales (Last 20):
      ${recentSales}

      Recent Expenses:
      ${expenses}

      Provide a concise 3-point action plan to increase profitability and 1 warning about potential risks (e.g., low stock, low margins). 
      Keep the tone professional yet encouraging.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No insights generated.";

  } catch (error) {
    console.error("Gemini Error:", error);
    return "Unable to generate insights at this time. Please check your internet connection or API Key quota.";
  }
};

import React from 'react';
import { LayoutDashboard, Package, ShoppingCart, DollarSign, Settings as SettingsIcon, TrendingUp } from 'lucide-react';

interface SidebarProps {
  currentPage: string;
  onNavigate: (page: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPage, onNavigate }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'inventory', label: 'Inventory', icon: Package },
    { id: 'sales', label: 'Sales (POS)', icon: ShoppingCart },
    { id: 'expenses', label: 'Expenses', icon: DollarSign },
    { id: 'insights', label: 'AI Insights', icon: TrendingUp },
    { id: 'settings', label: 'Settings', icon: SettingsIcon },
  ];

  return (
    <div className="w-64 bg-slate-900 text-white flex flex-col h-screen fixed left-0 top-0 shadow-xl z-10 hidden md:flex">
      <div className="p-6 border-b border-slate-800">
        <h1 className="text-2xl font-bold text-primary-400">LinenLogic</h1>
        <p className="text-xs text-slate-400 mt-1">Premium Towel Manager</p>
      </div>

      <nav className="flex-1 p-4 space-y-2">
        {menuItems.map((item) => {
          const Icon = item.icon;
          const isActive = currentPage === item.id;
          return (
            <button
              key={item.id}
              onClick={() => onNavigate(item.id)}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
                isActive 
                  ? 'bg-primary text-white font-medium' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Icon size={20} />
              <span>{item.label}</span>
            </button>
          );
        })}
      </nav>

      <div className="p-4 border-t border-slate-800">
        <div className="flex items-center space-x-2 text-slate-400 text-sm">
          <div className="w-2 h-2 rounded-full bg-green-500"></div>
          <span>System Online</span>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useMemo } from 'react';
import { AppData, Settings } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, LineChart, Line } from 'recharts';
import { DollarSign, Package, TrendingUp, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  settings: Settings;
}

const Dashboard: React.FC<DashboardProps> = ({ data, settings }) => {
  const stats = useMemo(() => {
    const totalSales = data.transactions
      .filter(t => t.type === 'SALE')
      .reduce((acc, curr) => acc + curr.totalAmount, 0);

    const totalProfit = data.transactions
      .filter(t => t.type === 'SALE')
      .reduce((acc, curr) => acc + curr.profit, 0);

    const totalExpenses = data.expenses.reduce((acc, curr) => acc + curr.amount, 0);

    const netProfit = totalProfit - totalExpenses;

    const lowStockCount = data.products.filter(p => p.stock <= p.minStock).length;

    return { totalSales, netProfit, lowStockCount, totalExpenses };
  }, [data]);

  const salesData = useMemo(() => {
    // Group sales by date (last 7 days)
    const last7Days = new Array(7).fill(0).map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      return d.toISOString().split('T')[0];
    });

    return last7Days.map(date => {
      const daySales = data.transactions
        .filter(t => t.type === 'SALE' && t.date.startsWith(date))
        .reduce((acc, curr) => acc + curr.totalAmount, 0);
      return { date: date.slice(5), amount: daySales };
    });
  }, [data]);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Business Overview</h2>
        <span className="text-sm text-slate-500">Last updated: {new Date().toLocaleTimeString()}</span>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Total Revenue</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {settings.currency} {stats.totalSales.toLocaleString()}
              </h3>
            </div>
            <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
              <DollarSign size={20} />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Net Profit</p>
              <h3 className={`text-2xl font-bold mt-1 ${stats.netProfit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                {settings.currency} {stats.netProfit.toLocaleString()}
              </h3>
            </div>
            <div className="p-2 bg-green-50 text-green-600 rounded-lg">
              <TrendingUp size={20} />
            </div>
          </div>
          <p className="text-xs text-slate-400 mt-2">After deducting {settings.currency}{stats.totalExpenses} expenses</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Total Products</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {data.products.length}
              </h3>
            </div>
            <div className="p-2 bg-purple-50 text-purple-600 rounded-lg">
              <Package size={20} />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Low Stock Alerts</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {stats.lowStockCount}
              </h3>
            </div>
            <div className={`p-2 rounded-lg ${stats.lowStockCount > 0 ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>
              <AlertTriangle size={20} />
            </div>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Sales Trend (Last 7 Days)</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="date" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="amount" fill="#0d9488" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 overflow-y-auto max-h-[400px]">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Low Stock Warning</h3>
          {data.products.filter(p => p.stock <= p.minStock).length === 0 ? (
            <div className="flex flex-col items-center justify-center h-48 text-slate-400">
              <Package size={48} className="mb-2 opacity-50" />
              <p>All stock levels are healthy</p>
            </div>
          ) : (
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-500">
                <tr>
                  <th className="px-4 py-2 rounded-tl-lg">Product</th>
                  <th className="px-4 py-2">Stock</th>
                  <th className="px-4 py-2 rounded-tr-lg">Min Level</th>
                </tr>
              </thead>
              <tbody>
                {data.products
                  .filter(p => p.stock <= p.minStock)
                  .map(p => (
                    <tr key={p.id} className="border-b border-slate-100 last:border-0">
                      <td className="px-4 py-3 font-medium text-slate-800">{p.name}</td>
                      <td className="px-4 py-3 text-red-600 font-bold">{p.stock}</td>
                      <td className="px-4 py-3 text-slate-500">{p.minStock}</td>
                    </tr>
                  ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { AppData, Product, Settings } from '../types';
import { Plus, Search, Edit2, Trash2, ArrowUpRight } from 'lucide-react';

interface InventoryProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Inventory: React.FC<InventoryProps> = ({ data, onUpdate, settings }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Product>>({
    name: '', category: '', buyPrice: 0, sellPrice: 0, stock: 0, minStock: 5, description: ''
  });

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setEditingProduct(product);
      setFormData(product);
    } else {
      setEditingProduct(null);
      setFormData({ name: '', category: 'General', buyPrice: 0, sellPrice: 0, stock: 0, minStock: 5, description: '' });
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!formData.name || !formData.buyPrice || !formData.sellPrice) return;

    let updatedProducts = [...data.products];
    const newProduct: Product = {
      id: editingProduct ? editingProduct.id : crypto.randomUUID(),
      name: formData.name,
      description: formData.description || '',
      category: formData.category || 'General',
      buyPrice: Number(formData.buyPrice),
      sellPrice: Number(formData.sellPrice),
      stock: Number(formData.stock),
      minStock: Number(formData.minStock),
    };

    if (editingProduct) {
      updatedProducts = updatedProducts.map(p => p.id === editingProduct.id ? newProduct : p);
    } else {
      updatedProducts.push(newProduct);
    }

    onUpdate({ ...data, products: updatedProducts });
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this product?')) {
      onUpdate({ ...data, products: data.products.filter(p => p.id !== id) });
    }
  };

  const calculateMargin = (buy: number, sell: number) => {
    if (!sell) return 0;
    return ((sell - buy) / sell) * 100;
  };

  const filteredProducts = data.products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Margin preview for modal
  const marginPreview = calculateMargin(Number(formData.buyPrice || 0), Number(formData.sellPrice || 0));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Inventory Management</h2>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-primary hover:bg-secondary text-white px-4 py-2 rounded-lg flex items-center space-x-2 transition-colors"
        >
          <Plus size={20} />
          <span>Add New Towel</span>
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-2">
        <Search className="text-slate-400" size={20} />
        <input
          type="text"
          placeholder="Search by name or category..."
          className="flex-1 outline-none text-slate-700"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-sm">
              <tr>
                <th className="px-6 py-4 font-semibold">Product Name</th>
                <th className="px-6 py-4 font-semibold">Category</th>
                <th className="px-6 py-4 font-semibold text-right">Cost</th>
                <th className="px-6 py-4 font-semibold text-right">Price</th>
                <th className="px-6 py-4 font-semibold text-right">Margin</th>
                <th className="px-6 py-4 font-semibold text-center">Stock</th>
                <th className="px-6 py-4 font-semibold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredProducts.map(product => {
                const margin = calculateMargin(product.buyPrice, product.sellPrice);
                return (
                  <tr key={product.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 text-slate-800 font-medium">{product.name}</td>
                    <td className="px-6 py-4 text-slate-500">
                      <span className="px-2 py-1 bg-slate-100 rounded text-xs font-medium">{product.category}</span>
                    </td>
                    <td className="px-6 py-4 text-right text-slate-600">{settings.currency} {product.buyPrice.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right text-slate-800 font-medium">{settings.currency} {product.sellPrice.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right">
                      <span className={`text-xs font-bold px-2 py-1 rounded-full ${margin < 20 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                        {margin.toFixed(1)}%
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={`font-bold ${product.stock <= product.minStock ? 'text-red-600' : 'text-slate-700'}`}>
                        {product.stock}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end space-x-2">
                        <button onClick={() => handleOpenModal(product)} className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                          <Edit2 size={16} />
                        </button>
                        <button onClick={() => handleDelete(product.id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {filteredProducts.length === 0 && (
                <tr>
                  <td colSpan={7} className="text-center py-10 text-slate-400">No products found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden animate-fade-in">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">{editingProduct ? 'Edit Product' : 'Add New Product'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Product Name</label>
                <input 
                  type="text" 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent outline-none"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                  <select 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.category}
                    onChange={e => setFormData({...formData, category: e.target.value})}
                  >
                    <option value="General">General</option>
                    <option value="Face Towel">Face Towel</option>
                    <option value="Bath Towel">Bath Towel</option>
                    <option value="Hand Towel">Hand Towel</option>
                    <option value="Microfiber">Microfiber</option>
                    <option value="Bamboo">Bamboo</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Min Stock Alert</label>
                  <input 
                    type="number" 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.minStock}
                    onChange={e => setFormData({...formData, minStock: Number(e.target.value)})}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 p-4 bg-slate-50 rounded-xl border border-slate-100">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Buy Price (Cost)</label>
                  <input 
                    type="number" 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.buyPrice}
                    onChange={e => setFormData({...formData, buyPrice: Number(e.target.value)})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Sell Price</label>
                  <input 
                    type="number" 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.sellPrice}
                    onChange={e => setFormData({...formData, sellPrice: Number(e.target.value)})}
                  />
                </div>
                <div className="col-span-2">
                  <div className="flex justify-between text-sm mb-1">
                    <span>Projected Margin</span>
                    <span className={marginPreview < 20 ? 'text-red-600 font-bold' : 'text-green-600 font-bold'}>
                      {marginPreview.toFixed(1)}%
                    </span>
                  </div>
                  <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                    <div 
                      className={`h-full ${marginPreview < 20 ? 'bg-red-500' : 'bg-green-500'}`} 
                      style={{ width: `${Math.min(Math.max(marginPreview, 0), 100)}%` }}
                    ></div>
                  </div>
                  {marginPreview < 20 && (
                    <p className="text-xs text-red-500 mt-1">Warning: Profit margin is low.</p>
                  )}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Initial Stock</label>
                <input 
                  type="number" 
                  className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                  value={formData.stock}
                  onChange={e => setFormData({...formData, stock: Number(e.target.value)})}
                />
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 flex justify-end space-x-3">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Cancel
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-primary hover:bg-secondary text-white rounded-lg font-medium"
              >
                Save Product
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, CheckCircle, Search } from 'lucide-react';

interface SalesProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Sales: React.FC<SalesProps> = ({ data, onUpdate, settings }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
  const [checkoutComplete, setCheckoutComplete] = useState(false);

  const availableProducts = useMemo(() => {
    return data.products.filter(p => 
      p.stock > 0 && 
      p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [data.products, searchTerm]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev; // Don't exceed stock
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, discount: 0 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        // Check stock limit for increase
        const product = data.products.find(p => p.id === id);
        if (delta > 0 && product && newQty > product.stock) return item;
        return { ...item, quantity: Math.max(1, newQty) };
      }
      return item;
    }));
  };

  const updateDiscount = (id: string, discount: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, discount: Math.min(100, Math.max(0, discount)) } : item));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => {
      const discountedPrice = item.sellPrice * (1 - item.discount / 100);
      return acc + (discountedPrice * item.quantity);
    }, 0);
  }, [cart]);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const transaction: Transaction = {
      id: crypto.randomUUID(),
      type: 'SALE',
      date: new Date().toISOString(),
      paymentMethod,
      totalAmount: cartTotal,
      profit: 0, // Calculate below
      items: cart.map(item => ({
        productId: item.id,
        productName: item.name,
        quantity: item.quantity,
        priceAtMoment: item.sellPrice,
        buyPriceAtMoment: item.buyPrice,
        discount: item.discount
      }))
    };

    // Calculate Profit
    transaction.profit = transaction.items.reduce((acc, item) => {
      const revenue = (item.priceAtMoment * (1 - item.discount/100)) * item.quantity;
      const cost = item.buyPriceAtMoment * item.quantity;
      return acc + (revenue - cost);
    }, 0);

    // Update Stock
    const updatedProducts = data.products.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: p.stock - cartItem.quantity };
      }
      return p;
    });

    const updatedTransactions = [transaction, ...data.transactions];

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    setCheckoutComplete(true);
    setTimeout(() => {
      setCheckoutComplete(false);
      setCart([]);
    }, 2000);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)] md:flex-row gap-6">
      {/* Product Catalog */}
      <div className="flex-1 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100">
          <h2 className="text-lg font-bold text-slate-800 mb-2">Select Products</h2>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text"
              placeholder="Search inventory..."
              className="w-full pl-10 p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 grid grid-cols-2 lg:grid-cols-3 gap-4 content-start">
          {availableProducts.map(product => (
            <div 
              key={product.id}
              onClick={() => addToCart(product)}
              className="p-3 border border-slate-100 rounded-lg hover:border-primary hover:shadow-md cursor-pointer transition-all bg-white group"
            >
              <h3 className="font-medium text-slate-800 truncate">{product.name}</h3>
              <p className="text-xs text-slate-500 mb-2">{product.category}</p>
              <div className="flex justify-between items-end">
                <span className="font-bold text-primary">{settings.currency} {product.sellPrice}</span>
                <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-600">Stock: {product.stock}</span>
              </div>
            </div>
          ))}
          {availableProducts.length === 0 && (
            <div className="col-span-full text-center text-slate-400 py-10">
              No products found.
            </div>
          )}
        </div>
      </div>

      {/* Cart & Checkout */}
      <div className="w-full md:w-96 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <ShoppingCart size={20} /> Current Sale
          </h2>
          <span className="bg-primary/10 text-primary px-2 py-1 rounded-full text-xs font-bold">
            {cart.reduce((a, b) => a + b.quantity, 0)} Items
          </span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-60">
              <ShoppingCart size={48} />
              <p>Cart is empty</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex flex-col p-3 border border-slate-100 rounded-lg relative group">
                <div className="flex justify-between mb-2">
                  <span className="font-medium text-slate-800">{item.name}</span>
                  <button 
                    onClick={() => removeFromCart(item.id)}
                    className="text-slate-300 hover:text-red-500 transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>

                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2 bg-slate-50 rounded-lg p-1">
                    <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm">
                      <Minus size={14} />
                    </button>
                    <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                    <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm">
                      <Plus size={14} />
                    </button>
                  </div>

                  <div className="flex flex-col items-end">
                    <span className="font-bold text-slate-800">
                      {settings.currency} {(item.sellPrice * (1 - item.discount/100) * item.quantity).toFixed(2)}
                    </span>
                    {item.discount > 0 && (
                      <span className="text-xs text-green-600">-{item.discount}% Off</span>
                    )}
                  </div>
                </div>

                {/* Discount Input */}
                <div className="mt-2 flex items-center gap-2">
                  <label className="text-xs text-slate-400">Discount %:</label>
                  <input 
                    type="number" 
                    min="0" max="100"
                    value={item.discount}
                    onChange={(e) => updateDiscount(item.id, Number(e.target.value))}
                    className="w-16 p-1 text-xs border rounded outline-none text-right"
                  />
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-4 bg-slate-50 border-t border-slate-100 space-y-4">
          <div>
             <label className="block text-sm font-medium text-slate-600 mb-2">Payment Method</label>
             <div className="grid grid-cols-2 gap-2">
               {Object.values(PaymentMethod).map(method => (
                 <button
                   key={method}
                   onClick={() => setPaymentMethod(method)}
                   className={`px-2 py-2 text-xs font-bold rounded-lg border ${
                     paymentMethod === method 
                      ? 'bg-primary text-white border-primary' 
                      : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'
                   }`}
                 >
                   {method.replace('_', ' ')}
                 </button>
               ))}
             </div>
          </div>

          <div className="flex justify-between items-center pt-2">
            <span className="text-slate-500">Total Amount</span>
            <span className="text-2xl font-bold text-slate-900">{settings.currency} {cartTotal.toFixed(2)}</span>
          </div>

          <button
            onClick={handleCheckout}
            disabled={cart.length === 0 || checkoutComplete}
            className={`w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center space-x-2 transition-all ${
              checkoutComplete 
                ? 'bg-green-500 text-white' 
                : cart.length === 0 
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  : 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg hover:shadow-xl'
            }`}
          >
            {checkoutComplete ? (
              <>
                <CheckCircle size={24} />
                <span>Success!</span>
              </>
            ) : (
              <span>Confirm Sale</span>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Sales;

