import React, { useState, useEffect } from 'react';
import { AppData, Settings as SettingsType } from './types';
import { getInitialData, loadData, saveData, getStoredSettings, saveSettings } from './services/storage';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Inventory from './pages/Inventory';
import Sales from './pages/Sales';
import Expenses from './pages/Expenses';
import SettingsPage from './pages/Settings';
import Insights from './pages/Insights';
import { Menu } from 'lucide-react';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [data, setData] = useState<AppData>(getInitialData());
  const [settings, setSettings] = useState<SettingsType>(getStoredSettings());
  const [loading, setLoading] = useState(true);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Initial Data Load
  useEffect(() => {
    const init = async () => {
      setLoading(true);
      const loadedData = await loadData(settings);
      if (loadedData) {
        setData(loadedData);
      }
      setLoading(false);
    };
    init();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  // Save Data when changed (Debounced slightly in real world, but direct here for simplicity)
  const handleDataUpdate = (newData: AppData) => {
    setData(newData);
    saveData(newData, settings);
  };

  const handleSettingsUpdate = (newSettings: SettingsType) => {
    setSettings(newSettings);
    saveSettings(newSettings);
    // Reload data if storage keys changed
    if (newSettings.jsonBinId !== settings.jsonBinId) {
      setLoading(true);
      loadData(newSettings).then(d => {
        if(d) setData(d);
        setLoading(false);
      });
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard data={data} settings={settings} />;
      case 'inventory':
        return <Inventory data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'sales':
        return <Sales data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'expenses':
        return <Expenses data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'insights':
        return <Insights data={data} settings={settings} onUpdateSettings={handleSettingsUpdate} />;
      case 'settings':
        return <SettingsPage settings={settings} onSave={handleSettingsUpdate} />;
      default:
        return <Dashboard data={data} settings={settings} />;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-medium">Loading LinenLogic...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans">
      <Sidebar currentPage={currentPage} onNavigate={(p) => { setCurrentPage(p); setMobileMenuOpen(false); }} />

      {/* Mobile Header */}
      <div className="md:hidden bg-slate-900 text-white p-4 flex justify-between items-center sticky top-0 z-20 shadow-md">
        <h1 className="font-bold text-lg">LinenLogic</h1>
        <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
          <Menu />
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div className="md:hidden fixed inset-0 z-30 bg-slate-900/95 p-4 animate-fade-in">
           <div className="flex justify-end mb-8">
             <button onClick={() => setMobileMenuOpen(false)} className="text-white p-2">Close</button>
           </div>
           <div className="flex flex-col space-y-4">
             {['dashboard', 'inventory', 'sales', 'expenses', 'insights', 'settings'].map(page => (
               <button 
                key={page}
                onClick={() => { setCurrentPage(page); setMobileMenuOpen(false); }}
                className={`text-left text-xl py-2 border-b border-slate-700 ${currentPage === page ? 'text-primary-400 font-bold' : 'text-slate-400'}`}
               >
                 {page.charAt(0).toUpperCase() + page.slice(1)}
               </button>
             ))}
           </div>
        </div>
      )}

      {/* Main Content */}
      <main className="md:ml-64 p-4 md:p-8 min-h-screen">
        {renderPage()}
      </main>
    </div>
  );
};

export default App;

export interface Product {
  id: string;
  name: string;
  description: string;
  buyPrice: number;
  sellPrice: number;
  stock: number;
  minStock: number;
  category: string;
}

export interface CartItem extends Product {
  quantity: number;
  discount: number; // Percentage
}

export enum PaymentMethod {
  CASH = 'CASH',
  MOMO = 'MOMO',
  BANK_TRANSFER = 'BANK_TRANSFER',
  OTHER = 'OTHER'
}

export interface Transaction {
  id: string;
  type: 'SALE' | 'PURCHASE'; // Purchase = buying from wholesaler, Sale = selling to customer
  items: {
    productId: string;
    productName: string;
    quantity: number;
    priceAtMoment: number;
    buyPriceAtMoment: number; // To calculate profit later even if prices change
    discount: number;
  }[];
  totalAmount: number;
  profit: number; // Calculated field
  paymentMethod: PaymentMethod;
  date: string;
  notes?: string;
}

export interface Expense {
  id: string;
  description: string;
  amount: number;
  category: string; // Changed from union type to string to support dynamic categories
  date: string;
}

export interface AppData {
  products: Product[];
  transactions: Transaction[];
  expenses: Expense[];
}

export interface Settings {
  jsonBinId: string;
  jsonBinKey: string;
  currency: string;
  inventoryCategories: string[];
  expenseCategories: string[];
}

import { AppData, Settings } from '../types';

const LS_KEY_DATA = 'linen_logic_data';
const LS_KEY_SETTINGS = 'linen_logic_settings';

const DEFAULT_SETTINGS: Settings = {
  jsonBinId: '',
  jsonBinKey: '',
  currency: 'GHS',
  inventoryCategories: ['Face Towel', 'Bath Towel', 'Hand Towel', 'Microfiber', 'Bamboo', 'Robes', 'Sets'],
  expenseCategories: ['Transport', 'Packaging', 'Marketing', 'Utilities', 'Rent', 'Salaries', 'Other']
};

export const getStoredSettings = (): Settings => {
  const stored = localStorage.getItem(LS_KEY_SETTINGS);
  if (!stored) return DEFAULT_SETTINGS;

  const parsed = JSON.parse(stored);
  // Merge with defaults to ensure new fields exist for existing users
  return { ...DEFAULT_SETTINGS, ...parsed };
};

export const saveSettings = (settings: Settings) => {
  localStorage.setItem(LS_KEY_SETTINGS, JSON.stringify(settings));
};

export const getInitialData = (): AppData => {
  // Return empty structure, actual load happens in App provider
  return { products: [], transactions: [], expenses: [] };
};

export const loadData = async (settings: Settings): Promise<AppData | null> => {
  // If JSONBin configured, try fetch
  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        headers: {
          'X-Master-Key': settings.jsonBinKey,
        },
      });
      if (!response.ok) throw new Error('Failed to fetch from JSONBin');
      const json = await response.json();
      return json.record as AppData;
    } catch (e) {
      console.error("JSONBin load failed, falling back to local:", e);
    }
  }

  // Fallback to LocalStorage
  const local = localStorage.getItem(LS_KEY_DATA);
  return local ? JSON.parse(local) : null;
};

export const saveData = async (data: AppData, settings: Settings): Promise<boolean> => {
  // Always save local first for speed/backup
  localStorage.setItem(LS_KEY_DATA, JSON.stringify(data));

  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'X-Master-Key': settings.jsonBinKey,
        },
        body: JSON.stringify(data),
      });
      return response.ok;
    } catch (e) {
      console.error("JSONBin save failed:", e);
      return false;
    }
  }
  return true;
};

import { GoogleGenAI } from "@google/genai";
import { AppData } from "../types";

// NOTE: In a real production app, you would proxy this through a backend.
// For this demo, we assume the user might not have set the env var, 
// so we'll check if the key is available. If not, we return a mock/error.

export const generateBusinessInsight = async (data: AppData, apiKey: string): Promise<string> => {
  if (!apiKey) {
    return "Please configure your Google Gemini API Key in the code environment variables (process.env.API_KEY) or Settings to use AI features.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Prepare a summary to reduce token usage
    const productSummary = data.products.map(p => 
      `${p.name} (${p.category}): Stock ${p.stock}, Buy ${p.buyPrice}, Sell ${p.sellPrice}`
    ).join('\n');

    const recentSales = data.transactions
      .filter(t => t.type === 'SALE')
      .slice(0, 20)
      .map(t => `Date: ${t.date}, Items: ${t.items.map(i => i.productName).join(', ')}, Total: ${t.totalAmount}`)
      .join('\n');

    const prompt = `
      You are a specialized business consultant for a skincare and towel business in Ghana. 
      Your goal is to help the owner educate customers on the importance of hygiene and high-quality towels for skincare, and to maximize profits considering local context.

      Context:
      - Location: Ghana (Consider seasons like Harmattan (dry/dusty), Rainy Season, and major events like December in Gh, Easter, Weddings).
      - Business: Buying and selling skincare towels (Wholesale to Retail).

      Data Snapshot:
      Current Inventory:
      ${productSummary}

      Recent Sales (Last 20):
      ${recentSales}

      Task:
      Provide a strategic report covering:
      1. **Customer Education**: Give 2 specific talking points or social media caption ideas that explain why using specific towels (like the ones in stock) helps with acne, sensitive skin, or hygiene, especially given the current weather in Ghana.
      2. **Sales & Marketing Strategy**: Suggest a promotion or bundle based on upcoming events or seasons in Ghana (e.g., "Harmattan Skin Rescue Kit").
      3. **Pricing & Inventory Review**: Analyze the current buy/sell prices. Are margins healthy? Suggest a pricing model tweak or a specific product to push.

      Keep the tone professional, encouraging, and locally relevant. Use markdown for formatting.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No insights generated.";

  } catch (error) {
    console.error("Gemini Error:", error);
    return "Unable to generate insights at this time. Please check your internet connection or API Key quota.";
  }
};

import React, { useState } from 'react';
import { Settings as SettingsType } from '../types';
import { Save, Database, Tag, X, Plus } from 'lucide-react';

interface SettingsProps {
  settings: SettingsType;
  onSave: (settings: SettingsType) => void;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [formData, setFormData] = useState<SettingsType>(settings);
  const [message, setMessage] = useState('');
  const [newInvCat, setNewInvCat] = useState('');
  const [newExpCat, setNewExpCat] = useState('');

  const handleSave = () => {
    onSave(formData);
    setMessage('Settings saved successfully!');
    setTimeout(() => setMessage(''), 3000);
  };

  const addInvCategory = () => {
    if (newInvCat && !formData.inventoryCategories.includes(newInvCat)) {
      setFormData({
        ...formData,
        inventoryCategories: [...formData.inventoryCategories, newInvCat]
      });
      setNewInvCat('');
    }
  };

  const removeInvCategory = (cat: string) => {
    setFormData({
      ...formData,
      inventoryCategories: formData.inventoryCategories.filter(c => c !== cat)
    });
  };

  const addExpCategory = () => {
    if (newExpCat && !formData.expenseCategories.includes(newExpCat)) {
      setFormData({
        ...formData,
        expenseCategories: [...formData.expenseCategories, newExpCat]
      });
      setNewExpCat('');
    }
  };

  const removeExpCategory = (cat: string) => {
    setFormData({
      ...formData,
      expenseCategories: formData.expenseCategories.filter(c => c !== cat)
    });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <h2 className="text-2xl font-bold text-slate-800">System Configuration</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Categories Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 space-y-6">
           <div className="flex items-center space-x-2">
             <Tag className="text-primary" size={24} />
             <h3 className="text-lg font-bold text-slate-700">Categories</h3>
           </div>

           {/* Inventory Categories */}
           <div>
             <label className="block text-sm font-medium text-slate-700 mb-2">Inventory Types</label>
             <div className="flex flex-wrap gap-2 mb-2">
               {formData.inventoryCategories.map(cat => (
                 <span key={cat} className="bg-blue-50 text-blue-700 px-2 py-1 rounded text-sm flex items-center gap-1">
                   {cat}
                   <button onClick={() => removeInvCategory(cat)} className="hover:text-red-500"><X size={12}/></button>
                 </span>
               ))}
             </div>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 className="flex-1 p-2 border border-slate-300 rounded text-sm outline-none"
                 placeholder="New category..."
                 value={newInvCat}
                 onChange={e => setNewInvCat(e.target.value)}
                 onKeyDown={e => e.key === 'Enter' && addInvCategory()}
               />
               <button onClick={addInvCategory} className="bg-slate-100 hover:bg-slate-200 p-2 rounded"><Plus size={16}/></button>
             </div>
           </div>

           {/* Expense Categories */}
           <div>
             <label className="block text-sm font-medium text-slate-700 mb-2">Expense Types</label>
             <div className="flex flex-wrap gap-2 mb-2">
               {formData.expenseCategories.map(cat => (
                 <span key={cat} className="bg-orange-50 text-orange-700 px-2 py-1 rounded text-sm flex items-center gap-1">
                   {cat}
                   <button onClick={() => removeExpCategory(cat)} className="hover:text-red-500"><X size={12}/></button>
                 </span>
               ))}
             </div>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 className="flex-1 p-2 border border-slate-300 rounded text-sm outline-none"
                 placeholder="New category..."
                 value={newExpCat}
                 onChange={e => setNewExpCat(e.target.value)}
