  );
};

export default Settings;

import React, { useMemo } from 'react';
import { AppData, Settings } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, PieChart, Pie, Cell } from 'recharts';
import { DollarSign, Package, TrendingUp, AlertTriangle, Wallet } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  settings: Settings;
}

const Dashboard: React.FC<DashboardProps> = ({ data, settings }) => {
  const stats = useMemo(() => {
    const totalSales = data.transactions
      .filter(t => t.type === 'SALE')
      .reduce((acc, curr) => acc + curr.totalAmount, 0);

    const totalProfit = data.transactions
      .filter(t => t.type === 'SALE')
      .reduce((acc, curr) => acc + curr.profit, 0);

    const totalExpenses = data.expenses.reduce((acc, curr) => acc + curr.amount, 0);

    const netProfit = totalProfit - totalExpenses;

    const lowStockCount = data.products.filter(p => p.stock <= p.minStock).length;

    // Inventory Valuation
    const inventoryCost = data.products.reduce((acc, p) => acc + (p.buyPrice * p.stock), 0);
    const inventoryPotentialRevenue = data.products.reduce((acc, p) => acc + (p.sellPrice * p.stock), 0);
    const inventoryPotentialProfit = inventoryPotentialRevenue - inventoryCost;

    return { 
      totalSales, 
      netProfit, 
      lowStockCount, 
      totalExpenses, 
      inventoryCost, 
      inventoryPotentialRevenue,
      inventoryPotentialProfit 
    };
  }, [data]);

  const salesData = useMemo(() => {
    // Group sales by date (last 7 days)
    const last7Days = new Array(7).fill(0).map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      return d.toISOString().split('T')[0];
    });

    return last7Days.map(date => {
      const daySales = data.transactions
        .filter(t => t.type === 'SALE' && t.date.startsWith(date))
        .reduce((acc, curr) => acc + curr.totalAmount, 0);
      return { date: date.slice(5), amount: daySales };
    });
  }, [data]);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-2">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Business Overview</h2>
          <p className="text-sm text-slate-500">Track your performance and stock value</p>
        </div>
        <span className="text-xs font-mono bg-slate-100 px-2 py-1 rounded text-slate-500">
          Last updated: {new Date().toLocaleTimeString()}
        </span>
      </div>

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Total Sales Revenue</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {settings.currency} {stats.totalSales.toLocaleString()}
              </h3>
            </div>
            <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
              <DollarSign size={20} />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Net Profit (Actual)</p>
              <h3 className={`text-2xl font-bold mt-1 ${stats.netProfit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
