import React, { useState, useEffect } from 'react';
import { AppData, Settings as SettingsType } from './types';
import { getInitialData, loadData, saveData, getStoredSettings, saveSettings } from './services/storage';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Inventory from './pages/Inventory';
import Sales from './pages/Sales';
import Expenses from './pages/Expenses';
import SettingsPage from './pages/Settings';
import Insights from './pages/Insights';
import { LayoutDashboard, Package, ShoppingCart, DollarSign, TrendingUp, Settings as SettingsIcon } from 'lucide-react';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [data, setData] = useState<AppData>(getInitialData());
  const [settings, setSettings] = useState<SettingsType>(getStoredSettings());
  const [loading, setLoading] = useState(true);

  // Initial Data Load
  useEffect(() => {
    const init = async () => {
      setLoading(true);
      const loadedData = await loadData(settings);
      if (loadedData) {
        setData(loadedData);
      }
      setLoading(false);
    };
    init();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  // Save Data when changed
  const handleDataUpdate = (newData: AppData) => {
    setData(newData);
    saveData(newData, settings);
  };

  const handleSettingsUpdate = (newSettings: SettingsType) => {
    setSettings(newSettings);
    saveSettings(newSettings);
    // Reload data if storage keys changed
    if (newSettings.jsonBinId !== settings.jsonBinId) {
      setLoading(true);
      loadData(newSettings).then(d => {
        if(d) setData(d);
        setLoading(false);
      });
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard data={data} settings={settings} />;
      case 'inventory':
        return <Inventory data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'sales':
        return <Sales data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'expenses':
        return <Expenses data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'insights':
        return <Insights data={data} settings={settings} onUpdateSettings={handleSettingsUpdate} />;
      case 'settings':
        return <SettingsPage settings={settings} onSave={handleSettingsUpdate} data={data} />;
      default:
        return <Dashboard data={data} settings={settings} />;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Home', icon: LayoutDashboard },
    { id: 'inventory', label: 'Stock', icon: Package },
    { id: 'sales', label: 'Sales', icon: ShoppingCart },
    { id: 'expenses', label: 'Costs', icon: DollarSign },
    { id: 'settings', label: 'Config', icon: SettingsIcon },
  ];

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-medium">Loading LinenLogic...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans flex flex-col md:flex-row">
      {/* Desktop Sidebar */}
      <Sidebar currentPage={currentPage} onNavigate={setCurrentPage} />

      {/* Main Content Area */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 min-h-[calc(100vh-80px)] md:min-h-screen pb-24 md:pb-8 overflow-y-auto">
        {renderPage()}
      </main>

      {/* Mobile Bottom Navigation */}
      <div className="md:hidden fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 z-50 px-2 py-2 shadow-lg safe-area-bottom">
        <div className="flex justify-around items-center">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = currentPage === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setCurrentPage(item.id)}
                className={`flex flex-col items-center p-2 rounded-lg transition-colors ${
                  isActive ? 'text-primary' : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                <Icon size={24} strokeWidth={isActive ? 2.5 : 2} />
                <span className="text-[10px] font-medium mt-1">{item.label}</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, CheckCircle, Search, History, RotateCcw, Edit2, Calendar, CreditCard, StickyNote, Save } from 'lucide-react';

interface SalesProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Sales: React.FC<SalesProps> = ({ data, onUpdate, settings }) => {
  const [activeTab, setActiveTab] = useState<'POS' | 'HISTORY'>('POS');

  // POS State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
  const [checkoutComplete, setCheckoutComplete] = useState(false);

  // Edit History State
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [editForm, setEditForm] = useState<{date: string, paymentMethod: PaymentMethod, notes: string}>({
    date: '', paymentMethod: PaymentMethod.CASH, notes: ''
  });

  // --- POS LOGIC ---
  const availableProducts = useMemo(() => {
    return data.products.filter(p => 
      p.stock > 0 && 
      p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [data.products, searchTerm]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev; // Don't exceed stock
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, discount: 0 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const product = data.products.find(p => p.id === id);
        if (delta > 0 && product && newQty > product.stock) return item;
        return { ...item, quantity: Math.max(1, newQty) };
      }
      return item;
    }));
  };

  const updateDiscount = (id: string, discount: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, discount: Math.min(100, Math.max(0, discount)) } : item));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => {
      const discountedPrice = item.sellPrice * (1 - item.discount / 100);
      return acc + (discountedPrice * item.quantity);
    }, 0);
  }, [cart]);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const date = new Date().toISOString();

    // Create individual transactions for each item in the cart
    const newTransactions: Transaction[] = cart.map(item => {
      const revenue = (item.sellPrice * (1 - item.discount / 100)) * item.quantity;
      const cost = item.buyPrice * item.quantity;
      const profit = revenue - cost;

      return {
        id: crypto.randomUUID(),
        type: 'SALE',
        date: date,
        paymentMethod,
        totalAmount: revenue,
        profit: profit,
        items: [{
          productId: item.id,
          productName: item.name,
          quantity: item.quantity,
          priceAtMoment: item.sellPrice,
          buyPriceAtMoment: item.buyPrice,
          discount: item.discount
        }]
      };
    });

    // Update stock for all items
    const updatedProducts = data.products.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: p.stock - cartItem.quantity };
      }
      return p;
    });

    const updatedTransactions = [...newTransactions, ...data.transactions];

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    setCheckoutComplete(true);
    setTimeout(() => {
      setCheckoutComplete(false);
      setCart([]);
    }, 2000);
  };

  // --- HISTORY LOGIC ---
  const handleVoidTransaction = (t: Transaction) => {
    if (!confirm('Are you sure you want to void this transaction? This will restore stock.')) return;

    const updatedProducts = [...data.products];
    t.items.forEach(item => {
      const productIndex = updatedProducts.findIndex(p => p.id === item.productId);
      if (productIndex > -1) {
        updatedProducts[productIndex] = {
          ...updatedProducts[productIndex],
          stock: updatedProducts[productIndex].stock + item.quantity
        };
      }
    });

    const updatedTransactions = data.transactions.filter(tr => tr.id !== t.id);

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });
  };

  const handleEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setEditForm({
      date: t.date.slice(0, 16), // Format for datetime-local
      paymentMethod: t.paymentMethod,
      notes: t.notes || ''
    });
    setIsEditModalOpen(true);
  };

  const saveTransactionEdit = () => {
    if (!editingTransaction) return;

    const updatedTransactions = data.transactions.map(t => {
      if (t.id === editingTransaction.id) {
        return {
          ...t,
          date: new Date(editForm.date).toISOString(),
          paymentMethod: editForm.paymentMethod,
          notes: editForm.notes
        };
      }
      return t;
    });

    onUpdate({ ...data, transactions: updatedTransactions });
    setIsEditModalOpen(false);
    setEditingTransaction(null);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)]">
      {/* Tabs */}
      <div className="flex space-x-4 mb-4 border-b border-slate-200">
        <button
          onClick={() => setActiveTab('POS')}
          className={`pb-2 px-4 font-bold transition-colors ${activeTab === 'POS' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}
        >
          Point of Sale
        </button>
        <button
          onClick={() => setActiveTab('HISTORY')}
          className={`pb-2 px-4 font-bold transition-colors ${activeTab === 'HISTORY' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}
        >
          Sales History
        </button>
      </div>

      {activeTab === 'POS' ? (
        <div className="flex flex-col md:flex-row gap-6 flex-1 overflow-hidden">
          {/* Product Catalog */}
          <div className="flex-1 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100">
              <h2 className="text-lg font-bold text-slate-800 mb-2">Select Products</h2>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text"
                  placeholder="Search inventory..."
                  className="w-full pl-10 p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 grid grid-cols-2 lg:grid-cols-3 gap-4 content-start">
              {availableProducts.map(product => (
                <div 
                  key={product.id}
                  onClick={() => addToCart(product)}
                  className="p-3 border border-slate-100 rounded-lg hover:border-primary hover:shadow-md cursor-pointer transition-all bg-white group"
                >
                  <h3 className="font-medium text-slate-800 truncate">{product.name}</h3>
                  <p className="text-xs text-slate-500 mb-2">{product.category}</p>
                  <div className="flex justify-between items-end">
                    <span className="font-bold text-primary">{settings.currency} {product.sellPrice}</span>
                    <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-600">Stock: {product.stock}</span>
                  </div>
                </div>
              ))}
              {availableProducts.length === 0 && (
                <div className="col-span-full text-center text-slate-400 py-10">
                  No products found.
                </div>
              )}
            </div>
          </div>

          {/* Cart & Checkout */}
          <div className="w-full md:w-96 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <ShoppingCart size={20} /> Current Sale
              </h2>
              <span className="bg-primary/10 text-primary px-2 py-1 rounded-full text-xs font-bold">
                {cart.reduce((a, b) => a + b.quantity, 0)} Items
              </span>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-60">
                  <ShoppingCart size={48} />
                  <p>Cart is empty</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex flex-col p-3 border border-slate-100 rounded-lg relative group">
                    <div className="flex justify-between mb-2">
                      <span className="font-medium text-slate-800">{item.name}</span>
                      <button 
                        onClick={() => removeFromCart(item.id)}
                        className="text-slate-300 hover:text-red-500 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>

                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-2 bg-slate-50 rounded-lg p-1">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Minus size={14} />
                        </button>
                        <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Plus size={14} />
                        </button>
                      </div>

                      <div className="flex flex-col items-end">
                        <span className="font-bold text-slate-800">
                          {settings.currency} {(item.sellPrice * (1 - item.discount/100) * item.quantity).toFixed(2)}
                        </span>
                        {item.discount > 0 && (
                          <span className="text-xs text-green-600">-{item.discount}% Off</span>
                        )}
                      </div>
                    </div>

                    <div className="mt-2 flex items-center gap-2">
                      <label className="text-xs text-slate-400">Discount %:</label>
                      <input 
                        type="number" 
                        min="0" max="100"
                        value={item.discount}
                        onChange={(e) => updateDiscount(item.id, Number(e.target.value))}
                        className="w-16 p-1 text-xs border rounded outline-none text-right"
                      />
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-4 bg-slate-50 border-t border-slate-100 space-y-4">
              <div>
                 <label className="block text-sm font-medium text-slate-600 mb-2">Payment Method</label>
                 <div className="grid grid-cols-2 gap-2">
                   {Object.values(PaymentMethod).map(method => (
                     <button
                       key={method}
                       onClick={() => setPaymentMethod(method)}
                       className={`px-2 py-2 text-xs font-bold rounded-lg border ${
                         paymentMethod === method 
                          ? 'bg-primary text-white border-primary' 
                          : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'
                       }`}
                     >
                       {method.replace('_', ' ')}
                     </button>
                   ))}
                 </div>
              </div>

              <div className="flex justify-between items-center pt-2">
                <span className="text-slate-500">Total Amount</span>
                <span className="text-2xl font-bold text-slate-900">{settings.currency} {cartTotal.toFixed(2)}</span>
              </div>

              <button
                onClick={handleCheckout}
                disabled={cart.length === 0 || checkoutComplete}
                className={`w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center space-x-2 transition-all ${
                  checkoutComplete 
                    ? 'bg-green-500 text-white' 
                    : cart.length === 0 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                      : 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg hover:shadow-xl'
                }`}
              >
                {checkoutComplete ? (
                  <>
                    <CheckCircle size={24} />
                    <span>Success!</span>
                  </>
                ) : (
                  <span>Confirm Sale</span>
                )}
              </button>
            </div>
          </div>
        </div>
      ) : (
        /* HISTORY TAB */
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex-1 overflow-hidden flex flex-col">
          <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
             <h3 className="font-bold text-slate-700 flex items-center gap-2">
               <History size={20} /> Recorded Sales
             </h3>
             <span className="text-sm text-slate-500">
               Total Records: {data.transactions.filter(t => t.type === 'SALE').length}
             </span>
          </div>
          <div className="flex-1 overflow-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-100 text-slate-600 sticky top-0 z-10 text-sm">
                 <tr>
                   <th className="px-6 py-3">Date</th>
                   <th className="px-6 py-3">Items</th>
                   <th className="px-6 py-3">Payment</th>
                   <th className="px-6 py-3 text-right">Amount</th>
                   <th className="px-6 py-3 text-right">Actions</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {data.transactions
                  .filter(t => t.type === 'SALE')
                  .map(t => (
                    <tr key={t.id} className="hover:bg-slate-50">
                      <td className="px-6 py-4 text-sm text-slate-500 whitespace-nowrap">
                        {new Date(t.date).toLocaleString()}
                        {t.notes && <div className="text-xs text-slate-400 mt-1 max-w-[150px] truncate">Note: {t.notes}</div>}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col gap-1">
                          {t.items.map((item, idx) => (
                            <span key={idx} className="text-sm font-medium text-slate-800">
                              {item.productName} <span className="text-slate-500">x{item.quantity}</span>
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-sm">
                        <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs font-bold">
                          {t.paymentMethod}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right font-bold text-slate-900">
                        {settings.currency} {t.totalAmount.toFixed(2)}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                          <button 
                            onClick={() => handleEditTransaction(t)}
                            className="text-blue-500 hover:text-blue-700 hover:bg-blue-50 p-2 rounded transition-colors"
                            title="Edit Record"
                          >
                            <Edit2 size={16} />
                          </button>
                          <button 
                            onClick={() => handleVoidTransaction(t)}
                            className="text-red-500 hover:text-red-700 hover:bg-red-50 p-2 rounded transition-colors"
                            title="Void Transaction"
                          >
                            <RotateCcw size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                ))}
                {data.transactions.filter(t => t.type === 'SALE').length === 0 && (
                  <tr>
                    <td colSpan={5} className="text-center py-10 text-slate-400">
                      No sales recorded yet.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Edit Transaction Modal */}
      {isEditModalOpen && editingTransaction && (
         <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in">
               <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                 <h3 className="font-bold text-slate-800">Edit Transaction</h3>
                 <button onClick={() => setIsEditModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
               </div>
               <div className="p-6 space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                      <Calendar size={14}/> Date & Time
                    </label>
                    <input 
                      type="datetime-local" 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                      value={editForm.date}
                      onChange={e => setEditForm({...editForm, date: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                      <CreditCard size={14}/> Payment Method
                    </label>
                    <select 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                      value={editForm.paymentMethod}
                      onChange={e => setEditForm({...editForm, paymentMethod: e.target.value as PaymentMethod})}
                    >
                       {Object.values(PaymentMethod).map(m => (
                         <option key={m} value={m}>{m}</option>
                       ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                      <StickyNote size={14}/> Notes
                    </label>
                    <textarea 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none h-24 resize-none"
                      value={editForm.notes}
                      onChange={e => setEditForm({...editForm, notes: e.target.value})}
                      placeholder="Optional notes about this sale..."
                    />
                  </div>
                  <div className="flex gap-2 pt-2">
                     <button 
                       onClick={() => setIsEditModalOpen(false)}
                       className="flex-1 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
                     >
                       Cancel
                     </button>
                     <button 
                       onClick={saveTransactionEdit}
                       className="flex-1 py-2 bg-primary hover:bg-secondary text-white rounded-lg font-medium flex justify-center items-center gap-2"
                     >
                       <Save size={18} /> Save Changes
                     </button>
                  </div>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

export default Sales;

export interface Product {
  id: string;
  name: string;
  description: string;
  buyPrice: number;
  sellPrice: number;
  stock: number;
  minStock: number;
  category: string;
}

export interface CartItem extends Product {
  quantity: number;
  discount: number; // Percentage
}

export enum PaymentMethod {
  CASH = 'CASH',
  MOMO = 'MOMO',
  BANK_TRANSFER = 'BANK_TRANSFER',
  OTHER = 'OTHER'
}

export interface Transaction {
  id: string;
  type: 'SALE' | 'PURCHASE'; // Purchase = buying from wholesaler, Sale = selling to customer
  items: {
    productId: string;
    productName: string;
    quantity: number;
    priceAtMoment: number;
    buyPriceAtMoment: number; // To calculate profit later even if prices change
    discount: number;
  }[];
  totalAmount: number;
  profit: number; // Calculated field
  paymentMethod: PaymentMethod;
  date: string;
  notes?: string;
}

export interface Expense {
  id: string;
  description: string;
  amount: number;
  category: string; // Changed from union type to string to support dynamic categories
  date: string;
}

export interface AppData {
  products: Product[];
  transactions: Transaction[];
  expenses: Expense[];
}

export interface Settings {
  jsonBinId: string;
  jsonBinKey: string;
  currency: string;
  inventoryCategories: string[];
  expenseCategories: string[];
  securityPin: string; // New field for PIN protection
}

import { AppData, Settings } from '../types';

const LS_KEY_DATA = 'linen_logic_data';
const LS_KEY_SETTINGS = 'linen_logic_settings';

const DEFAULT_SETTINGS: Settings = {
  jsonBinId: '',
  jsonBinKey: '',
  currency: 'GHS',
  inventoryCategories: ['Face Towel', 'Bath Towel', 'Hand Towel'],
  expenseCategories: ['Transport', 'Packaging', 'Marketing', 'Utilities', 'Rent', 'Salaries', 'Other'],
  securityPin: ''
};

export const getStoredSettings = (): Settings => {
  const stored = localStorage.getItem(LS_KEY_SETTINGS);
  if (!stored) return DEFAULT_SETTINGS;

  const parsed = JSON.parse(stored);
  // Merge with defaults to ensure new fields exist for existing users
  return { ...DEFAULT_SETTINGS, ...parsed };
};

export const saveSettings = (settings: Settings) => {
  localStorage.setItem(LS_KEY_SETTINGS, JSON.stringify(settings));
};

export const getInitialData = (): AppData => {
  // Return empty structure, actual load happens in App provider
  return { products: [], transactions: [], expenses: [] };
};

export const loadData = async (settings: Settings): Promise<AppData | null> => {
  // If JSONBin configured, try fetch
  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        headers: {
          'X-Master-Key': settings.jsonBinKey,
        },
      });
      if (!response.ok) throw new Error('Failed to fetch from JSONBin');
      const json = await response.json();
      return json.record as AppData;
    } catch (e) {
      console.error("JSONBin load failed, falling back to local:", e);
    }
  }

  // Fallback to LocalStorage
  const local = localStorage.getItem(LS_KEY_DATA);
  return local ? JSON.parse(local) : null;
};

export const saveData = async (data: AppData, settings: Settings): Promise<boolean> => {
  // Always save local first for speed/backup
  localStorage.setItem(LS_KEY_DATA, JSON.stringify(data));

  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'X-Master-Key': settings.jsonBinKey,
        },
        body: JSON.stringify(data),
      });
      return response.ok;
    } catch (e) {
      console.error("JSONBin save failed:", e);
      return false;
    }
  }
  return true;
};

import React, { useState } from 'react';
import { Settings as SettingsType, AppData } from '../types';
import { Save, Database, Tag, X, Plus, Download, Lock, Unlock, Shield, ShieldCheck, KeyRound } from 'lucide-react';

interface SettingsProps {
  settings: SettingsType;
  onSave: (settings: SettingsType) => void;
  data: AppData;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave, data }) => {
  const [formData, setFormData] = useState<SettingsType>(settings);
  const [message, setMessage] = useState('');
  const [newInvCat, setNewInvCat] = useState('');
  const [newExpCat, setNewExpCat] = useState('');

  // Security State
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [showPinModal, setShowPinModal] = useState(false);
  const [pinAction, setPinAction] = useState<'UNLOCK' | 'SETUP' | 'CHANGE'>('UNLOCK');
  const [pinInput, setPinInput] = useState('');
  const [pinConfirm, setPinConfirm] = useState('');

  const handleSave = () => {
    onSave(formData);
    setMessage('Settings saved successfully!');
    setTimeout(() => setMessage(''), 3000);
    // Lock again after saving critical data
    if (formData.securityPin) setIsUnlocked(false);
  };

  const handleExport = () => {
    const dataStr = JSON.stringify(data, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `linen_logic_backup_${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    setMessage('Data exported successfully!');
    setTimeout(() => setMessage(''), 3000);
  };

  // --- Category Handlers ---
  const addInvCategory = () => {
    if (newInvCat && !formData.inventoryCategories.includes(newInvCat)) {
      setFormData({
        ...formData,
        inventoryCategories: [...formData.inventoryCategories, newInvCat]
      });
      setNewInvCat('');
    }
  };

  const removeInvCategory = (cat: string) => {
    setFormData({
      ...formData,
      inventoryCategories: formData.inventoryCategories.filter(c => c !== cat)
    });
  };

  const addExpCategory = () => {
    if (newExpCat && !formData.expenseCategories.includes(newExpCat)) {
      setFormData({
        ...formData,
        expenseCategories: [...formData.expenseCategories, newExpCat]
      });
      setNewExpCat('');
    }
  };

  const removeExpCategory = (cat: string) => {
    setFormData({
      ...formData,
      expenseCategories: formData.expenseCategories.filter(c => c !== cat)
    });
  };

  // --- Security Handlers ---
  const initiateUnlock = () => {
    if (!formData.securityPin) {
      setIsUnlocked(true); // No PIN set, just unlock
    } else {
      setPinAction('UNLOCK');
      setPinInput('');
      setShowPinModal(true);
    }
  };

  const initiatePinSetup = () => {
    setPinAction(formData.securityPin ? 'CHANGE' : 'SETUP');
    setPinInput('');
    setPinConfirm('');
    setShowPinModal(true);
  };

  const handlePinSubmit = () => {
    if (pinAction === 'UNLOCK') {
      if (pinInput === formData.securityPin) {
        setIsUnlocked(true);
        setShowPinModal(false);
      } else {
        alert('Incorrect PIN');
        setPinInput('');
      }
    } else if (pinAction === 'SETUP' || pinAction === 'CHANGE') {
      if (pinInput.length < 4) {
        alert('PIN must be at least 4 digits');
        return;
      }
      if (pinInput !== pinConfirm) {
        alert('PINs do not match');
        return;
      }
      // Save PIN immediately to local state, user must click "Save Config" to persist
      setFormData({ ...formData, securityPin: pinInput });
      setShowPinModal(false);
      setMessage(pinAction === 'SETUP' ? 'PIN Set! Click "Save Config" to finish.' : 'PIN Changed! Click "Save Config".');
      setTimeout(() => setMessage(''), 4000);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <h2 className="text-2xl font-bold text-slate-800">System Configuration</h2>

      {/* Security Banner */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex justify-between items-center">
        <div className="flex items-center gap-3">
