      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Categories Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 space-y-6">
           <div className="flex items-center space-x-2">
