               <input 
                 type="text" 
                 className="flex-1 p-2 border border-slate-300 rounded text-sm outline-none"
                 placeholder="New category..."
                 value={newInvCat}
                 onChange={e => setNewInvCat(e.target.value)}
                 onKeyDown={e => e.key === 'Enter' && addInvCategory()}
               />
               <button onClick={addInvCategory} className="bg-slate-100 hover:bg-slate-200 p-2 rounded"><Plus size={16}/></button>
             </div>
           </div>

           {/* Expense Categories */}
           <div>
             <label className="block text-sm font-medium text-slate-700 mb-2">Expense Types</label>
             <div className="flex flex-wrap gap-2 mb-2">
               {formData.expenseCategories.map(cat => (
                 <span key={cat} className="bg-orange-50 text-orange-700 px-2 py-1 rounded text-sm flex items-center gap-1">
                   {cat}
                   <button onClick={() => removeExpCategory(cat)} className="hover:text-red-500"><X size={12}/></button>
                 </span>
               ))}
             </div>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 className="flex-1 p-2 border border-slate-300 rounded text-sm outline-none"
                 placeholder="New category..."
                 value={newExpCat}
                 onChange={e => setNewExpCat(e.target.value)}
                 onKeyDown={e => e.key === 'Enter' && addExpCategory()}
               />
               <button onClick={addExpCategory} className="bg-slate-100 hover:bg-slate-200 p-2 rounded"><Plus size={16}/></button>
             </div>
           </div>
        </div>

        {/* System Settings (Protected) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 space-y-6 relative overflow-hidden">

          <div className="flex justify-between items-start">
             <div className="flex items-center space-x-2 mb-4">
               <Database className="text-primary" size={24} />
               <h3 className="text-lg font-bold text-slate-700">Data Storage</h3>
             </div>
             {formData.securityPin && (
               <button 
                onClick={() => setIsUnlocked(!isUnlocked)}
                className={`p-2 rounded-lg transition-colors ${isUnlocked ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-500'}`}
                title={isUnlocked ? "Lock Settings" : "Unlock Settings"}
               >
                 {isUnlocked ? <Unlock size={20} /> : <Lock size={20} />}
               </button>
             )}
          </div>

          <p className="text-xs text-slate-500 mb-4">
            JSONBin.io Configuration for cloud sync.
            {!isUnlocked && formData.securityPin && " (Hidden for security)"}
          </p>

          <div className={`space-y-4 ${!isUnlocked && formData.securityPin ? 'opacity-50 blur-[2px] pointer-events-none select-none' : ''}`}>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Bin ID</label>
              <input 
                type={isUnlocked ? "text" : "password"}
                value={formData.jsonBinId}
                onChange={e => setFormData({...formData, jsonBinId: e.target.value})}
                className="w-full p-2 border border-slate-300 rounded-lg outline-none font-mono text-sm"
                placeholder="e.g. 660..."
                disabled={!isUnlocked && !!formData.securityPin}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Master API Key</label>
              <input 
                type="password" 
                value={formData.jsonBinKey}
                onChange={e => setFormData({...formData, jsonBinKey: e.target.value})}
                className="w-full p-2 border border-slate-300 rounded-lg outline-none font-mono text-sm"
                placeholder="$2a$10$..."
                disabled={!isUnlocked && !!formData.securityPin}
              />
            </div>
          </div>

          {/* Lock Overlay */}
          {!isUnlocked && formData.securityPin && (
            <div className="absolute inset-0 z-10 flex items-center justify-center top-20 bg-white/30 backdrop-blur-sm">
               <button 
                 onClick={initiateUnlock}
                 className="bg-slate-900 text-white px-6 py-2 rounded-lg font-bold shadow-lg flex items-center gap-2"
               >
                 <KeyRound size={18} /> Unlock Details
               </button>
            </div>
          )}

          <div className="pt-4 border-t border-slate-100">
             <h4 className="text-sm font-medium text-slate-700 mb-2">Data Backup</h4>
             <button
                onClick={handleExport}
                className="w-full bg-slate-100 hover:bg-slate-200 text-slate-700 py-2 rounded-lg font-medium flex justify-center items-center gap-2 transition-colors border border-slate-200"
             >
               <Download size={18} /> Export Data (JSON)
             </button>
          </div>

          <div className="pt-6 border-t border-slate-100">
             <h3 className="text-lg font-bold text-slate-700 mb-4">Preferences</h3>
             <div>
                 <label className="block text-sm font-medium text-slate-700 mb-1">Currency Symbol</label>
                 <input 
                   type="text" 
                   value={formData.currency}
                   onChange={e => setFormData({...formData, currency: e.target.value})}
                   className="w-24 p-2 border border-slate-300 rounded-lg outline-none text-center"
                   placeholder="GHS"
                 />
             </div>
          </div>

          <div className="flex items-center justify-between pt-4">
            <span className="text-green-600 font-medium text-sm">{message}</span>
            <button 
              onClick={handleSave}
              className="bg-primary hover:bg-secondary text-white px-6 py-2 rounded-lg font-medium flex items-center space-x-2 transition-colors"
            >
              <Save size={18} />
              <span>Save Config</span>
            </button>
          </div>
        </div>
      </div>

      {/* PIN Modal */}
      {showPinModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-sm overflow-hidden animate-fade-in">
             <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
               <h3 className="font-bold text-slate-800">
                 {pinAction === 'UNLOCK' ? 'Enter Admin PIN' : 'Set Security PIN'}
               </h3>
               <button onClick={() => setShowPinModal(false)} className="text-slate-400 hover:text-slate-600">✕</button>
             </div>
             <div className="p-6 space-y-4">
                <p className="text-sm text-slate-500">
                  {pinAction === 'UNLOCK' 
                    ? "Enter your security PIN to view/edit sensitive settings."
                    : "Create a PIN to protect your API keys and configuration."}
                </p>

                <input 
                  type="password" 
                  autoFocus
                  placeholder="Enter PIN"
                  className="w-full p-3 text-center text-2xl tracking-widest border border-slate-300 rounded-lg outline-none focus:border-primary"
                  value={pinInput}
                  onChange={e => setPinInput(e.target.value)}
                  maxLength={6}
                />

                {(pinAction === 'SETUP' || pinAction === 'CHANGE') && (
                  <input 
                    type="password" 
                    placeholder="Confirm PIN"
                    className="w-full p-3 text-center text-2xl tracking-widest border border-slate-300 rounded-lg outline-none focus:border-primary"
                    value={pinConfirm}
                    onChange={e => setPinConfirm(e.target.value)}
                    maxLength={6}
                  />
                )}

                <button 
                  onClick={handlePinSubmit}
                  className="w-full py-3 bg-slate-900 text-white rounded-lg font-bold hover:bg-slate-800 transition-colors"
                >
                  {pinAction === 'UNLOCK' ? 'Unlock' : 'Save PIN'}
                </button>
             </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default Settings;

import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, CheckCircle, Search, History, RotateCcw, Edit2, Calendar, CreditCard, StickyNote, Save, CheckSquare, Square } from 'lucide-react';

interface SalesProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Sales: React.FC<SalesProps> = ({ data, onUpdate, settings }) => {
  const [activeTab, setActiveTab] = useState<'POS' | 'HISTORY'>('POS');

  // POS State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
  const [checkoutComplete, setCheckoutComplete] = useState(false);

  // Edit History State
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [editForm, setEditForm] = useState<{date: string, paymentMethod: PaymentMethod, notes: string}>({
    date: '', paymentMethod: PaymentMethod.CASH, notes: ''
  });

  // History Selection State
  const [selectedTransactionIds, setSelectedTransactionIds] = useState<Set<string>>(new Set());

  // --- POS LOGIC ---
  const availableProducts = useMemo(() => {
    return data.products.filter(p => 
      p.stock > 0 && 
      p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [data.products, searchTerm]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev; // Don't exceed stock
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, discount: 0 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const product = data.products.find(p => p.id === id);
        if (delta > 0 && product && newQty > product.stock) return item;
        return { ...item, quantity: Math.max(1, newQty) };
      }
      return item;
    }));
  };

  const updateDiscount = (id: string, discount: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, discount: Math.min(100, Math.max(0, discount)) } : item));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => {
      const discountedPrice = item.sellPrice * (1 - item.discount / 100);
      return acc + (discountedPrice * item.quantity);
    }, 0);
  }, [cart]);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const date = new Date().toISOString();

    // Create individual transactions for each item in the cart
    const newTransactions: Transaction[] = cart.map(item => {
      const revenue = (item.sellPrice * (1 - item.discount / 100)) * item.quantity;
      const cost = item.buyPrice * item.quantity;
      const profit = revenue - cost;

      return {
        id: crypto.randomUUID(),
        type: 'SALE',
        date: date,
        paymentMethod,
        totalAmount: revenue,
        profit: profit,
        items: [{
          productId: item.id,
          productName: item.name,
          quantity: item.quantity,
          priceAtMoment: item.sellPrice,
          buyPriceAtMoment: item.buyPrice,
          discount: item.discount
        }]
      };
    });

    // Update stock for all items
    const updatedProducts = data.products.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: p.stock - cartItem.quantity };
      }
      return p;
    });

    const updatedTransactions = [...newTransactions, ...data.transactions];

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    setCheckoutComplete(true);
    setTimeout(() => {
      setCheckoutComplete(false);
      setCart([]);
    }, 2000);
  };

  // --- HISTORY LOGIC ---
  const salesTransactions = useMemo(() => 
    data.transactions.filter(t => t.type === 'SALE').sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
    [data.transactions]
  );

  const handleVoidTransaction = (t: Transaction) => {
    if (!confirm('Are you sure you want to void this transaction? This will restore stock.')) return;

    const updatedProducts = [...data.products];
    t.items.forEach(item => {
      const productIndex = updatedProducts.findIndex(p => p.id === item.productId);
      if (productIndex > -1) {
        updatedProducts[productIndex] = {
          ...updatedProducts[productIndex],
          stock: updatedProducts[productIndex].stock + item.quantity
        };
      }
    });

    const updatedTransactions = data.transactions.filter(tr => tr.id !== t.id);

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    if (selectedTransactionIds.has(t.id)) {
      const newSet = new Set(selectedTransactionIds);
      newSet.delete(t.id);
      setSelectedTransactionIds(newSet);
    }
  };

  const handleEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setEditForm({
      date: t.date.slice(0, 16), // Format for datetime-local
      paymentMethod: t.paymentMethod,
      notes: t.notes || ''
    });
    setIsEditModalOpen(true);
  };

  const saveTransactionEdit = () => {
    if (!editingTransaction) return;

    const updatedTransactions = data.transactions.map(t => {
      if (t.id === editingTransaction.id) {
        return {
          ...t,
          date: new Date(editForm.date).toISOString(),
          paymentMethod: editForm.paymentMethod,
          notes: editForm.notes
        };
      }
      return t;
    });

    onUpdate({ ...data, transactions: updatedTransactions });
    setIsEditModalOpen(false);
    setEditingTransaction(null);
  };

  // Bulk Handlers
  const handleSelectAllTransactions = () => {
    if (selectedTransactionIds.size === salesTransactions.length && salesTransactions.length > 0) {
      setSelectedTransactionIds(new Set());
    } else {
      setSelectedTransactionIds(new Set(salesTransactions.map(t => t.id)));
    }
  };

  const handleSelectTransaction = (id: string) => {
    const newSet = new Set(selectedTransactionIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedTransactionIds(newSet);
  };

  const handleBulkDeleteTransactions = () => {
    if (confirm(`Are you sure you want to delete ${selectedTransactionIds.size} sales records? This will NOT restore stock (use Void button on individual items for that).`)) {
      const updatedTransactions = data.transactions.filter(t => !selectedTransactionIds.has(t.id));
      onUpdate({ ...data, transactions: updatedTransactions });
      setSelectedTransactionIds(new Set());
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)] relative">
      {/* Tabs */}
      <div className="flex space-x-4 mb-4 border-b border-slate-200">
        <button
          onClick={() => setActiveTab('POS')}
          className={`pb-2 px-4 font-bold transition-colors ${activeTab === 'POS' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}
        >
          Point of Sale
        </button>
        <button
          onClick={() => setActiveTab('HISTORY')}
          className={`pb-2 px-4 font-bold transition-colors ${activeTab === 'HISTORY' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}
        >
          Sales History
        </button>
      </div>

      {activeTab === 'POS' ? (
        <div className="flex flex-col md:flex-row gap-6 flex-1 overflow-hidden">
          {/* Product Catalog */}
          <div className="flex-1 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100">
              <h2 className="text-lg font-bold text-slate-800 mb-2">Select Products</h2>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text"
                  placeholder="Search inventory..."
                  className="w-full pl-10 p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 grid grid-cols-2 lg:grid-cols-3 gap-4 content-start">
              {availableProducts.map(product => (
                <div 
                  key={product.id}
                  onClick={() => addToCart(product)}
                  className="p-3 border border-slate-100 rounded-lg hover:border-primary hover:shadow-md cursor-pointer transition-all bg-white group"
                >
                  <h3 className="font-medium text-slate-800 truncate">{product.name}</h3>
                  <p className="text-xs text-slate-500 mb-2">{product.category}</p>
                  <div className="flex justify-between items-end">
                    <span className="font-bold text-primary">{settings.currency} {product.sellPrice}</span>
                    <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-600">Stock: {product.stock}</span>
                  </div>
                </div>
              ))}
              {availableProducts.length === 0 && (
                <div className="col-span-full text-center text-slate-400 py-10">
                  No products found.
                </div>
              )}
            </div>
          </div>

          {/* Cart & Checkout */}
          <div className="w-full md:w-96 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <ShoppingCart size={20} /> Current Sale
              </h2>
              <span className="bg-primary/10 text-primary px-2 py-1 rounded-full text-xs font-bold">
                {cart.reduce((a, b) => a + b.quantity, 0)} Items
              </span>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-60">
                  <ShoppingCart size={48} />
                  <p>Cart is empty</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex flex-col p-3 border border-slate-100 rounded-lg relative group">
                    <div className="flex justify-between mb-2">
                      <span className="font-medium text-slate-800">{item.name}</span>
                      <button 
                        onClick={() => removeFromCart(item.id)}
                        className="text-slate-300 hover:text-red-500 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>

                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-2 bg-slate-50 rounded-lg p-1">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Minus size={14} />
                        </button>
                        <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Plus size={14} />
                        </button>
                      </div>

                      <div className="flex flex-col items-end">
                        <span className="font-bold text-slate-800">
                          {settings.currency} {(item.sellPrice * (1 - item.discount/100) * item.quantity).toFixed(2)}
                        </span>
                        {item.discount > 0 && (
                          <span className="text-xs text-green-600">-{item.discount}% Off</span>
                        )}
                      </div>
                    </div>

                    <div className="mt-2 flex items-center gap-2">
                      <label className="text-xs text-slate-400">Discount %:</label>
                      <input 
                        type="number" 
                        min="0" max="100"
                        value={item.discount}
                        onChange={(e) => updateDiscount(item.id, Number(e.target.value))}
                        className="w-16 p-1 text-xs border rounded outline-none text-right"
                      />
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-4 bg-slate-50 border-t border-slate-100 space-y-4">
              <div>
                 <label className="block text-sm font-medium text-slate-600 mb-2">Payment Method</label>
                 <div className="grid grid-cols-2 gap-2">
                   {Object.values(PaymentMethod).map(method => (
                     <button
                       key={method}
                       onClick={() => setPaymentMethod(method)}
                       className={`px-2 py-2 text-xs font-bold rounded-lg border ${
                         paymentMethod === method 
                          ? 'bg-primary text-white border-primary' 
                          : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'
                       }`}
                     >
                       {method.replace('_', ' ')}
                     </button>
                   ))}
                 </div>
              </div>

              <div className="flex justify-between items-center pt-2">
                <span className="text-slate-500">Total Amount</span>
                <span className="text-2xl font-bold text-slate-900">{settings.currency} {cartTotal.toFixed(2)}</span>
              </div>

              <button
                onClick={handleCheckout}
                disabled={cart.length === 0 || checkoutComplete}
                className={`w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center space-x-2 transition-all ${
                  checkoutComplete 
                    ? 'bg-green-500 text-white' 
                    : cart.length === 0 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                      : 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg hover:shadow-xl'
                }`}
              >
                {checkoutComplete ? (
                  <>
                    <CheckCircle size={24} />
                    <span>Success!</span>
                  </>
                ) : (
                  <span>Confirm Sale</span>
                )}
              </button>
            </div>
          </div>
        </div>
      ) : (
        /* HISTORY TAB */
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex-1 overflow-hidden flex flex-col relative">

          {/* Bulk Action Bar */}
          {selectedTransactionIds.size > 0 && (
            <div className="bg-slate-900 text-white p-4 absolute top-4 left-4 right-4 rounded-xl shadow-lg flex justify-between items-center z-20 animate-fade-in">
              <div className="flex items-center space-x-4">
                <span className="font-bold">{selectedTransactionIds.size} Selected</span>
                <button onClick={() => setSelectedTransactionIds(new Set())} className="text-slate-400 hover:text-white text-sm">Cancel</button>
              </div>
              <button 
                onClick={handleBulkDeleteTransactions}
                className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-lg flex items-center space-x-2 text-sm font-medium transition-colors"
              >
                <Trash2 size={16} /> <span>Delete Selected</span>
              </button>
            </div>
          )}

          <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
             <h3 className="font-bold text-slate-700 flex items-center gap-2">
               <History size={20} /> Recorded Sales
