    minStock: { enabled: false, value: '' },
    buyPrice: { enabled: false, value: 0 }, 
    sellPrice: { enabled: false, value: 0 }, 
  });

  // --- Search & Filter ---
  const filteredProducts = data.products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Handlers ---
  const handleOpenRestock = (product: Product) => {
    setRestockData({
      productId: product.id,
      quantity: 10,
      unitCost: product.buyPrice,
      sellPrice: product.sellPrice
    });
    setIsRestockModalOpen(true);
  };

  const handleRestockCostChange = (newCost: number) => {
    const product = data.products.find(p => p.id === restockData.productId);
    let suggestedSell = restockData.sellPrice;

    if (product) {
      // Maintain existing margin percentage
      // Markup = Sell / Buy
      const currentMarkup = product.buyPrice > 0 ? (product.sellPrice / product.buyPrice) : 1.4;
      suggestedSell = Math.ceil(newCost * currentMarkup);
    }

    setRestockData(prev => ({
      ...prev,
      unitCost: newCost,
      sellPrice: suggestedSell
    }));
  };

  const handleRestockSubmit = () => {
    const product = data.products.find(p => p.id === restockData.productId);
    if (!product || restockData.quantity <= 0) return;

    // 1. Create a Purchase Transaction Record for history
    const purchaseTx: Transaction = {
      id: crypto.randomUUID(),
      type: 'PURCHASE',
      date: new Date().toISOString(),
      paymentMethod: PaymentMethod.CASH, // Default assuming cash for stock buy
      totalAmount: restockData.quantity * restockData.unitCost,
      profit: 0,
      items: [{
        productId: product.id,
        productName: product.name,
        quantity: restockData.quantity,
        priceAtMoment: 0, // Not selling
        buyPriceAtMoment: restockData.unitCost,
        discount: 0
      }],
      notes: `Restock: Added ${restockData.quantity} units @ ${settings.currency}${restockData.unitCost}. New Price: ${settings.currency}${restockData.sellPrice}`
    };

    // 2. Update Product Stock and Cost and Sell Price
    const updatedProducts = data.products.map(p => {
      if (p.id === restockData.productId) {
        return {
          ...p,
          stock: p.stock + restockData.quantity,
          buyPrice: restockData.unitCost, // Update cost to latest purchase price
          sellPrice: restockData.sellPrice // Update sell price based on suggestion/edit
        };
      }
      return p;
    });

    // 3. Save
    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: [purchaseTx, ...data.transactions]
    });

    setIsRestockModalOpen(false);
  };

  const handleSelectAll = () => {
    if (selectedIds.size === filteredProducts.length && filteredProducts.length > 0) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredProducts.map(p => p.id)));
    }
  };

  const handleSelectRow = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const handleBulkDelete = () => {
    if (confirm(`Are you sure you want to delete ${selectedIds.size} products? This cannot be undone.`)) {
      const updatedProducts = data.products.filter(p => !selectedIds.has(p.id));
      onUpdate({ ...data, products: updatedProducts });
      setSelectedIds(new Set());
    }
  };

  const executeBulkUpdate = () => {
    const updatedProducts = data.products.map(p => {
      if (!selectedIds.has(p.id)) return p;

      let updated = { ...p };

      if (bulkConfig.category.enabled) {
        updated.category = bulkConfig.category.value;
      }
      if (bulkConfig.minStock.enabled && bulkConfig.minStock.value !== '') {
        updated.minStock = Number(bulkConfig.minStock.value);
      }
      if (bulkConfig.buyPrice.enabled && bulkConfig.buyPrice.value !== 0) {
        updated.buyPrice = Math.round(updated.buyPrice * (1 + (bulkConfig.buyPrice.value / 100)) * 100) / 100;
      }
      if (bulkConfig.sellPrice.enabled && bulkConfig.sellPrice.value !== 0) {
        updated.sellPrice = Math.round(updated.sellPrice * (1 + (bulkConfig.sellPrice.value / 100)) * 100) / 100;
      }

      return updated;
    });

    onUpdate({ ...data, products: updatedProducts });
    setIsBulkEditOpen(false);
    setSelectedIds(new Set());
    setBulkConfig({
      category: { enabled: false, value: settings.inventoryCategories[0] || 'General' },
      minStock: { enabled: false, value: '' },
      buyPrice: { enabled: false, value: 0 },
      sellPrice: { enabled: false, value: 0 },
    });
  };

  const handleBuyPriceChange = (val: number) => {
    setFormData(prev => {
      const updates: any = { ...prev, buyPrice: val };
      if (autoPricingEnabled && !editingProduct) {
        updates.sellPrice = Math.ceil(val * 1.4); 
      }
      return updates;
    });
  };

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setEditingProduct(product);
      setFormData(product);
      setAutoPricingEnabled(false);
    } else {
      setEditingProduct(null);
      setFormData({ 
        name: '', 
        category: settings.inventoryCategories[0] || 'General', 
        buyPrice: 0, 
        sellPrice: 0, 
        stock: 0, 
        minStock: 5, 
        description: '' 
      });
      setAutoPricingEnabled(true);
    }
    setIsModalOpen(true);
  };

  const saveProduct = (): Product | null => {
    if (!formData.name || !formData.buyPrice || !formData.sellPrice) return null;

    const newProduct: Product = {
      id: editingProduct ? editingProduct.id : crypto.randomUUID(),
      name: formData.name,
      description: formData.description || '',
      category: formData.category || 'General',
      buyPrice: Number(formData.buyPrice),
      sellPrice: Number(formData.sellPrice),
      stock: Number(formData.stock),
      minStock: Number(formData.minStock),
    };

    let updatedProducts = [...data.products];
    if (editingProduct) {
      updatedProducts = updatedProducts.map(p => p.id === editingProduct.id ? newProduct : p);
    } else {
      updatedProducts.push(newProduct);
    }

    onUpdate({ ...data, products: updatedProducts });
    return newProduct;
  };

  const handleSaveAndClose = () => {
    if (saveProduct()) setIsModalOpen(false);
  };

  const handleSaveAndAddAnother = () => {
    if (saveProduct()) {
      setEditingProduct(null);
      setFormData({ 
        name: '', 
        category: formData.category,
        buyPrice: 0, 
        sellPrice: 0, 
        stock: 0, 
        minStock: 5, 
        description: '' 
      });
      setAutoPricingEnabled(true);
    }
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this product?')) {
      onUpdate({ ...data, products: data.products.filter(p => p.id !== id) });
    }
  };

  const calculateMargin = (buy: number, sell: number) => {
    if (!sell) return 0;
    return ((sell - buy) / sell) * 100;
  };

  const marginPreview = calculateMargin(Number(formData.buyPrice || 0), Number(formData.sellPrice || 0));

  return (
    <div className="space-y-6 relative">
      {/* Bulk Action Bar */}
      {selectedIds.size > 0 && (
        <div className="bg-slate-900 text-white p-4 rounded-xl shadow-lg flex justify-between items-center animate-fade-in sticky top-0 z-20">
          <div className="flex items-center space-x-4">
            <span className="font-bold">{selectedIds.size} Selected</span>
            <button onClick={() => setSelectedIds(new Set())} className="text-slate-400 hover:text-white text-sm">Cancel</button>
          </div>
          <div className="flex space-x-3">
             <button 
               onClick={handleBulkDelete}
               className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-lg flex items-center space-x-2 text-sm font-medium"
             >
               <Trash2 size={16} /> <span>Delete</span>
             </button>
             <button 
               onClick={() => setIsBulkEditOpen(true)}
               className="px-4 py-2 bg-primary hover:bg-secondary rounded-lg flex items-center space-x-2 text-sm font-medium"
             >
               <Settings2 size={16} /> <span>Bulk Edit</span>
             </button>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Inventory Management</h2>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-primary hover:bg-secondary text-white px-4 py-2 rounded-lg flex items-center space-x-2 transition-colors"
        >
          <Plus size={20} />
          <span>Add New Towel</span>
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-2">
        <Search className="text-slate-400" size={20} />
        <input
          type="text"
          placeholder="Search by name or category..."
          className="flex-1 outline-none text-slate-700"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-sm">
              <tr>
                <th className="px-6 py-4 w-12">
                   <button onClick={handleSelectAll} className="flex items-center text-slate-400 hover:text-slate-600">
                     {selectedIds.size > 0 && selectedIds.size === filteredProducts.length ? <CheckSquare size={20} /> : <Square size={20} />}
                   </button>
                </th>
                <th className="px-6 py-4 font-semibold">Product Name</th>
                <th className="px-6 py-4 font-semibold">Category</th>
                <th className="px-6 py-4 font-semibold text-right">Cost</th>
                <th className="px-6 py-4 font-semibold text-right">Price</th>
                <th className="px-6 py-4 font-semibold text-right">Margin</th>
                <th className="px-6 py-4 font-semibold text-center">Stock</th>
                <th className="px-6 py-4 font-semibold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredProducts.map(product => {
                const margin = calculateMargin(product.buyPrice, product.sellPrice);
                const isSelected = selectedIds.has(product.id);
                return (
                  <tr key={product.id} className={`transition-colors ${isSelected ? 'bg-blue-50/50' : 'hover:bg-slate-50'}`}>
                    <td className="px-6 py-4">
                      <button onClick={() => handleSelectRow(product.id)} className={`flex items-center ${isSelected ? 'text-primary' : 'text-slate-300 hover:text-slate-400'}`}>
                        {isSelected ? <CheckSquare size={20} /> : <Square size={20} />}
                      </button>
                    </td>
                    <td className="px-6 py-4 text-slate-800 font-medium">{product.name}</td>
                    <td className="px-6 py-4 text-slate-500">
                      <span className="px-2 py-1 bg-slate-100 rounded text-xs font-medium">{product.category}</span>
                    </td>
                    <td className="px-6 py-4 text-right text-slate-600">{settings.currency} {product.buyPrice.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right text-slate-800 font-medium">{settings.currency} {product.sellPrice.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right">
                      <span className={`text-xs font-bold px-2 py-1 rounded-full ${margin < 20 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                        {margin.toFixed(1)}%
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={`font-bold ${product.stock <= product.minStock ? 'text-red-600' : 'text-slate-700'}`}>
                        {product.stock}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end space-x-1">
                        <button 
                          onClick={() => handleOpenRestock(product)} 
                          className="p-2 text-green-600 hover:bg-green-50 rounded-lg"
                          title="Restock"
                        >
                          <PackagePlus size={16} />
                        </button>
                        <button onClick={() => handleOpenModal(product)} className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                          <Edit2 size={16} />
                        </button>
                        <button onClick={() => handleDelete(product.id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {filteredProducts.length === 0 && (
                <tr>
                  <td colSpan={8} className="text-center py-10 text-slate-400">No products found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Restock Modal */}
      {isRestockModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-sm overflow-hidden animate-fade-in">
             <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
               <h3 className="font-bold text-slate-800">Add Stock & Update Price</h3>
               <button onClick={() => setIsRestockModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
             </div>
             <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Quantity to Add</label>
                  <input 
                    type="number" 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-green-500/20"
                    value={restockData.quantity}
                    onChange={e => setRestockData({...restockData, quantity: Number(e.target.value)})}
                    autoFocus
                  />
               </div>

               <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Unit Cost</label>
                    <input 
                      type="number" 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                      value={restockData.unitCost}
                      onChange={e => handleRestockCostChange(Number(e.target.value))}
                    />
                    <p className="text-[10px] text-slate-400 mt-1">Updates Buy Price</p>
                 </div>
                 <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-1">
                      New Sell Price <TrendingUp size={12} className="text-green-500"/>
                    </label>
                    <input 
                      type="number" 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none font-bold text-slate-800"
                      value={restockData.sellPrice}
                      onChange={e => setRestockData({...restockData, sellPrice: Number(e.target.value)})}
                    />
                 </div>
               </div>

               <button 
                onClick={handleRestockSubmit}
                className="w-full py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg font-medium flex justify-center items-center gap-2"
               >
                 <PackagePlus size={18} /> Confirm Restock
               </button>
             </div>
          </div>
        </div>
      )}

      {/* Single Product Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden animate-fade-in">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">{editingProduct ? 'Edit Product' : 'Add New Product'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Product Name</label>
                <input 
                  type="text" 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent outline-none"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                  <select 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.category}
                    onChange={e => setFormData({...formData, category: e.target.value})}
                  >
                    {settings.inventoryCategories.map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Min Stock Alert</label>
                  <input 
                    type="number" 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.minStock}
                    onChange={e => setFormData({...formData, minStock: Number(e.target.value)})}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 p-4 bg-slate-50 rounded-xl border border-slate-100">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Buy Price (Cost)</label>
                  <input 
                    type="number" 
                    className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                    value={formData.buyPrice}
                    onChange={e => handleBuyPriceChange(Number(e.target.value))}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Sell Price</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                      value={formData.sellPrice}
                      onChange={e => setFormData({...formData, sellPrice: Number(e.target.value)})}
                    />
                    {autoPricingEnabled && !editingProduct && formData.sellPrice > 0 && (
                      <div className="absolute right-2 top-2 text-xs text-green-600 font-bold bg-green-50 px-1 rounded">Suggested</div>
                    )}
                  </div>
                </div>
                <div className="col-span-2">
                  <div className="flex justify-between text-sm mb-1">
                    <span>Projected Margin</span>
                    <span className={marginPreview < 20 ? 'text-red-600 font-bold' : 'text-green-600 font-bold'}>
                      {marginPreview.toFixed(1)}%
                    </span>
                  </div>
                  <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                    <div 
                      className={`h-full ${marginPreview < 20 ? 'bg-red-500' : 'bg-green-500'}`} 
                      style={{ width: `${Math.min(Math.max(marginPreview, 0), 100)}%` }}
                    ></div>
                  </div>
                  {marginPreview < 20 && formData.buyPrice > 0 && (
                    <p className="text-xs text-red-500 mt-1">Warning: Profit margin is low.</p>
                  )}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Stock Quantity</label>
                <input 
                  type="number" 
                  className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                  value={formData.stock}
                  onChange={e => setFormData({...formData, stock: Number(e.target.value)})}
                />
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 flex justify-between">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Cancel
              </button>
              <div className="flex space-x-2">
                {!editingProduct && (
                  <button 
                    onClick={handleSaveAndAddAnother}
                    className="px-4 py-2 text-primary hover:bg-primary/10 rounded-lg font-medium flex items-center"
                  >
                    <Plus size={16} className="mr-1"/> Save & Add Another
                  </button>
                )}
                <button 
                  onClick={handleSaveAndClose}
                  className="px-4 py-2 bg-primary hover:bg-secondary text-white rounded-lg font-medium"
                >
                  Save Product
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Bulk Edit Modal */}
      {isBulkEditOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden animate-fade-in">
             <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
               <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                 <Settings2 size={20} /> Bulk Edit ({selectedIds.size} items)
               </h3>
               <button onClick={() => setIsBulkEditOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
             </div>

             <div className="p-6 space-y-6">
                <p className="text-sm text-slate-500">Select fields to update. Only checked fields will be applied.</p>

                {/* Category Update */}
                <div className="flex items-start gap-3">
                   <button 
                    onClick={() => setBulkConfig(prev => ({...prev, category: {...prev.category, enabled: !prev.category.enabled}}))}
                    className={`mt-1 ${bulkConfig.category.enabled ? 'text-primary' : 'text-slate-300'}`}
                   >
                     {bulkConfig.category.enabled ? <CheckSquare size={20} /> : <Square size={20} />}
                   </button>
                   <div className="flex-1">
                     <label className="block text-sm font-medium text-slate-700 mb-1">Change Category</label>
                     <select 
                       className="w-full p-2 border border-slate-300 rounded-lg outline-none disabled:bg-slate-50 disabled:text-slate-400"
                       disabled={!bulkConfig.category.enabled}
                       value={bulkConfig.category.value}
                       onChange={e => setBulkConfig(prev => ({...prev, category: {...prev.category, value: e.target.value}}))}
                     >
                       {settings.inventoryCategories.map(cat => (
                         <option key={cat} value={cat}>{cat}</option>
                       ))}
                     </select>
                   </div>
                </div>

                {/* Min Stock Update */}
                <div className="flex items-start gap-3">
                   <button 
                    onClick={() => setBulkConfig(prev => ({...prev, minStock: {...prev.minStock, enabled: !prev.minStock.enabled}}))}
                    className={`mt-1 ${bulkConfig.minStock.enabled ? 'text-primary' : 'text-slate-300'}`}
                   >
                     {bulkConfig.minStock.enabled ? <CheckSquare size={20} /> : <Square size={20} />}
                   </button>
                   <div className="flex-1">
                     <label className="block text-sm font-medium text-slate-700 mb-1">Set Min Stock Alert</label>
                     <input 
                       type="number" 
                       className="w-full p-2 border border-slate-300 rounded-lg outline-none disabled:bg-slate-50 disabled:text-slate-400"
                       placeholder="e.g. 10"
                       disabled={!bulkConfig.minStock.enabled}
                       value={bulkConfig.minStock.value}
                       onChange={e => setBulkConfig(prev => ({...prev, minStock: {...prev.minStock, value: e.target.value}}))}
                     />
                   </div>
                </div>

                {/* Price Adjustments */}
                <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-100">
                    <div className="flex items-start gap-3">
                       <button 
                        onClick={() => setBulkConfig(prev => ({...prev, buyPrice: {...prev.buyPrice, enabled: !prev.buyPrice.enabled}}))}
                        className={`mt-1 ${bulkConfig.buyPrice.enabled ? 'text-primary' : 'text-slate-300'}`}
                       >
                         {bulkConfig.buyPrice.enabled ? <CheckSquare size={20} /> : <Square size={20} />}
                       </button>
                       <div className="flex-1">
                         <label className="block text-sm font-medium text-slate-700 mb-1">Buy Price % Change</label>
                         <input 
                           type="number" 
                           className="w-full p-2 border border-slate-300 rounded-lg outline-none disabled:bg-slate-50 disabled:text-slate-400"
                           placeholder="e.g. 10 or -5"
                           disabled={!bulkConfig.buyPrice.enabled}
                           value={bulkConfig.buyPrice.value}
                           onChange={e => setBulkConfig(prev => ({...prev, buyPrice: {...prev.buyPrice, value: Number(e.target.value)}}))}
                         />
                         <p className="text-[10px] text-slate-400 mt-1">Positive to increase, negative to decrease.</p>
                       </div>
                    </div>

                    <div className="flex items-start gap-3">
                       <button 
                        onClick={() => setBulkConfig(prev => ({...prev, sellPrice: {...prev.sellPrice, enabled: !prev.sellPrice.enabled}}))}
                        className={`mt-1 ${bulkConfig.sellPrice.enabled ? 'text-primary' : 'text-slate-300'}`}
                       >
                         {bulkConfig.sellPrice.enabled ? <CheckSquare size={20} /> : <Square size={20} />}
                       </button>
                       <div className="flex-1">
                         <label className="block text-sm font-medium text-slate-700 mb-1">Sell Price % Change</label>
                         <input 
                           type="number" 
                           className="w-full p-2 border border-slate-300 rounded-lg outline-none disabled:bg-slate-50 disabled:text-slate-400"
                           placeholder="e.g. 15 or -10"
                           disabled={!bulkConfig.sellPrice.enabled}
                           value={bulkConfig.sellPrice.value}
                           onChange={e => setBulkConfig(prev => ({...prev, sellPrice: {...prev.sellPrice, value: Number(e.target.value)}}))}
                         />
                       </div>
                    </div>
                </div>
             </div>

             <div className="p-6 border-t border-slate-100 flex justify-end gap-3">
                <button 
                  onClick={() => setIsBulkEditOpen(false)}
                  className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
                >
                  Cancel
                </button>
                <button 
                  onClick={executeBulkUpdate}
                  className="px-6 py-2 bg-primary hover:bg-secondary text-white rounded-lg font-medium flex items-center gap-2"
                >
                  <Save size={18} /> Apply Changes
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, CheckCircle, Search, History, RotateCcw, Edit2, Calendar, CreditCard, StickyNote, Save, CheckSquare, Square, X, Filter } from 'lucide-react';

interface SalesProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Sales: React.FC<SalesProps> = ({ data, onUpdate, settings }) => {
  const [activeTab, setActiveTab] = useState<'POS' | 'HISTORY'>('POS');

  // POS State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
  const [checkoutComplete, setCheckoutComplete] = useState(false);

  // Edit History State
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [editForm, setEditForm] = useState<{date: string, paymentMethod: PaymentMethod, notes: string}>({
    date: '', paymentMethod: PaymentMethod.CASH, notes: ''
  });

  // History Selection & Filter State
  const [selectedTransactionIds, setSelectedTransactionIds] = useState<Set<string>>(new Set());
  const [dateFilter, setDateFilter] = useState({ start: '', end: '' });

  // --- POS LOGIC ---
  const availableProducts = useMemo(() => {
    return data.products.filter(p => 
      p.stock > 0 && 
      p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [data.products, searchTerm]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev; // Don't exceed stock
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, discount: 0 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const product = data.products.find(p => p.id === id);
        if (delta > 0 && product && newQty > product.stock) return item;
        return { ...item, quantity: Math.max(1, newQty) };
      }
      return item;
    }));
  };

  const updateDiscount = (id: string, discount: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, discount: Math.min(100, Math.max(0, discount)) } : item));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => {
      const discountedPrice = item.sellPrice * (1 - item.discount / 100);
      return acc + (discountedPrice * item.quantity);
    }, 0);
  }, [cart]);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const date = new Date().toISOString();

    // Create individual transactions for each item in the cart
    const newTransactions: Transaction[] = cart.map(item => {
      const revenue = (item.sellPrice * (1 - item.discount / 100)) * item.quantity;
      const cost = item.buyPrice * item.quantity;
      const profit = revenue - cost;

      return {
        id: crypto.randomUUID(),
        type: 'SALE',
        date: date,
        paymentMethod,
        totalAmount: revenue,
        profit: profit,
        items: [{
          productId: item.id,
          productName: item.name,
          quantity: item.quantity,
          priceAtMoment: item.sellPrice,
          buyPriceAtMoment: item.buyPrice,
          discount: item.discount
        }]
      };
    });

    // Update stock for all items
    const updatedProducts = data.products.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: p.stock - cartItem.quantity };
      }
      return p;
    });

    const updatedTransactions = [...newTransactions, ...data.transactions];

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    setCheckoutComplete(true);
    setTimeout(() => {
      setCheckoutComplete(false);
      setCart([]);
    }, 2000);
  };

  // --- HISTORY LOGIC ---
  const salesTransactions = useMemo(() => {
    let filtered = data.transactions.filter(t => t.type === 'SALE');

    if (dateFilter.start) {
      const start = new Date(dateFilter.start);
      start.setHours(0, 0, 0, 0);
      filtered = filtered.filter(t => new Date(t.date) >= start);
    }

    if (dateFilter.end) {
      const end = new Date(dateFilter.end);
      end.setHours(23, 59, 59, 999);
      filtered = filtered.filter(t => new Date(t.date) <= end);
    }

    return filtered.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [data.transactions, dateFilter]);

  const handleVoidTransaction = (t: Transaction) => {
    if (!confirm('Are you sure you want to void this transaction? This will restore stock.')) return;

    const updatedProducts = [...data.products];
    t.items.forEach(item => {
      const productIndex = updatedProducts.findIndex(p => p.id === item.productId);
      if (productIndex > -1) {
        updatedProducts[productIndex] = {
          ...updatedProducts[productIndex],
          stock: updatedProducts[productIndex].stock + item.quantity
        };
      }
    });

    const updatedTransactions = data.transactions.filter(tr => tr.id !== t.id);

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    if (selectedTransactionIds.has(t.id)) {
      const newSet = new Set(selectedTransactionIds);
      newSet.delete(t.id);
      setSelectedTransactionIds(newSet);
    }
  };

  const handleEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setEditForm({
      date: t.date.slice(0, 16), // Format for datetime-local
      paymentMethod: t.paymentMethod,
      notes: t.notes || ''
    });
    setIsEditModalOpen(true);
  };

  const saveTransactionEdit = () => {
    if (!editingTransaction) return;

    const updatedTransactions = data.transactions.map(t => {
      if (t.id === editingTransaction.id) {
        return {
          ...t,
          date: new Date(editForm.date).toISOString(),
          paymentMethod: editForm.paymentMethod,
          notes: editForm.notes
        };
      }
      return t;
    });

    onUpdate({ ...data, transactions: updatedTransactions });
    setIsEditModalOpen(false);
    setEditingTransaction(null);
  };

  // Bulk Handlers
  const handleSelectAllTransactions = () => {
    if (selectedTransactionIds.size === salesTransactions.length && salesTransactions.length > 0) {
      setSelectedTransactionIds(new Set());
    } else {
      setSelectedTransactionIds(new Set(salesTransactions.map(t => t.id)));
    }
  };

  const handleSelectTransaction = (id: string) => {
    const newSet = new Set(selectedTransactionIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedTransactionIds(newSet);
  };

  const handleBulkDeleteTransactions = () => {
    if (confirm(`Are you sure you want to delete ${selectedTransactionIds.size} sales records? This will NOT restore stock (use Void button on individual items for that).`)) {
      const updatedTransactions = data.transactions.filter(t => !selectedTransactionIds.has(t.id));
      onUpdate({ ...data, transactions: updatedTransactions });
      setSelectedTransactionIds(new Set());
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)] relative">
      {/* Tabs */}
      <div className="flex space-x-4 mb-4 border-b border-slate-200">
        <button
          onClick={() => setActiveTab('POS')}
          className={`pb-2 px-4 font-bold transition-colors ${activeTab === 'POS' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}
        >
          Point of Sale
        </button>
        <button
          onClick={() => setActiveTab('HISTORY')}
          className={`pb-2 px-4 font-bold transition-colors ${activeTab === 'HISTORY' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}
        >
          Sales History
        </button>
      </div>

      {activeTab === 'POS' ? (
        <div className="flex flex-col md:flex-row gap-6 flex-1 overflow-hidden">
          {/* Product Catalog */}
          <div className="flex-1 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100">
              <h2 className="text-lg font-bold text-slate-800 mb-2">Select Products</h2>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text"
                  placeholder="Search inventory..."
                  className="w-full pl-10 p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 grid grid-cols-2 lg:grid-cols-3 gap-4 content-start">
              {availableProducts.map(product => (
                <div 
                  key={product.id}
                  onClick={() => addToCart(product)}
                  className="p-3 border border-slate-100 rounded-lg hover:border-primary hover:shadow-md cursor-pointer transition-all bg-white group"
                >
                  <h3 className="font-medium text-slate-800 truncate">{product.name}</h3>
                  <p className="text-xs text-slate-500 mb-2">{product.category}</p>
                  <div className="flex justify-between items-end">
                    <span className="font-bold text-primary">{settings.currency} {product.sellPrice}</span>
                    <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-600">Stock: {product.stock}</span>
                  </div>
                </div>
              ))}
              {availableProducts.length === 0 && (
                <div className="col-span-full text-center text-slate-400 py-10">
                  No products found.
                </div>
              )}
            </div>
          </div>

          {/* Cart & Checkout */}
          <div className="w-full md:w-96 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <ShoppingCart size={20} /> Current Sale
              </h2>
              <span className="bg-primary/10 text-primary px-2 py-1 rounded-full text-xs font-bold">
                {cart.reduce((a, b) => a + b.quantity, 0)} Items
              </span>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-60">
                  <ShoppingCart size={48} />
                  <p>Cart is empty</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex flex-col p-3 border border-slate-100 rounded-lg relative group">
                    <div className="flex justify-between mb-2">
                      <span className="font-medium text-slate-800">{item.name}</span>
                      <button 
                        onClick={() => removeFromCart(item.id)}
                        className="text-slate-300 hover:text-red-500 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>

                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-2 bg-slate-50 rounded-lg p-1">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Minus size={14} />
                        </button>
                        <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Plus size={14} />
                        </button>
                      </div>

                      <div className="flex flex-col items-end">
                        <span className="font-bold text-slate-800">
                          {settings.currency} {(item.sellPrice * (1 - item.discount/100) * item.quantity).toFixed(2)}
                        </span>
                        {item.discount > 0 && (
                          <span className="text-xs text-green-600">-{item.discount}% Off</span>
                        )}
                      </div>
                    </div>

                    <div className="mt-2 flex items-center gap-2">
                      <label className="text-xs text-slate-400">Discount %:</label>
                      <input 
                        type="number" 
                        min="0" max="100"
                        value={item.discount}
                        onChange={(e) => updateDiscount(item.id, Number(e.target.value))}
                        className="w-16 p-1 text-xs border rounded outline-none text-right"
                      />
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-4 bg-slate-50 border-t border-slate-100 space-y-4">
              <div>
                 <label className="block text-sm font-medium text-slate-600 mb-2">Payment Method</label>
                 <div className="grid grid-cols-2 gap-2">
                   {Object.values(PaymentMethod).map(method => (
                     <button
                       key={method}
                       onClick={() => setPaymentMethod(method)}
                       className={`px-2 py-2 text-xs font-bold rounded-lg border ${
                         paymentMethod === method 
                          ? 'bg-primary text-white border-primary' 
                          : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'
                       }`}
                     >
                       {method.replace('_', ' ')}
                     </button>
                   ))}
                 </div>
              </div>

              <div className="flex justify-between items-center pt-2">
                <span className="text-slate-500">Total Amount</span>
                <span className="text-2xl font-bold text-slate-900">{settings.currency} {cartTotal.toFixed(2)}</span>
              </div>

              <button
                onClick={handleCheckout}
                disabled={cart.length === 0 || checkoutComplete}
                className={`w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center space-x-2 transition-all ${
                  checkoutComplete 
                    ? 'bg-green-500 text-white' 
                    : cart.length === 0 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                      : 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg hover:shadow-xl'
                }`}
              >
                {checkoutComplete ? (
                  <>
                    <CheckCircle size={24} />
                    <span>Success!</span>
                  </>
                ) : (
                  <span>Confirm Sale</span>
                )}
              </button>
            </div>
          </div>
        </div>
      ) : (
        /* HISTORY TAB */
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex-1 overflow-hidden flex flex-col relative">

          {/* Bulk Action Bar */}
          {selectedTransactionIds.size > 0 && (
            <div className="bg-slate-900 text-white p-4 absolute top-4 left-4 right-4 rounded-xl shadow-lg flex justify-between items-center z-20 animate-fade-in">
              <div className="flex items-center space-x-4">
                <span className="font-bold">{selectedTransactionIds.size} Selected</span>
                <button onClick={() => setSelectedTransactionIds(new Set())} className="text-slate-400 hover:text-white text-sm">Cancel</button>
              </div>
              <button 
                onClick={handleBulkDeleteTransactions}
                className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-lg flex items-center space-x-2 text-sm font-medium transition-colors"
              >
                <Trash2 size={16} /> <span>Delete Selected</span>
              </button>
            </div>
          )}

          <div className="p-4 border-b border-slate-100 bg-slate-50 flex flex-col sm:flex-row justify-between items-center gap-4">
             <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-start">
               <h3 className="font-bold text-slate-700 flex items-center gap-2">
                 <History size={20} /> Recorded Sales
               </h3>
               <span className="text-sm text-slate-500 bg-slate-100 px-2 py-1 rounded">
                 {salesTransactions.length}
               </span>
             </div>

             {/* Date Filters */}
             <div className="flex items-center gap-2 w-full sm:w-auto">
                <div className="flex items-center bg-white border border-slate-200 rounded-lg p-1 flex-1 sm:flex-none">
                    <span className="text-xs text-slate-400 px-2">From</span>
                    <input 
                        type="date" 
                        className="outline-none text-sm text-slate-600 bg-transparent w-full sm:w-auto"
                        value={dateFilter.start}
                        onChange={e => setDateFilter(prev => ({...prev, start: e.target.value}))}
                    />
                </div>
                <div className="flex items-center bg-white border border-slate-200 rounded-lg p-1 flex-1 sm:flex-none">
                    <span className="text-xs text-slate-400 px-2">To</span>
                    <input 
                        type="date" 
                        className="outline-none text-sm text-slate-600 bg-transparent w-full sm:w-auto"
                        value={dateFilter.end}
                        onChange={e => setDateFilter(prev => ({...prev, end: e.target.value}))}
                    />
                </div>
                {(dateFilter.start || dateFilter.end) && (
                    <button 
                        onClick={() => setDateFilter({start: '', end: ''})}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                        title="Clear Date Filter"
                    >
                        <X size={18} />
                    </button>
                )}
             </div>
          </div>
          <div className="flex-1 overflow-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-100 text-slate-600 sticky top-0 z-10 text-sm">
                 <tr>
                   <th className="px-6 py-3 w-12">
                     <button onClick={handleSelectAllTransactions} className="flex items-center text-slate-400 hover:text-slate-600">
                       {salesTransactions.length > 0 && selectedTransactionIds.size === salesTransactions.length ? <CheckSquare size={20} /> : <Square size={20} />}
                     </button>
                   </th>
                   <th className="px-6 py-3">Date</th>
                   <th className="px-6 py-3">Items</th>
                   <th className="px-6 py-3">Payment</th>
                   <th className="px-6 py-3 text-right">Amount</th>
                   <th className="px-6 py-3 text-right">Actions</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {salesTransactions.map(t => {
                    const isSelected = selectedTransactionIds.has(t.id);
                    return (
                      <tr key={t.id} className={`transition-colors ${isSelected ? 'bg-blue-50/50' : 'hover:bg-slate-50'}`}>
                        <td className="px-6 py-4">
                          <button onClick={() => handleSelectTransaction(t.id)} className={`flex items-center ${isSelected ? 'text-primary' : 'text-slate-300 hover:text-slate-400'}`}>
                            {isSelected ? <CheckSquare size={20} /> : <Square size={20} />}
                          </button>
                        </td>
                        <td className="px-6 py-4 text-sm text-slate-500 whitespace-nowrap">
                          {new Date(t.date).toLocaleString()}
                          {t.notes && <div className="text-xs text-slate-400 mt-1 max-w-[150px] truncate">Note: {t.notes}</div>}
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex flex-col gap-1">
                            {t.items.map((item, idx) => (
                              <span key={idx} className="text-sm font-medium text-slate-800">
                                {item.productName} <span className="text-slate-500">x{item.quantity}</span>
                              </span>
                            ))}
                          </div>
                        </td>
                        <td className="px-6 py-4 text-sm">
                          <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs font-bold">
                            {t.paymentMethod}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right font-bold text-slate-900">
                          {settings.currency} {t.totalAmount.toFixed(2)}
                        </td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex justify-end gap-2">
                            <button 
                              onClick={() => handleEditTransaction(t)}
                              className="text-blue-500 hover:text-blue-700 hover:bg-blue-50 p-2 rounded transition-colors"
                              title="Edit Record"
                            >
                              <Edit2 size={16} />
                            </button>
                            <button 
                              onClick={() => handleVoidTransaction(t)}
                              className="text-red-500 hover:text-red-700 hover:bg-red-50 p-2 rounded transition-colors"
                              title="Void Transaction (Restores Stock)"
                            >
                              <RotateCcw size={16} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                {salesTransactions.length === 0 && (
                  <tr>
                    <td colSpan={6} className="text-center py-10 text-slate-400">
                      No sales found for selected period.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Edit Transaction Modal */}
      {isEditModalOpen && editingTransaction && (
         <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in">
               <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                 <h3 className="font-bold text-slate-800">Edit Transaction</h3>
                 <button onClick={() => setIsEditModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
               </div>
               <div className="p-6 space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                      <Calendar size={14}/> Date & Time
                    </label>
                    <input 
                      type="datetime-local" 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                      value={editForm.date}
                      onChange={e => setEditForm({...editForm, date: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                      <CreditCard size={14}/> Payment Method
                    </label>
                    <select 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                      value={editForm.paymentMethod}
                      onChange={e => setEditForm({...editForm, paymentMethod: e.target.value as PaymentMethod})}
                    >
                       {Object.values(PaymentMethod).map(m => (
                         <option key={m} value={m}>{m}</option>
                       ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                      <StickyNote size={14}/> Notes
                    </label>
                    <textarea 
                      className="w-full p-2 border border-slate-300 rounded-lg outline-none h-24 resize-none"
                      value={editForm.notes}
                      onChange={e => setEditForm({...editForm, notes: e.target.value})}
                      placeholder="Optional notes about this sale..."
                    />
                  </div>
                  <div className="flex gap-2 pt-2">
                     <button 
                       onClick={() => setIsEditModalOpen(false)}
                       className="flex-1 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
                     >
                       Cancel
                     </button>
                     <button 
                       onClick={saveTransactionEdit}
                       className="flex-1 py-2 bg-primary hover:bg-secondary text-white rounded-lg font-medium flex justify-center items-center gap-2"
                     >
                       <Save size={18} /> Save Changes
                     </button>
                  </div>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

