import React, { useMemo, useState } from 'react';
import { AppData, Settings } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, PieChart, Pie, Cell } from 'recharts';
import { DollarSign, Package, TrendingUp, AlertTriangle, Wallet, CalendarRange } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  settings: Settings;
}

type TimeRange = '2W' | '1M' | '1Q' | '1Y';

const Dashboard: React.FC<DashboardProps> = ({ data, settings }) => {
  const [timeRange, setTimeRange] = useState<TimeRange>('2W');

  const stats = useMemo(() => {
    const now = new Date();
    let startDate = new Date();
    switch(timeRange) {
        case '2W': startDate.setDate(now.getDate() - 14); break;
        case '1M': startDate.setDate(now.getDate() - 30); break;
        case '1Q': startDate.setDate(now.getDate() - 90); break;
        case '1Y': startDate.setFullYear(now.getFullYear() - 1); break;
    }

    // Set to beginning of day to include all txs from that day onwards
    startDate.setHours(0,0,0,0);

    const isInRange = (d: string) => new Date(d) >= startDate;

    const filteredSales = data.transactions.filter(t => t.type === 'SALE' && isInRange(t.date));

    const totalSales = filteredSales.reduce((acc, curr) => acc + curr.totalAmount, 0);
    const totalProfit = filteredSales.reduce((acc, curr) => acc + curr.profit, 0);
    const totalExpenses = data.expenses.filter(e => isInRange(e.date)).reduce((acc, curr) => acc + curr.amount, 0);

    const netProfit = totalProfit - totalExpenses;

    // Inventory stats are point-in-time, so we show current status regardless of time range
    const lowStockCount = data.products.filter(p => p.stock <= p.minStock).length;
    const inventoryCost = data.products.reduce((acc, p) => acc + (p.buyPrice * p.stock), 0);
    const inventoryPotentialRevenue = data.products.reduce((acc, p) => acc + (p.sellPrice * p.stock), 0);
    const inventoryPotentialProfit = inventoryPotentialRevenue - inventoryCost;

    return { 
      totalSales, 
      netProfit, 
      lowStockCount, 
      totalExpenses, 
      inventoryCost, 
      inventoryPotentialRevenue,
      inventoryPotentialProfit 
    };
  }, [data, timeRange]);

  const salesData = useMemo(() => {
    const now = new Date();
    let startDate = new Date();
    let groupByMonth = false;

    switch(timeRange) {
        case '2W': startDate.setDate(now.getDate() - 14); break;
        case '1M': startDate.setDate(now.getDate() - 30); break;
        case '1Q': startDate.setDate(now.getDate() - 90); break;
        case '1Y': startDate.setFullYear(now.getFullYear() - 1); groupByMonth = true; break;
    }
    startDate.setHours(0,0,0,0);

    const filtered = data.transactions.filter(t => t.type === 'SALE' && new Date(t.date) >= startDate);

    // Create aggregations
    const groups: {[key: string]: number} = {};

    // Pre-fill keys to ensure continuous axis
    if (!groupByMonth) {
        // Fill Daily
        for (let d = new Date(startDate); d <= now; d.setDate(d.getDate() + 1)) {
            const key = d.toISOString().split('T')[0];
            groups[key] = 0;
        }
    } else {
        // Fill Monthly
         for (let d = new Date(startDate); d <= now; d.setMonth(d.getMonth() + 1)) {
            const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
            groups[key] = 0;
         }
    }

    filtered.forEach(t => {
        const d = new Date(t.date);
        let key = '';
        if (groupByMonth) {
            key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        } else {
            key = d.toISOString().split('T')[0];
        }

        // Only add if key exists in our pre-filled range (safeguard) or add new
        if (groups[key] !== undefined) {
             groups[key] += t.totalAmount;
        } else {
             groups[key] = t.totalAmount;
        }
    });

    return Object.entries(groups).map(([date, amount]) => ({
        date: groupByMonth ? date : date.slice(5), // Remove Year for daily to save space
        amount
    })).sort((a,b) => a.date.localeCompare(b.date)); // Simple string sort works for ISO formats YYYY-MM and MM-DD
  }, [data, timeRange]);

  const timeRangeLabel = {
    '2W': 'Last 2 Weeks',
    '1M': 'Last 30 Days',
    '1Q': 'Last Quarter',
    '1Y': 'Last Year'
  }[timeRange];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Business Overview</h2>
          <p className="text-sm text-slate-500">Performance for {timeRangeLabel}</p>
        </div>

        <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
           {(['2W', '1M', '1Q', '1Y'] as TimeRange[]).map((r) => (
             <button
               key={r}
               onClick={() => setTimeRange(r)}
               className={`px-3 py-1 text-sm font-bold rounded-md transition-colors ${
                 timeRange === r 
                   ? 'bg-slate-800 text-white shadow' 
                   : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
               }`}
             >
               {r}
             </button>
           ))}
        </div>
      </div>

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Sales ({timeRange})</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {settings.currency} {stats.totalSales.toLocaleString()}
              </h3>
            </div>
            <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
              <DollarSign size={20} />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Net Profit ({timeRange})</p>
              <h3 className={`text-2xl font-bold mt-1 ${stats.netProfit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                {settings.currency} {stats.netProfit.toLocaleString()}
              </h3>
            </div>
            <div className="p-2 bg-green-50 text-green-600 rounded-lg">
              <TrendingUp size={20} />
            </div>
          </div>
          <p className="text-xs text-slate-400 mt-2">Deducted {settings.currency}{stats.totalExpenses} expenses</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Inventory Value (Cost)</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {settings.currency} {stats.inventoryCost.toLocaleString()}
              </h3>
            </div>
            <div className="p-2 bg-orange-50 text-orange-600 rounded-lg">
              <Wallet size={20} />
            </div>
          </div>
          <p className="text-xs text-slate-400 mt-2">Current capital tied in stock</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Low Stock Alerts</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">
                {stats.lowStockCount}
              </h3>
            </div>
            <div className={`p-2 rounded-lg ${stats.lowStockCount > 0 ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>
              <AlertTriangle size={20} />
            </div>
          </div>
        </div>
      </div>

      {/* Inventory Valuation Details */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
         <div className="md:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-semibold text-slate-800 mb-4">Capital vs Revenue ({timeRange})</h3>
            <div className="space-y-6">
              {/* Progress bar for Revenue vs Inventory Cost */}
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-slate-600">Period Sales vs Current Stock Value</span>
                  <span className="font-bold text-slate-800">
                    {Math.round((stats.totalSales / (stats.inventoryCost + stats.totalSales || 1)) * 100)}% Recouped
                  </span>
                </div>
                <div className="h-4 bg-slate-100 rounded-full overflow-hidden flex">
                   <div 
                      className="bg-blue-500 h-full" 
                      style={{ width: `${(stats.totalSales / (stats.totalSales + stats.inventoryCost || 1)) * 100}%` }}
                      title={`Sales: ${settings.currency}${stats.totalSales}`}
                   ></div>
                   <div 
                      className="bg-orange-400 h-full" 
                      style={{ width: `${(stats.inventoryCost / (stats.totalSales + stats.inventoryCost || 1)) * 100}%` }}
                      title={`Stock Cost: ${settings.currency}${stats.inventoryCost}`}
                   ></div>
                </div>
                <div className="flex justify-between text-xs text-slate-400 mt-1">
                  <div className="flex items-center gap-1"><div className="w-2 h-2 bg-blue-500 rounded-full"></div> Sales Collected</div>
                  <div className="flex items-center gap-1"><div className="w-2 h-2 bg-orange-400 rounded-full"></div> Stock Value (Cost)</div>
                </div>
              </div>

              {/* Potential Profit */}
              <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                <h4 className="text-sm font-medium text-slate-500 mb-2">Projected Performance (If all current stock sold)</h4>
                <div className="flex justify-between items-end">
                  <div>
                    <div className="text-xs text-slate-400">Total Potential Revenue</div>
                    <div className="text-lg font-bold text-slate-700">{settings.currency} {stats.inventoryPotentialRevenue.toLocaleString()}</div>
                  </div>
                  <div className="text-right">
                    <div className="text-xs text-slate-400">Potential Profit in Stock</div>
                    <div className="text-lg font-bold text-green-600">+{settings.currency} {stats.inventoryPotentialProfit.toLocaleString()}</div>
                  </div>
                </div>
              </div>
            </div>
         </div>

         {/* Sales Chart */}
         <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Sales Trend</h3>
          <div className="h-40">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="date" axisLine={false} tickLine={false} fontSize={10} minTickGap={10} />
                <Tooltip 
                  cursor={{fill: 'transparent'}}
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  formatter={(value) => [`${settings.currency} ${value}`, 'Sales']}
                />
                <Bar dataKey="amount" fill="#0d9488" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 overflow-y-auto max-h-[400px]">
        <h3 className="text-lg font-semibold text-slate-800 mb-4">Low Stock Warning</h3>
        {data.products.filter(p => p.stock <= p.minStock).length === 0 ? (
          <div className="flex flex-col items-center justify-center h-32 text-slate-400">
            <Package size={32} className="mb-2 opacity-50" />
            <p>All stock levels are healthy</p>
          </div>
        ) : (
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500">
              <tr>
                <th className="px-4 py-2 rounded-tl-lg">Product</th>
                <th className="px-4 py-2">Stock</th>
                <th className="px-4 py-2 rounded-tr-lg">Min Level</th>
              </tr>
            </thead>
            <tbody>
              {data.products
                .filter(p => p.stock <= p.minStock)
                .map(p => (
                  <tr key={p.id} className="border-b border-slate-100 last:border-0">
                    <td className="px-4 py-3 font-medium text-slate-800">{p.name}</td>
                    <td className="px-4 py-3 text-red-600 font-bold">{p.stock}</td>
                    <td className="px-4 py-3 text-slate-500">{p.minStock}</td>
                  </tr>
                ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

export interface Product {
  id: string;
  name: string;
  description: string;
  buyPrice: number;
  sellPrice: number;
  stock: number;
  minStock: number;
  category: string;
  lastPriceUpdate?: string; // Tracks when the sell price was last changed
}

export interface CartItem extends Product {
  quantity: number;
  discount: number; // Percentage
}

export enum PaymentMethod {
  CASH = 'CASH',
  MOMO = 'MOMO',
  BANK_TRANSFER = 'BANK_TRANSFER',
  OTHER = 'OTHER'
}

export interface Transaction {
  id: string;
  type: 'SALE' | 'PURCHASE'; // Purchase = buying from wholesaler, Sale = selling to customer
  items: {
    productId: string;
    productName: string;
    quantity: number;
    priceAtMoment: number;
    buyPriceAtMoment: number; // To calculate profit later even if prices change
    discount: number;
  }[];
  totalAmount: number;
  profit: number; // Calculated field
  paymentMethod: PaymentMethod;
  date: string;
  notes?: string;
}

export interface Expense {
  id: string;
  description: string;
  amount: number;
  category: string; // Changed from union type to string to support dynamic categories
  date: string;
}

export interface AppData {
  products: Product[];
  transactions: Transaction[];
  expenses: Expense[];
}

export interface Settings {
  jsonBinId: string;
  jsonBinKey: string;
  currency: string;
  inventoryCategories: string[];
  expenseCategories: string[];
  securityPin: string; // New field for PIN protection
}

import React, { useState } from 'react';
import { AppData, Product, Settings, Transaction, PaymentMethod } from '../types';
import { Plus, Search, Edit2, Trash2, Settings2, Save, CheckSquare, Square, PackagePlus, TrendingUp, Clock } from 'lucide-react';

interface InventoryProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Inventory: React.FC<InventoryProps> = ({ data, onUpdate, settings }) => {
  const [searchTerm, setSearchTerm] = useState('');

  // Modals
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isRestockModalOpen, setIsRestockModalOpen] = useState(false);

  // State
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isBulkEditOpen, setIsBulkEditOpen] = useState(false);
  const [autoPricingEnabled, setAutoPricingEnabled] = useState(true);

  // Forms
  const [formData, setFormData] = useState<Partial<Product>>({
    name: '', category: '', buyPrice: 0, sellPrice: 0, stock: 0, minStock: 5, description: ''
  });

  const [restockData, setRestockData] = useState({
    productId: '',
    quantity: 0,
    unitCost: 0,
    sellPrice: 0
  });

  const [bulkConfig, setBulkConfig] = useState({
    category: { enabled: false, value: settings.inventoryCategories[0] || 'General' },
    minStock: { enabled: false, value: '' },
    buyPrice: { enabled: false, value: 0 }, 
    sellPrice: { enabled: false, value: 0 }, 
  });

  // --- Helpers ---
  const isPriceStale = (dateStr?: string) => {
    if (!dateStr) return false;
    const sixMonthsAgo = new Date();
    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);
    return new Date(dateStr) < sixMonthsAgo;
  };

  // --- Search & Filter ---
  const filteredProducts = data.products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Handlers ---
  const handleOpenRestock = (product: Product) => {
    setRestockData({
      productId: product.id,
      quantity: 10,
      unitCost: product.buyPrice,
      sellPrice: product.sellPrice
    });
    setIsRestockModalOpen(true);
  };

  const handleRestockCostChange = (newCost: number) => {
    const product = data.products.find(p => p.id === restockData.productId);
    let suggestedSell = restockData.sellPrice;

    if (product) {
      // Maintain existing margin percentage
      // Markup = Sell / Buy
      const currentMarkup = product.buyPrice > 0 ? (product.sellPrice / product.buyPrice) : 1.4;
      suggestedSell = Math.ceil(newCost * currentMarkup);
    }

    setRestockData(prev => ({
      ...prev,
      unitCost: newCost,
      sellPrice: suggestedSell
    }));
  };

  const handleRestockSubmit = () => {
    const product = data.products.find(p => p.id === restockData.productId);
    if (!product || restockData.quantity <= 0) return;

    // 1. Create a Purchase Transaction Record for history
    const purchaseTx: Transaction = {
      id: crypto.randomUUID(),
      type: 'PURCHASE',
      date: new Date().toISOString(),
      paymentMethod: PaymentMethod.CASH, // Default assuming cash for stock buy
      totalAmount: restockData.quantity * restockData.unitCost,
      profit: 0,
      items: [{
        productId: product.id,
        productName: product.name,
        quantity: restockData.quantity,
        priceAtMoment: 0, // Not selling
        buyPriceAtMoment: restockData.unitCost,
        discount: 0
      }],
      notes: `Restock: Added ${restockData.quantity} units @ ${settings.currency}${restockData.unitCost}. New Price: ${settings.currency}${restockData.sellPrice}`
    };

    // 2. Update Product Stock and Cost and Sell Price
    const updatedProducts = data.products.map(p => {
      if (p.id === restockData.productId) {
        const priceChanged = p.sellPrice !== restockData.sellPrice;
        return {
          ...p,
          stock: p.stock + restockData.quantity,
          buyPrice: restockData.unitCost, // Update cost to latest purchase price
          sellPrice: restockData.sellPrice, // Update sell price based on suggestion/edit
          lastPriceUpdate: priceChanged ? new Date().toISOString() : p.lastPriceUpdate
        };
      }
      return p;
    });

    // 3. Save
    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: [purchaseTx, ...data.transactions]
    });

    setIsRestockModalOpen(false);
  };

  const handleSelectAll = () => {
    if (selectedIds.size === filteredProducts.length && filteredProducts.length > 0) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredProducts.map(p => p.id)));
    }
  };

  const handleSelectRow = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const handleBulkDelete = () => {
    if (confirm(`Are you sure you want to delete ${selectedIds.size} products? This cannot be undone.`)) {
      const updatedProducts = data.products.filter(p => !selectedIds.has(p.id));
      onUpdate({ ...data, products: updatedProducts });
      setSelectedIds(new Set());
    }
  };

  const executeBulkUpdate = () => {
    const updatedProducts = data.products.map(p => {
      if (!selectedIds.has(p.id)) return p;

      let updated = { ...p };
      let priceChanged = false;

      if (bulkConfig.category.enabled) {
        updated.category = bulkConfig.category.value;
      }
      if (bulkConfig.minStock.enabled && bulkConfig.minStock.value !== '') {
        updated.minStock = Number(bulkConfig.minStock.value);
      }
      if (bulkConfig.buyPrice.enabled && bulkConfig.buyPrice.value !== 0) {
        updated.buyPrice = Math.round(updated.buyPrice * (1 + (bulkConfig.buyPrice.value / 100)) * 100) / 100;
      }
      if (bulkConfig.sellPrice.enabled && bulkConfig.sellPrice.value !== 0) {
        updated.sellPrice = Math.round(updated.sellPrice * (1 + (bulkConfig.sellPrice.value / 100)) * 100) / 100;
        priceChanged = true;
      }

      if (priceChanged) {
        updated.lastPriceUpdate = new Date().toISOString();
      }

      return updated;
    });

    onUpdate({ ...data, products: updatedProducts });
    setIsBulkEditOpen(false);
    setSelectedIds(new Set());
    setBulkConfig({
      category: { enabled: false, value: settings.inventoryCategories[0] || 'General' },
      minStock: { enabled: false, value: '' },
      buyPrice: { enabled: false, value: 0 },
      sellPrice: { enabled: false, value: 0 },
    });
  };

  const handleBuyPriceChange = (val: number) => {
    setFormData(prev => {
      const updates: any = { ...prev, buyPrice: val };
      if (autoPricingEnabled && !editingProduct) {
        updates.sellPrice = Math.ceil(val * 1.4); 
      }
      return updates;
    });
  };

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setEditingProduct(product);
      setFormData(product);
      setAutoPricingEnabled(false);
    } else {
      setEditingProduct(null);
      setFormData({ 
        name: '', 
        category: settings.inventoryCategories[0] || 'General', 
        buyPrice: 0, 
        sellPrice: 0, 
        stock: 0, 
        minStock: 5, 
        description: '' 
      });
      setAutoPricingEnabled(true);
    }
    setIsModalOpen(true);
  };

  const saveProduct = (): Product | null => {
    if (!formData.name || !formData.buyPrice || !formData.sellPrice) return null;

    const currentPrice = editingProduct ? editingProduct.sellPrice : 0;
    const newPrice = Number(formData.sellPrice);
    const priceChanged = currentPrice !== newPrice;

    const newProduct: Product = {
      id: editingProduct ? editingProduct.id : crypto.randomUUID(),
      name: formData.name || '',
      description: formData.description || '',
      category: formData.category || 'General',
      buyPrice: Number(formData.buyPrice),
      sellPrice: newPrice,
      stock: Number(formData.stock),
      minStock: Number(formData.minStock),
      // Update date if price changed OR it's a new product
      lastPriceUpdate: priceChanged || !editingProduct ? new Date().toISOString() : editingProduct.lastPriceUpdate
    };

    let updatedProducts = [...data.products];
    if (editingProduct) {
      updatedProducts = updatedProducts.map(p => p.id === editingProduct.id ? newProduct : p);
    } else {
      updatedProducts.push(newProduct);
    }

    onUpdate({ ...data, products: updatedProducts });
    return newProduct;
  };

  const handleSaveAndClose = () => {
    if (saveProduct()) setIsModalOpen(false);
  };

  const handleSaveAndAddAnother = () => {
    if (saveProduct()) {
      setEditingProduct(null);
      setFormData({ 
        name: '', 
        category: formData.category,
        buyPrice: 0, 
        sellPrice: 0, 
        stock: 0, 
        minStock: 5, 
        description: '' 
      });
      setAutoPricingEnabled(true);
    }
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this product?')) {
      onUpdate({ ...data, products: data.products.filter(p => p.id !== id) });
    }
  };

  const calculateMargin = (buy: number, sell: number) => {
    if (!sell) return 0;
    return ((sell - buy) / sell) * 100;
  };

  const marginPreview = calculateMargin(Number(formData.buyPrice || 0), Number(formData.sellPrice || 0));

  return (
    <div className="space-y-6 relative">
      {/* Bulk Action Bar */}
