// Utility to hash sensitive data (PIN)
export const hashString = async (text: string): Promise<string> => {
  if (!text) return '';
  const msgBuffer = new TextEncoder().encode(text);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

export const getStoredSettings = (): Settings => {
  const stored = localStorage.getItem(LS_KEY_SETTINGS);
  if (!stored) return DEFAULT_SETTINGS;

  const parsed = JSON.parse(stored);
  // Merge with defaults to ensure new fields exist for existing users
  return { ...DEFAULT_SETTINGS, ...parsed };
};

export const saveSettings = (settings: Settings) => {
  localStorage.setItem(LS_KEY_SETTINGS, JSON.stringify(settings));
};

export const getInitialData = (): AppData => {
  // Return empty structure, actual load happens in App provider
  return { products: [], transactions: [], expenses: [] };
};

export const loadData = async (settings: Settings): Promise<AppData | null> => {
  // If JSONBin configured, try fetch
  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        headers: {
          'X-Master-Key': settings.jsonBinKey,
        },
      });
      if (!response.ok) throw new Error('Failed to fetch from JSONBin');
      const json = await response.json();
      return json.record as AppData;
    } catch (e) {
      console.error("JSONBin load failed, falling back to local:", e);
    }
  }

  // Fallback to LocalStorage
  const local = localStorage.getItem(LS_KEY_DATA);
  return local ? JSON.parse(local) : null;
};

export const saveData = async (data: AppData, settings: Settings): Promise<boolean> => {
  // Always save local first for speed/backup
  localStorage.setItem(LS_KEY_DATA, JSON.stringify(data));

  if (settings.jsonBinId && settings.jsonBinKey) {
    try {
      const response = await fetch(`https://api.jsonbin.io/v3/b/${settings.jsonBinId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'X-Master-Key': settings.jsonBinKey,
        },
        body: JSON.stringify(data),
      });
      return response.ok;
    } catch (e) {
      console.error("JSONBin save failed:", e);
      return false;
    }
  }
  return true;
};

