import React, { useState, useEffect } from 'react';
import { AppData, Settings as SettingsType } from './types';
import { getInitialData, loadData, saveData, getStoredSettings, saveSettings } from './services/storage';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Inventory from './pages/Inventory';
import Sales from './pages/Sales';
import Expenses from './pages/Expenses';
import SettingsPage from './pages/Settings';
import Insights from './pages/Insights';
import Documentation from './pages/Documentation';
import { LayoutDashboard, Package, ShoppingCart, DollarSign, TrendingUp, Settings as SettingsIcon, BookOpen } from 'lucide-react';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [data, setData] = useState<AppData>(getInitialData());
  const [settings, setSettings] = useState<SettingsType>(getStoredSettings());
  const [loading, setLoading] = useState(true);

  // Initial Data Load
  useEffect(() => {
    const init = async () => {
      setLoading(true);
      const loadedData = await loadData(settings);
      if (loadedData) {
        setData(loadedData);
      }
      setLoading(false);
    };
    init();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  // Apply Wireframe Mode
  useEffect(() => {
    if (settings.viewMode === 'wireframe') {
      document.body.classList.add('wireframe-mode');
    } else {
      document.body.classList.remove('wireframe-mode');
    }
  }, [settings.viewMode]);

  // Save Data when changed
  const handleDataUpdate = (newData: AppData) => {
    setData(newData);
    saveData(newData, settings);
  };

  const handleSettingsUpdate = (newSettings: SettingsType) => {
    setSettings(newSettings);
    saveSettings(newSettings);
    // Reload data if storage keys changed
    if (newSettings.jsonBinId !== settings.jsonBinId) {
      setLoading(true);
      loadData(newSettings).then(d => {
        if(d) setData(d);
        setLoading(false);
      });
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard data={data} settings={settings} />;
      case 'inventory':
        return <Inventory data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'sales':
        return <Sales data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'expenses':
        return <Expenses data={data} onUpdate={handleDataUpdate} settings={settings} />;
      case 'insights':
        return <Insights data={data} settings={settings} onUpdateSettings={handleSettingsUpdate} />;
      case 'documentation':
        return <Documentation />;
      case 'settings':
        return <SettingsPage settings={settings} onSave={handleSettingsUpdate} data={data} />;
      default:
        return <Dashboard data={data} settings={settings} />;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Home', icon: LayoutDashboard },
    { id: 'inventory', label: 'Stock', icon: Package },
    { id: 'sales', label: 'Sales', icon: ShoppingCart },
    { id: 'expenses', label: 'Costs', icon: DollarSign },
    { id: 'settings', label: 'Config', icon: SettingsIcon },
    { id: 'documentation', label: 'Docs', icon: BookOpen },
  ];

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-medium">Loading LinenLogic...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans flex flex-col md:flex-row">
      {/* Desktop Sidebar */}
      <Sidebar currentPage={currentPage} onNavigate={setCurrentPage} />

      {/* Main Content Area */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 min-h-[calc(100vh-80px)] md:min-h-screen pb-24 md:pb-8 overflow-y-auto">
        {renderPage()}
      </main>

      {/* Mobile Bottom Navigation */}
      <div className="md:hidden fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 z-50 px-2 py-2 shadow-lg safe-area-bottom">
        <div className="flex justify-around items-center">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = currentPage === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setCurrentPage(item.id)}
                className={`flex flex-col items-center p-2 rounded-lg transition-colors ${
                  isActive ? 'text-primary' : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                <Icon size={24} strokeWidth={isActive ? 2.5 : 2} />
                <span className="text-[10px] font-medium mt-1">{item.label}</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

