// so we'll check if the key is available. If not, we return a mock/error.

export const generateBusinessInsight = async (data: AppData, apiKey: string): Promise<string> => {
    return chatWithBusinessCoach("Generate a general business report based on my current data.", data, apiKey);
};

export const chatWithBusinessCoach = async (question: string, data: AppData, apiKey: string): Promise<string> => {
    if (!apiKey) {
        return "Please configure your Google Gemini API Key in Settings to use AI features.";
    }

    try {
        const ai = new GoogleGenAI({ apiKey });

        // Prepare a summary to reduce token usage
        const productSummary = data.products.map(p => 
          `- ${p.name} (${p.category}): Stock ${p.stock}, Buy ${p.buyPrice}, Sell ${p.sellPrice}`
        ).join('\n');

        const recentSales = data.transactions
          .filter(t => t.type === 'SALE')
          .slice(0, 15)
          .map(t => `- ${t.date.split('T')[0]}: ${t.items.map(i => i.productName).join(', ')} (${t.totalAmount})`)
          .join('\n');

        const activePromos = (data.promotions || []).filter(p => p.isActive).map(p => p.name).join(', ');

        const systemPrompt = `
          You are an experienced Product Manager and Business Strategist advising a Skincare Towel Business in Ghana (LinenLogic).

          **Your Persona:**
          - **Expertise:** Retail strategy, inventory optimization, customer psychology, and local Ghanaian market trends.
          - **Context:** Ghana (Accra/Kumasi dynamics, Harmattan season, Rainy season, Wedding seasons, 'December in Gh', etc).
          - **Tone:** Professional, encouraging, forward-thinking, and practical. Global outlook with local execution.

          **Current Business Data:**
          - Inventory: 
          ${productSummary}
          - Recent Sales: 
          ${recentSales}
          - Active Promotions: ${activePromos || 'None'}

          **Task:**
          Answer the user's question deeply and strategically. 
          If they ask for marketing ideas, suggest things relevant to Ghana (e.g., WhatsApp Status bundles, Influencer boxes).
          If they ask about pricing, analyze their margins.
          Always format your response with clear Markdown (bolding, lists) for readability.
        `;

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: activePromos ? `Question: ${question}` : `Question: ${question}`, // Just passing the user question, system prompt is config
          config: {
            systemInstruction: systemPrompt,
          }
        });

        return response.text || "No insights generated.";

      } catch (error) {
        console.error("Gemini Error:", error);
        return "Unable to connect to AI Advisor. Please check your internet connection or API Key.";
      }
}

import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings, Promotion } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, CheckCircle, Search, History, RotateCcw, Edit2, Calendar, CreditCard, StickyNote, Save, CheckSquare, Square, X, Gift, Percent } from 'lucide-react';

interface SalesProps {
  data: AppData;
  onUpdate: (data: AppData) => void;
  settings: Settings;
}

const Sales: React.FC<SalesProps> = ({ data, onUpdate, settings }) => {
  const [activeTab, setActiveTab] = useState<'POS' | 'HISTORY' | 'PROMOTIONS'>('POS');

  // POS State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
  const [checkoutComplete, setCheckoutComplete] = useState(false);

  // Promotions State
  const [promoForm, setPromoForm] = useState<Partial<Promotion>>({
      name: '', price: 0, startDate: '', endDate: '', items: [], isActive: true
  });
  const [promoSearch, setPromoSearch] = useState('');

  // Edit History State
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [editForm, setEditForm] = useState<{date: string, paymentMethod: PaymentMethod, notes: string}>({
    date: '', paymentMethod: PaymentMethod.CASH, notes: ''
  });

  // History Selection & Filter State
  const [selectedTransactionIds, setSelectedTransactionIds] = useState<Set<string>>(new Set());
  const [dateFilter, setDateFilter] = useState({ start: '', end: '' });

  // --- POS LOGIC ---
  const activePromotions = useMemo(() => {
    const now = new Date();
    return (data.promotions || []).filter(p => {
        const start = new Date(p.startDate);
        const end = new Date(p.endDate);
        return p.isActive && now >= start && now <= end;
    });
  }, [data.promotions]);

  const availableProducts = useMemo(() => {
    return data.products.filter(p => 
      p.stock > 0 && 
      !p.isArchived &&
      p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [data.products, searchTerm]);

  const addToCart = (product: Product, isPromo = false, promoItems: {productId: string, quantity: number}[] = []) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        // For bundles, we assume infinite "bundle" stock, but actual stock check happens at checkout or we could check here.
        // For simplicity, we just add bundles.
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { 
          ...product, 
          quantity: 1, 
          discount: product.defaultDiscount || 0,
          isPromotion: isPromo,
          promotionItems: promoItems
      }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const product = data.products.find(p => p.id === id);
        // Only check stock limit for regular items, bundles check happens differently (complex)
        // For now allowing bundle qty increase freely
        if (delta > 0 && product && !item.isPromotion && newQty > product.stock) return item;
        return { ...item, quantity: Math.max(1, newQty) };
      }
      return item;
    }));
  };

  const updateDiscount = (id: string, discount: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, discount: Math.min(100, Math.max(0, discount)) } : item));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => {
      const discountedPrice = item.sellPrice * (1 - item.discount / 100);
      return acc + (discountedPrice * item.quantity);
    }, 0);
  }, [cart]);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const date = new Date().toISOString();

    // Create transaction
    const newTransactions: Transaction[] = cart.map(item => {
      const revenue = (item.sellPrice * (1 - item.discount / 100)) * item.quantity;
      // For promotions, cost is sum of items costs
      let cost = 0;
      if (item.isPromotion && item.promotionItems) {
         item.promotionItems.forEach(pi => {
            const p = data.products.find(prod => prod.id === pi.productId);
            if (p) cost += (p.buyPrice * pi.quantity);
         });
         cost = cost * item.quantity;
      } else {
         cost = item.buyPrice * item.quantity;
      }

      const profit = revenue - cost;

      return {
        id: crypto.randomUUID(),
        type: 'SALE',
        date: date,
        paymentMethod,
        totalAmount: revenue,
        profit: profit,
        items: [{
          productId: item.id,
          productName: item.name,
          quantity: item.quantity,
          priceAtMoment: item.sellPrice,
          buyPriceAtMoment: cost / item.quantity, // Average unit cost
          discount: item.discount,
          isPromotion: item.isPromotion
        }]
      };
    });

    // Update stock logic
    let updatedProducts = [...data.products];

    cart.forEach(cartItem => {
        if (cartItem.isPromotion && cartItem.promotionItems) {
            // Deduct stock for all items in bundle * quantity of bundles sold
            cartItem.promotionItems.forEach(promoItem => {
                 const pIndex = updatedProducts.findIndex(p => p.id === promoItem.productId);
                 if (pIndex > -1) {
                     updatedProducts[pIndex] = {
                         ...updatedProducts[pIndex],
                         stock: updatedProducts[pIndex].stock - (promoItem.quantity * cartItem.quantity)
                     };
                 }
            });
        } else {
            // Regular Item
            const pIndex = updatedProducts.findIndex(p => p.id === cartItem.id);
            if (pIndex > -1) {
                updatedProducts[pIndex] = {
                    ...updatedProducts[pIndex],
                    stock: updatedProducts[pIndex].stock - cartItem.quantity
                };
            }
        }
    });

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: [...newTransactions, ...data.transactions]
    });

    setCheckoutComplete(true);
    setTimeout(() => {
      setCheckoutComplete(false);
      setCart([]);
    }, 2000);
  };

  // --- PROMOTIONS LOGIC ---
  const handleAddPromoItem = (product: Product) => {
      const currentItems = promoForm.items || [];
      const existing = currentItems.find(i => i.productId === product.id);
      if(existing) {
          setPromoForm({
              ...promoForm,
              items: currentItems.map(i => i.productId === product.id ? {...i, quantity: i.quantity + 1} : i)
          });
      } else {
          setPromoForm({
              ...promoForm,
              items: [...currentItems, { productId: product.id, quantity: 1 }]
          });
      }
  };

  const handleSavePromotion = () => {
      if(!promoForm.name || !promoForm.price || !promoForm.items?.length || !promoForm.startDate || !promoForm.endDate) return;

      const newPromo: Promotion = {
          id: crypto.randomUUID(),
          name: promoForm.name,
          description: promoForm.description || '',
          price: Number(promoForm.price),
          startDate: promoForm.startDate,
          endDate: promoForm.endDate,
          items: promoForm.items,
          isActive: true
      };

      onUpdate({
          ...data,
          promotions: [...(data.promotions || []), newPromo]
      });

      // Reset
      setPromoForm({ name: '', price: 0, startDate: '', endDate: '', items: [], isActive: true });
  };

  const handleDeletePromotion = (id: string) => {
      if(confirm("Delete this promotion?")) {
          onUpdate({
              ...data,
              promotions: data.promotions.filter(p => p.id !== id)
          });
      }
  };


  // --- HISTORY LOGIC ---
  const salesTransactions = useMemo(() => {
    let filtered = data.transactions.filter(t => t.type === 'SALE');

    if (dateFilter.start) {
      const start = new Date(dateFilter.start);
      start.setHours(0, 0, 0, 0);
      filtered = filtered.filter(t => new Date(t.date) >= start);
    }

    if (dateFilter.end) {
      const end = new Date(dateFilter.end);
      end.setHours(23, 59, 59, 999);
      filtered = filtered.filter(t => new Date(t.date) <= end);
    }

    return filtered.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [data.transactions, dateFilter]);

  const handleVoidTransaction = (t: Transaction) => {
    if (!confirm('⚠️ Are you sure you want to VOID this transaction?\n\nThis will:\n1. Restore stock to inventory\n2. Remove this sale record permanently\n\nContinue?')) return;

    const updatedProducts = [...data.products];

    t.items.forEach(item => {
        if(item.isPromotion) {
            // If it was a promo, restore stock for original bundle items
            // Wait, we need to know what was in the bundle at that time. 
            // Limitation: Transaction history currently stores flattened promo name. 
            // FIX: ideally we store bundle content in TX. 
            // FALLBACK: find current promo definition. If deleted, we can't fully restore.
            // For now, let's assume we can find the promo by ID (productId holds promo ID for bundles usually? No, we need to ensure unique IDs)
            // In checkout we used item.id which was promo.id.

            const promo = data.promotions?.find(p => p.id === item.productId);
            if(promo) {
                promo.items.forEach(pi => {
                    const pIndex = updatedProducts.findIndex(p => p.id === pi.productId);
                    if(pIndex > -1) {
                         updatedProducts[pIndex] = { ...updatedProducts[pIndex], stock: updatedProducts[pIndex].stock + (pi.quantity * item.quantity) };
                    }
                });
            } else {
                alert("Original promotion definition not found. Cannot automatically restore stock for this item.");
            }

        } else {
             const productIndex = updatedProducts.findIndex(p => p.id === item.productId);
             if (productIndex > -1) {
                updatedProducts[productIndex] = {
                ...updatedProducts[productIndex],
                stock: updatedProducts[productIndex].stock + item.quantity
                };
             }
        }
    });

    const updatedTransactions = data.transactions.filter(tr => tr.id !== t.id);

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: updatedTransactions
    });

    if (selectedTransactionIds.has(t.id)) {
      const newSet = new Set(selectedTransactionIds);
      newSet.delete(t.id);
      setSelectedTransactionIds(newSet);
    }
  };

  // ... (Keep existing Edit Handlers same as before, omitted for brevity if unchanged logic, but including for full file correctness)
  const handleEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setEditForm({ date: t.date.slice(0, 16), paymentMethod: t.paymentMethod, notes: t.notes || '' });
    setIsEditModalOpen(true);
  };

  const saveTransactionEdit = () => {
    if (!editingTransaction) return;
    const updatedTransactions = data.transactions.map(t => t.id === editingTransaction.id ? { ...t, date: new Date(editForm.date).toISOString(), paymentMethod: editForm.paymentMethod, notes: editForm.notes } : t);
    onUpdate({ ...data, transactions: updatedTransactions });
    setIsEditModalOpen(false);
    setEditingTransaction(null);
  };
  const handleSelectAllTransactions = () => {
      setSelectedTransactionIds(selectedTransactionIds.size === salesTransactions.length ? new Set() : new Set(salesTransactions.map(t => t.id)));
  };
  const handleSelectTransaction = (id: string) => {
    const newSet = new Set(selectedTransactionIds);
    if (newSet.has(id)) newSet.delete(id); else newSet.add(id);
    setSelectedTransactionIds(newSet);
  };
  const handleBulkDeleteTransactions = () => {
      if (confirm(`Delete ${selectedTransactionIds.size} records?`)) {
          onUpdate({ ...data, transactions: data.transactions.filter(t => !selectedTransactionIds.has(t.id)) });
          setSelectedTransactionIds(new Set());
      }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)] relative">
      {/* Tabs */}
      <div className="flex space-x-4 mb-4 border-b border-slate-200 overflow-x-auto">
        <button onClick={() => setActiveTab('POS')} className={`pb-2 px-4 font-bold whitespace-nowrap transition-colors ${activeTab === 'POS' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}>Point of Sale</button>
        <button onClick={() => setActiveTab('HISTORY')} className={`pb-2 px-4 font-bold whitespace-nowrap transition-colors ${activeTab === 'HISTORY' ? 'border-b-2 border-primary text-primary' : 'text-slate-400'}`}>Sales History</button>
        <button onClick={() => setActiveTab('PROMOTIONS')} className={`pb-2 px-4 font-bold whitespace-nowrap transition-colors ${activeTab === 'PROMOTIONS' ? 'border-b-2 border-purple-600 text-purple-600' : 'text-slate-400'}`}>Promotions & Bundles</button>
      </div>

      {activeTab === 'PROMOTIONS' && (
          <div className="flex flex-col md:flex-row gap-6 flex-1 overflow-hidden">
              {/* Creator */}
              <div className="flex-1 bg-white rounded-xl shadow-sm border border-slate-100 overflow-y-auto p-6">
                  <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><Gift className="text-purple-600"/> Create Seasonal Bundle</h3>
                  <div className="space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div>
                              <label className="block text-sm font-medium text-slate-600 mb-1">Bundle Name</label>
                              <input type="text" placeholder="e.g. Easter Hamper" className="w-full p-2 border rounded" value={promoForm.name} onChange={e => setPromoForm({...promoForm, name: e.target.value})}/>
                          </div>
                          <div>
                              <label className="block text-sm font-medium text-slate-600 mb-1">Selling Price ({settings.currency})</label>
                              <input type="number" className="w-full p-2 border rounded" value={promoForm.price} onChange={e => setPromoForm({...promoForm, price: Number(e.target.value)})}/>
                          </div>
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <div>
                              <label className="block text-sm font-medium text-slate-600 mb-1">Start Date</label>
                              <input type="date" className="w-full p-2 border rounded" value={promoForm.startDate} onChange={e => setPromoForm({...promoForm, startDate: e.target.value})}/>
                          </div>
                          <div>
                              <label className="block text-sm font-medium text-slate-600 mb-1">End Date</label>
                              <input type="date" className="w-full p-2 border rounded" value={promoForm.endDate} onChange={e => setPromoForm({...promoForm, endDate: e.target.value})}/>
                          </div>
                      </div>

                      {/* Bundle Items Builder */}
                      <div className="border rounded-xl p-4 bg-slate-50">
                          <h4 className="font-bold text-sm text-slate-700 mb-2">Bundle Contents</h4>
                          <div className="flex flex-wrap gap-2 mb-4">
                              {promoForm.items?.map((item, idx) => {
                                  const p = data.products.find(prod => prod.id === item.productId);
                                  return (
                                      <span key={idx} className="bg-white border px-2 py-1 rounded text-sm flex items-center gap-2 shadow-sm">
                                          {p?.name} <span className="font-bold text-purple-600">x{item.quantity}</span>
                                          <button onClick={() => setPromoForm({...promoForm, items: promoForm.items?.filter(i => i.productId !== item.productId)})} className="text-slate-400 hover:text-red-500"><X size={12}/></button>
                                      </span>
                                  )
                              })}
                          </div>
                          <div className="relative">
                              <Search size={16} className="absolute left-3 top-3 text-slate-400"/>
                              <input 
                                type="text" 
                                placeholder="Search products to add..." 
                                className="w-full p-2 pl-9 border rounded"
                                value={promoSearch}
                                onChange={e => setPromoSearch(e.target.value)}
                              />
                              {promoSearch && (
                                  <div className="absolute top-full left-0 w-full bg-white border shadow-lg z-10 max-h-40 overflow-y-auto rounded-b-lg">
                                      {data.products.filter(p => p.name.toLowerCase().includes(promoSearch.toLowerCase()) && !p.isArchived).map(p => (
                                          <div key={p.id} onClick={() => { handleAddPromoItem(p); setPromoSearch(''); }} className="p-2 hover:bg-slate-50 cursor-pointer text-sm">
                                              {p.name}
                                          </div>
                                      ))}
                                  </div>
                              )}
                          </div>
                      </div>

                      <button onClick={handleSavePromotion} className="w-full py-3 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 transition-colors">
                          Create Bundle
                      </button>
                  </div>
              </div>

              {/* List */}
              <div className="w-full md:w-96 bg-white rounded-xl shadow-sm border border-slate-100 p-4 overflow-y-auto">
                   <h3 className="font-bold text-slate-800 mb-4">Active Promotions</h3>
                   <div className="space-y-3">
                       {data.promotions?.map(promo => (
                           <div key={promo.id} className="border border-purple-100 bg-purple-50/30 p-4 rounded-xl relative group">
                               <button onClick={() => handleDeletePromotion(promo.id)} className="absolute top-2 right-2 text-slate-300 hover:text-red-500"><Trash2 size={14}/></button>
