            <div className="flex-1 overflow-y-auto p-4 grid grid-cols-2 lg:grid-cols-3 gap-4 content-start">
              {/* Promotions / Bundles Grid Section */}
              {activePromotions.map(promo => (
                  <div 
                  key={promo.id}
                  onClick={() => addToCart({
                      id: promo.id,
                      name: promo.name,
                      buyPrice: 0, // Calculated dynamically in logic or 0 for visual
                      sellPrice: promo.price,
                      stock: 999,
                      minStock: 0,
                      category: 'Bundle',
                      description: 'Seasonal Bundle',
                      isArchived: false
                  }, true, promo.items)}
                  className="p-3 border border-purple-200 bg-purple-50 rounded-lg hover:border-purple-400 hover:shadow-md cursor-pointer transition-all group flex flex-col justify-between"
                >
                  <div>
                    <h3 className="font-bold text-purple-900 truncate flex items-center gap-1"><Gift size={14}/> {promo.name}</h3>
                    <div className="flex flex-wrap gap-1 mt-1 mb-2">
                        <span className="text-[10px] bg-white border border-purple-200 px-1 py-0.5 rounded text-purple-700">Bundle</span>
                    </div>
                  </div>
                  <div className="flex justify-between items-end mt-2">
                    <span className="font-bold text-purple-700">{settings.currency} {promo.price}</span>
                  </div>
                </div>
              ))}

              {/* Regular Products */}
              {availableProducts.map(product => (
                <div 
                  key={product.id}
                  onClick={() => addToCart(product)}
                  className="p-3 border border-slate-100 rounded-lg hover:border-primary hover:shadow-md cursor-pointer transition-all bg-white group flex flex-col justify-between"
                >
                  <div>
                    <h3 className="font-medium text-slate-800 truncate">{product.name}</h3>
                    <div className="flex flex-wrap gap-1 mt-1 mb-2">
                        <span className="text-[10px] bg-slate-100 px-1 py-0.5 rounded text-slate-600">{product.category}</span>
                        {product.size && <span className="text-[10px] bg-purple-50 px-1 py-0.5 rounded text-purple-700">{product.size}</span>}
                    </div>
                  </div>
                  <div className="flex justify-between items-end mt-2">
                    <span className="font-bold text-primary">{settings.currency} {product.sellPrice}</span>
                    <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-600">Stock: {product.stock}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Cart & Checkout */}
          <div className="w-full md:w-96 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden order-1 md:order-2 h-1/2 md:h-auto">
            <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <ShoppingCart size={20} /> Current Sale
              </h2>
              <span className="bg-primary/10 text-primary px-2 py-1 rounded-full text-xs font-bold">
                {cart.reduce((a, b) => a + b.quantity, 0)} Items
              </span>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-60">
                  <ShoppingCart size={48} />
                  <p>Cart is empty</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className={`flex flex-col p-3 border rounded-lg relative group ${item.isPromotion ? 'border-purple-200 bg-purple-50/30' : 'border-slate-100'}`}>
                    <div className="flex justify-between mb-2">
                      <span className={`font-medium text-sm ${item.isPromotion ? 'text-purple-900 font-bold' : 'text-slate-800'}`}>
                          {item.isPromotion && <Gift size={12} className="inline mr-1"/>}
                          {item.name}
                      </span>
                      <button 
                        onClick={() => removeFromCart(item.id)}
                        className="text-slate-300 hover:text-red-500 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>

                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-2 bg-slate-50 rounded-lg p-1">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Minus size={14} />
                        </button>
                        <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm">
                          <Plus size={14} />
                        </button>
                      </div>

                      <div className="flex flex-col items-end">
                        <span className="font-bold text-slate-800">
                          {settings.currency} {(item.sellPrice * (1 - item.discount/100) * item.quantity).toFixed(2)}
                        </span>
                        {item.discount > 0 && (
                          <span className="text-xs text-green-600">-{item.discount}% Off</span>
                        )}
                      </div>
                    </div>

                    {/* ENHANCED MOBILE DISCOUNT FIELD */}
                    <div className="mt-3 flex items-center justify-between bg-white p-2 rounded border border-slate-100">
                      <label className="text-xs font-bold text-slate-500 flex items-center gap-1"><Percent size={10}/> Discount</label>
                      <div className="flex items-center gap-1">
                        <input 
                            type="number" 
                            min="0" max="100"
                            value={item.discount}
                            onChange={(e) => updateDiscount(item.id, Number(e.target.value))}
                            className="w-16 p-1 text-base text-right font-medium text-slate-800 border rounded outline-none focus:border-primary"
                        />
                        <span className="text-slate-400 text-xs">%</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-4 bg-slate-50 border-t border-slate-100 space-y-4">
              <div>
                 <label className="block text-sm font-medium text-slate-600 mb-2">Payment Method</label>
                 <div className="grid grid-cols-2 gap-2">
                   {Object.values(PaymentMethod).map(method => (
                     <button
                       key={method}
                       onClick={() => setPaymentMethod(method)}
                       className={`px-2 py-2 text-xs font-bold rounded-lg border ${
                         paymentMethod === method 
                          ? 'bg-primary text-white border-primary' 
                          : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'
                       }`}
                     >
                       {method.replace('_', ' ')}
                     </button>
                   ))}
                 </div>
              </div>

              <div className="flex justify-between items-center pt-2">
                <span className="text-slate-500">Total Amount</span>
                <span className="text-2xl font-bold text-slate-900">{settings.currency} {cartTotal.toFixed(2)}</span>
              </div>

              <button
                onClick={handleCheckout}
                disabled={cart.length === 0 || checkoutComplete}
                className={`w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center space-x-2 transition-all ${
                  checkoutComplete 
                    ? 'bg-green-500 text-white' 
                    : cart.length === 0 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                      : 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg hover:shadow-xl'
                }`}
              >
                {checkoutComplete ? (
                  <>
                    <CheckCircle size={24} />
                    <span>Success!</span>
                  </>
                ) : (
                  <span>Confirm Sale</span>
                )}
              </button>
            </div>
          </div>
        </div>
      ) : activeTab === 'HISTORY' ? (
        /* HISTORY TAB (Reused existing code mostly) */
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex-1 overflow-hidden flex flex-col relative">

          {selectedTransactionIds.size > 0 && (
            <div className="bg-slate-900 text-white p-4 absolute top-4 left-4 right-4 rounded-xl shadow-lg flex justify-between items-center z-20 animate-fade-in">
              <div className="flex items-center space-x-4">
                <span className="font-bold">{selectedTransactionIds.size} Selected</span>
                <button onClick={() => setSelectedTransactionIds(new Set())} className="text-slate-400 hover:text-white text-sm">Cancel</button>
              </div>
              <button onClick={handleBulkDeleteTransactions} className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-lg flex items-center space-x-2 text-sm font-medium transition-colors">
                <Trash2 size={16} /> <span>Delete Selected</span>
              </button>
            </div>
          )}

          <div className="p-4 border-b border-slate-100 bg-slate-50 flex flex-col sm:flex-row justify-between items-center gap-4">
             <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-start">
               <h3 className="font-bold text-slate-700 flex items-center gap-2"><History size={20} /> Recorded Sales</h3>
               <span className="text-sm text-slate-500 bg-slate-100 px-2 py-1 rounded">{salesTransactions.length}</span>
             </div>
             <div className="flex items-center gap-2 w-full sm:w-auto overflow-x-auto">
                <div className="flex items-center bg-white border border-slate-200 rounded-lg p-1 flex-1 sm:flex-none min-w-[120px]">
                    <span className="text-xs text-slate-400 px-2">From</span>
                    <input type="date" className="outline-none text-sm text-slate-600 bg-transparent w-full sm:w-auto" value={dateFilter.start} onChange={e => setDateFilter(prev => ({...prev, start: e.target.value}))}/>
                </div>
                <div className="flex items-center bg-white border border-slate-200 rounded-lg p-1 flex-1 sm:flex-none min-w-[120px]">
                    <span className="text-xs text-slate-400 px-2">To</span>
                    <input type="date" className="outline-none text-sm text-slate-600 bg-transparent w-full sm:w-auto" value={dateFilter.end} onChange={e => setDateFilter(prev => ({...prev, end: e.target.value}))}/>
                </div>
                {(dateFilter.start || dateFilter.end) && (
                    <button onClick={() => setDateFilter({start: '', end: ''})} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Clear Date Filter"><X size={18} /></button>
                )}
             </div>
          </div>
          <div className="flex-1 overflow-auto">
             <div className="min-w-[600px] md:min-w-0">
                <table className="w-full text-left border-collapse">
                <thead className="bg-slate-100 text-slate-600 sticky top-0 z-10 text-sm">
                    <tr>
                    <th className="px-6 py-3 w-12">
                        <button onClick={handleSelectAllTransactions} className="flex items-center text-slate-400 hover:text-slate-600">
                        {salesTransactions.length > 0 && selectedTransactionIds.size === salesTransactions.length ? <CheckSquare size={20} /> : <Square size={20} />}
                        </button>
                    </th>
                    <th className="px-6 py-3">Date</th>
                    <th className="px-6 py-3">Items</th>
                    <th className="px-6 py-3">Payment</th>
                    <th className="px-6 py-3 text-right">Amount</th>
                    <th className="px-6 py-3 text-right">Actions</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                    {salesTransactions.map(t => {
                        const isSelected = selectedTransactionIds.has(t.id);
                        return (
                        <tr key={t.id} className={`transition-colors ${isSelected ? 'bg-blue-50/50' : 'hover:bg-slate-50'}`}>
                            <td className="px-6 py-4">
                            <button onClick={() => handleSelectTransaction(t.id)} className={`flex items-center ${isSelected ? 'text-primary' : 'text-slate-300 hover:text-slate-400'}`}>
                                {isSelected ? <CheckSquare size={20} /> : <Square size={20} />}
                            </button>
                            </td>
                            <td className="px-6 py-4 text-sm text-slate-500 whitespace-nowrap">
                            {new Date(t.date).toLocaleString()}
                            {t.notes && <div className="text-xs text-slate-400 mt-1 max-w-[150px] truncate">Note: {t.notes}</div>}
                            </td>
                            <td className="px-6 py-4">
                            <div className="flex flex-col gap-1">
                                {t.items.map((item, idx) => (
                                <span key={idx} className={`text-sm font-medium ${item.isPromotion ? 'text-purple-700' : 'text-slate-800'}`}>
                                    {item.productName} <span className="text-slate-500">x{item.quantity}</span>
                                </span>
                                ))}
                            </div>
                            </td>
                            <td className="px-6 py-4 text-sm">
                            <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs font-bold">{t.paymentMethod}</span>
                            </td>
                            <td className="px-6 py-4 text-right font-bold text-slate-900">{settings.currency} {t.totalAmount.toFixed(2)}</td>
                            <td className="px-6 py-4 text-right">
                            <div className="flex justify-end gap-2">
                                <button onClick={() => handleEditTransaction(t)} className="text-blue-500 hover:text-blue-700 hover:bg-blue-50 p-2 rounded transition-colors" title="Edit Record"><Edit2 size={16} /></button>
                                <button onClick={() => handleVoidTransaction(t)} className="text-red-600 hover:text-red-800 hover:bg-red-50 px-3 py-1 rounded-lg transition-colors text-xs font-bold border border-red-200 hover:border-red-300 flex items-center gap-1" title="Void Transaction"><RotateCcw size={14} /> Void</button>
                            </div>
                            </td>
                        </tr>
                        );
                    })}
                    {salesTransactions.length === 0 && (
                    <tr><td colSpan={6} className="text-center py-10 text-slate-400">No sales found for selected period.</td></tr>
                    )}
                </tbody>
                </table>
             </div>
          </div>
        </div>
      ) : null}

      {/* Edit Transaction Modal */}
      {isEditModalOpen && editingTransaction && (
         <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in">
               <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                 <h3 className="font-bold text-slate-800">Edit Transaction</h3>
                 <button onClick={() => setIsEditModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
               </div>
               <div className="p-6 space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2"><Calendar size={14}/> Date & Time</label>
                    <input type="datetime-local" className="w-full p-2 border border-slate-300 rounded-lg outline-none" value={editForm.date} onChange={e => setEditForm({...editForm, date: e.target.value})} />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2"><CreditCard size={14}/> Payment Method</label>
                    <select className="w-full p-2 border border-slate-300 rounded-lg outline-none" value={editForm.paymentMethod} onChange={e => setEditForm({...editForm, paymentMethod: e.target.value as PaymentMethod})}>
                       {Object.values(PaymentMethod).map(m => <option key={m} value={m}>{m}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2"><StickyNote size={14}/> Notes</label>
                    <textarea className="w-full p-2 border border-slate-300 rounded-lg outline-none h-24 resize-none" value={editForm.notes} onChange={e => setEditForm({...editForm, notes: e.target.value})} placeholder="Optional notes about this sale..."/>
                  </div>
                  <div className="flex gap-2 pt-2">
                     <button onClick={() => setIsEditModalOpen(false)} className="flex-1 py-2 text-slate-600 hover:bg-slate-100 rounded-lg">Cancel</button>
                     <button onClick={saveTransactionEdit} className="flex-1 py-2 bg-primary hover:bg-secondary text-white rounded-lg font-medium flex justify-center items-center gap-2"><Save size={18} /> Save Changes</button>
                  </div>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

export default Sales;

import React, { useState, useEffect } from 'react';
import { AppData, Settings, AIChat } from '../types';
import { chatWithBusinessCoach } from '../services/gemini';
import { Sparkles, Loader2, Key, Send, User, Bot, MessageSquare } from 'lucide-react';

interface InsightsProps {
  data: AppData;
  settings: Settings;
  onUpdate: (data: AppData) => void;
}

const Insights: React.FC<InsightsProps> = ({ data, settings, onUpdate }) => {
  const [loading, setLoading] = useState(false);
  const [question, setQuestion] = useState('');
  const [apiKeyInput, setApiKeyInput] = useState('');
  const [showKeyInput, setShowKeyInput] = useState(false);

  // Only auto-scroll to bottom of chat
  const chatEndRef = React.useRef<HTMLDivElement>(null);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [data.aiChats]);

  const handleAsk = async () => {
    if (!question.trim()) return;

    let key = process.env.API_KEY || apiKeyInput;
    if (!key) {
      setShowKeyInput(true);
      return;
    }

    setLoading(true);
    const answer = await chatWithBusinessCoach(question, data, key);

    const newChat: AIChat = {
        id: crypto.randomUUID(),
        question: question,
        answer: answer,
        timestamp: new Date().toISOString(),
        category: 'General'
    };

    onUpdate({
        ...data,
        aiChats: [...(data.aiChats || []), newChat]
    });

    setQuestion('');
    setLoading(false);
    setShowKeyInput(false);
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-6rem)] flex flex-col">
      <div className="text-center space-y-2 mb-4 shrink-0">
        <div className="inline-flex items-center justify-center p-3 bg-gradient-to-tr from-purple-500 to-indigo-600 rounded-full shadow-lg text-white mb-2">
          <Sparkles size={24} />
        </div>
        <h2 className="text-2xl font-bold text-slate-800">Business Strategy Advisor</h2>
        <p className="text-sm text-slate-500">Your AI Product Manager for the Ghanaian Market.</p>
      </div>

      {showKeyInput && !process.env.API_KEY && (
        <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-xl mb-4 shrink-0">
           <h4 className="font-bold text-yellow-800 mb-2 flex items-center gap-2"><Key size={16}/> API Key Required</h4>
           <p className="text-sm text-yellow-700 mb-2">Please enter a Google Gemini API Key to use this feature.</p>
           <div className="flex gap-2">
             <input 
               type="password" 
               placeholder="Enter API Key" 
               className="flex-1 p-2 border border-yellow-300 rounded"
               value={apiKeyInput}
               onChange={(e) => setApiKeyInput(e.target.value)}
             />
             <button onClick={handleAsk} className="bg-yellow-600 text-white px-4 py-2 rounded hover:bg-yellow-700">Confirm</button>
           </div>
        </div>
      )}

      {/* Chat Area */}
      <div className="flex-1 bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden flex flex-col">
          <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-slate-50/50">
              {(!data.aiChats || data.aiChats.length === 0) && (
                  <div className="flex flex-col items-center justify-center h-full text-slate-400 opacity-60">
                      <MessageSquare size={48} className="mb-4"/>
                      <p>Ask me anything about pricing, bundles, or marketing trends in Ghana.</p>
                  </div>
              )}

              {(data.aiChats || []).map(chat => (
                  <div key={chat.id} className="space-y-4">
                      {/* User Bubble */}
                      <div className="flex justify-end">
                          <div className="bg-slate-800 text-white max-w-[80%] rounded-2xl rounded-tr-none p-4 shadow-sm relative">
                               <p>{chat.question}</p>
                               <div className="absolute -top-6 right-0 text-xs text-slate-400 flex items-center gap-1">
                                   <User size={12}/> You • {new Date(chat.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                               </div>
                          </div>
                      </div>

                      {/* AI Bubble */}
                      <div className="flex justify-start">
                          <div className="bg-white border border-purple-100 text-slate-800 max-w-[90%] rounded-2xl rounded-tl-none p-6 shadow-sm relative">
                               <div className="prose prose-sm prose-purple max-w-none">
                                  {chat.answer.split('\n').map((line, i) => (
                                      <p key={i} className={`mb-2 ${line.includes('Warning') ? 'text-red-600 font-bold bg-red-50 p-2 rounded' : ''} ${line.trim().startsWith('-') ? 'ml-4' : ''}`}>
                                      {line}
                                      </p>
                                  ))}
                               </div>
                               <div className="absolute -top-6 left-0 text-xs text-purple-600 flex items-center gap-1 font-bold">
                                   <Bot size={12}/> Advisor
                               </div>
                          </div>
                      </div>
                  </div>
              ))}
              <div ref={chatEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-4 bg-white border-t border-slate-100">
              <div className="flex gap-2 relative">
                  <input 
                    type="text" 
                    className="flex-1 bg-slate-100 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-purple-500/20 outline-none transition-all"
                    placeholder="e.g. Suggest a Christmas bundle for corporate gifts..."
                    value={question}
                    onChange={e => setQuestion(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && !loading && handleAsk()}
                    disabled={loading}
                  />
                  <button 
                    onClick={handleAsk}
                    disabled={loading || !question.trim()}
                    className={`px-6 py-3 rounded-xl font-bold flex items-center justify-center transition-all ${loading ? 'bg-slate-200 text-slate-400' : 'bg-purple-600 hover:bg-purple-700 text-white shadow-lg hover:shadow-purple-600/30'}`}
                  >
                      {loading ? <Loader2 size={20} className="animate-spin"/> : <Send size={20} />}
                  </button>
              </div>
          </div>
      </div>
    </div>
  );
};

export default Insights;

export interface Product {
  id: string;
  name: string;
  description: string;
  buyPrice: number;
  sellPrice: number;
  stock: number;
  minStock: number;
  category: string;
  size?: string; // New field
  defaultDiscount?: number; // New field
  isArchived?: boolean; // New field for soft delete
  lastPriceUpdate?: string; 
}

export interface Promotion {
  id: string;
  name: string;
  description: string;
  price: number;
  startDate: string;
  endDate: string;
  items: { productId: string; quantity: number }[];
  isActive: boolean;
}

export interface AIChat {
  id: string;
  question: string;
  answer: string;
  timestamp: string;
  category?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  totalSpent: number;
  joinedDate: string;
}

export interface CartItem extends Product {
  quantity: number;
  discount: number; // Percentage
  isPromotion?: boolean;
  promotionItems?: { productId: string; quantity: number }[];
}

export enum PaymentMethod {
  CASH = 'CASH',
  MOMO = 'MOMO',
  BANK_TRANSFER = 'BANK_TRANSFER',
  OTHER = 'OTHER'
}

export interface Transaction {
  id: string;
  type: 'SALE' | 'PURCHASE'; 
  source?: 'POS' | 'ONLINE'; // Distinguish where sale came from
  status?: 'COMPLETED' | 'PENDING' | 'DELIVERED'; // For online orders
  deliveryDetails?: {
    customerName: string;
    customerPhone: string;
    address: string;
  };
  items: {
    productId: string;
    productName: string;
    quantity: number;
    priceAtMoment: number;
    buyPriceAtMoment: number;
    discount: number;
    isPromotion?: boolean;
  }[];
  totalAmount: number;
  profit: number; 
  paymentMethod: PaymentMethod;
  date: string;
  notes?: string;
}

export interface Expense {
  id: string;
  description: string;
  amount: number;
  category: string; 
  date: string;
}

export interface AppData {
  products: Product[];
  transactions: Transaction[];
  expenses: Expense[];
  promotions: Promotion[];
  aiChats: AIChat[];
  customers: Customer[]; // Database of consented customers
}

export interface Settings {
  jsonBinId: string;
  jsonBinKey: string;
  currency: string;
  inventoryCategories: string[];
  productSizes: string[]; // New field
  expenseCategories: string[];
  securityPin: string; 
