import React, { useState } from 'react';
import { Settings as SettingsType, AppData, Product, Transaction, PaymentMethod, Expense } from '../types';
import { hashString } from '../services/storage';
import { Save, Database, Tag, X, Plus, Download, Lock, Unlock, Shield, ShieldCheck, KeyRound, Monitor, PenTool, PlayCircle, Ruler } from 'lucide-react';

interface SettingsProps {
  settings: SettingsType;
  onSave: (settings: SettingsType) => void;
  data: AppData;
  onUpdateData: (data: AppData) => void; 
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave, data, onUpdateData }) => {
  const [formData, setFormData] = useState<SettingsType>(settings);
  const [message, setMessage] = useState('');
  const [newInvCat, setNewInvCat] = useState('');
  const [newExpCat, setNewExpCat] = useState('');
  const [newSize, setNewSize] = useState('');

  // Security State
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [showPinModal, setShowPinModal] = useState(false);
  const [pinAction, setPinAction] = useState<'UNLOCK' | 'SETUP' | 'CHANGE'>('UNLOCK');
  const [pinInput, setPinInput] = useState('');
  const [pinConfirm, setPinConfirm] = useState('');

  const handleSave = () => {
    onSave(formData);
    setMessage('Settings saved successfully!');
    setTimeout(() => setMessage(''), 3000);
    if (formData.securityPin) setIsUnlocked(false);
  };

  const handleExport = () => {
    const dataStr = JSON.stringify(data, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `linen_logic_backup_${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    setMessage('Data exported successfully!');
    setTimeout(() => setMessage(''), 3000);
  };

  // --- DEMO DATA GENERATOR ---
  const generateDemoData = () => {
    if(!confirm("⚠️ Load Demo Data?\n\nThis is for portfolio demonstration. It will overwrite your current data with sample products and transactions.\n\nAre you sure?")) return;

    const today = new Date();
    const daysAgo = (days: number) => {
      const d = new Date();
      d.setDate(today.getDate() - days);
      return d.toISOString();
    };

    // 1. Seed Products
    const demoProducts: Product[] = [
      { id: 'p1', name: 'Premium Cotton Face Towel', category: 'Face Towel', size: 'Small', defaultDiscount: 0, buyPrice: 25, sellPrice: 45, stock: 42, minStock: 10, description: 'Ultra-soft, high absorption.', lastPriceUpdate: daysAgo(10) },
      { id: 'p2', name: 'Luxury Bath Sheet (White)', category: 'Bath Towel', size: 'Bath Sheet', defaultDiscount: 5, buyPrice: 80, sellPrice: 150, stock: 15, minStock: 5, description: 'Hotel quality 600GSM.', lastPriceUpdate: daysAgo(40) },
      { id: 'p3', name: 'Microfiber Hair Wrap', category: 'Hand Towel', size: 'Medium', defaultDiscount: 0, buyPrice: 30, sellPrice: 55, stock: 8, minStock: 10, description: 'Anti-frizz technology.', lastPriceUpdate: daysAgo(5) },
      { id: 'p4', name: 'Spa Robe (Unisex)', category: 'Robes', size: 'XL', defaultDiscount: 10, buyPrice: 150, sellPrice: 280, stock: 5, minStock: 3, description: 'Waffle knit texture.', lastPriceUpdate: daysAgo(100) }, // Stale price
      { id: 'p5', name: 'Exfoliating Washcloth 3-Pack', category: 'Face Towel', size: 'Set', defaultDiscount: 0, buyPrice: 40, sellPrice: 70, stock: 25, minStock: 8, description: 'Gentle scrub texture.', lastPriceUpdate: daysAgo(2) },
    ];

    // 2. Seed Transactions (Dynamic Dates for Dashboard)
    const demoTransactions: Transaction[] = [
      // Recent Sales
      { 
        id: 't1', type: 'SALE', date: daysAgo(0), paymentMethod: PaymentMethod.MOMO, totalAmount: 135, profit: 60,
        items: [{ productId: 'p1', productName: 'Premium Cotton Face Towel', quantity: 3, priceAtMoment: 45, buyPriceAtMoment: 25, discount: 0 }] 
      },
      { 
        id: 't2', type: 'SALE', date: daysAgo(1), paymentMethod: PaymentMethod.CASH, totalAmount: 150, profit: 70,
        items: [{ productId: 'p2', productName: 'Luxury Bath Sheet (White)', quantity: 1, priceAtMoment: 150, buyPriceAtMoment: 80, discount: 0 }] 
      },
      { 
        id: 't3', type: 'SALE', date: daysAgo(2), paymentMethod: PaymentMethod.MOMO, totalAmount: 220, profit: 100,
        items: [
            { productId: 'p3', productName: 'Microfiber Hair Wrap', quantity: 2, priceAtMoment: 55, buyPriceAtMoment: 30, discount: 0 },
            { productId: 'p5', productName: 'Exfoliating Washcloth 3-Pack', quantity: 2, priceAtMoment: 55, buyPriceAtMoment: 35, discount: 0 } // Price difference sim
        ] 
      },
      { 
        id: 't4', type: 'SALE', date: daysAgo(5), paymentMethod: PaymentMethod.CASH, totalAmount: 45, profit: 20,
        items: [{ productId: 'p1', productName: 'Premium Cotton Face Towel', quantity: 1, priceAtMoment: 45, buyPriceAtMoment: 25, discount: 0 }] 
      },
      // Older Sale
      { 
        id: 't5', type: 'SALE', date: daysAgo(12), paymentMethod: PaymentMethod.MOMO, totalAmount: 280, profit: 130,
        items: [{ productId: 'p4', productName: 'Spa Robe (Unisex)', quantity: 1, priceAtMoment: 280, buyPriceAtMoment: 150, discount: 0 }] 
      },
    ];

    // 3. Seed Expenses
    const demoExpenses: Expense[] = [
      { id: 'e1', description: 'Restock Delivery (Okada)', amount: 30, category: 'Transport', date: daysAgo(1) },
      { id: 'e2', description: 'Packaging Bags', amount: 150, category: 'Packaging', date: daysAgo(4) },
      { id: 'e3', description: 'Instagram Ad Boost', amount: 50, category: 'Marketing', date: daysAgo(8) },
    ];

    onUpdateData({
      products: demoProducts,
      transactions: demoTransactions,
      expenses: demoExpenses,
      promotions: [],
      aiChats: [],
      customers: []
    });

    setMessage('Demo Data Loaded! Check Dashboard.');
    setTimeout(() => setMessage(''), 4000);
  };


  // --- Category Handlers ---
  const addInvCategory = () => {
    if (newInvCat && !formData.inventoryCategories.includes(newInvCat)) {
      setFormData({
        ...formData,
        inventoryCategories: [...formData.inventoryCategories, newInvCat]
      });
      setNewInvCat('');
    }
  };

  const removeInvCategory = (cat: string) => {
    setFormData({
      ...formData,
      inventoryCategories: formData.inventoryCategories.filter(c => c !== cat)
    });
  };

  const addSize = () => {
    if (newSize && !formData.productSizes.includes(newSize)) {
      setFormData({
        ...formData,
        productSizes: [...(formData.productSizes || []), newSize]
      });
      setNewSize('');
    }
  };

  const removeSize = (size: string) => {
    setFormData({
      ...formData,
      productSizes: (formData.productSizes || []).filter(s => s !== size)
    });
  };

  const addExpCategory = () => {
    if (newExpCat && !formData.expenseCategories.includes(newExpCat)) {
      setFormData({
        ...formData,
        expenseCategories: [...formData.expenseCategories, newExpCat]
      });
      setNewExpCat('');
    }
  };

  const removeExpCategory = (cat: string) => {
    setFormData({
      ...formData,
      expenseCategories: formData.expenseCategories.filter(c => c !== cat)
    });
  };

  // --- Security Handlers ---
  const initiateUnlock = () => {
    if (!formData.securityPin) {
      setIsUnlocked(true); // No PIN set, just unlock
    } else {
      setPinAction('UNLOCK');
      setPinInput('');
      setShowPinModal(true);
    }
  };

  const initiatePinSetup = () => {
    setPinAction(formData.securityPin ? 'CHANGE' : 'SETUP');
    setPinInput('');
    setPinConfirm('');
    setShowPinModal(true);
  };

  const handlePinSubmit = async () => {
    if (pinAction === 'UNLOCK') {
      const hashedInput = await hashString(pinInput);
      if (hashedInput === formData.securityPin) {
        setIsUnlocked(true);
        setShowPinModal(false);
      } else {
        alert('Incorrect PIN');
        setPinInput('');
      }
    } else if (pinAction === 'SETUP' || pinAction === 'CHANGE') {
      if (pinInput.length < 4) {
        alert('PIN must be at least 4 digits');
        return;
      }
      if (pinInput !== pinConfirm) {
        alert('PINs do not match');
        return;
      }

      const hashedPin = await hashString(pinInput);
      setFormData({ ...formData, securityPin: hashedPin });
      setShowPinModal(false);
      setMessage(pinAction === 'SETUP' ? 'PIN Set! Click "Save Config" to finish.' : 'PIN Changed! Click "Save Config".');
      setTimeout(() => setMessage(''), 4000);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-20 md:pb-8">
