import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings, Customer } from '../types';
import { ShoppingBag, Search, ShoppingCart, Plus, Minus, X, CheckCircle, ArrowLeft, ArrowRight, Truck, ShieldCheck, MapPin, User, Phone, Smartphone, Bike, Store, Loader2 } from 'lucide-react';

interface StorefrontProps {
  data: AppData;
  settings: Settings;
  onUpdate: (data: AppData) => void;
  onBackToAdmin: () => void;
}

const Storefront: React.FC<StorefrontProps> = ({ data, settings, onUpdate, onBackToAdmin }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [checkoutStep, setCheckoutStep] = useState<'CART' | 'DETAILS' | 'PAYMENT' | 'PROCESSING' | 'SUCCESS'>('CART');

  // Checkout Form
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [address, setAddress] = useState('');
  const [deliveryMode, setDeliveryMode] = useState<'DELIVERY' | 'PICKUP'>('DELIVERY');
  const [consentToPromotions, setConsentToPromotions] = useState(false);

  // Payment Form
  const [momoNetwork, setMomoNetwork] = useState<'MTN' | 'TELECEL' | 'AT'>('MTN');
  const [momoNumber, setMomoNumber] = useState('');

  // --- Logic ---
  const filteredProducts = useMemo(() => {
    return data.products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCat = categoryFilter === 'All' || p.category === categoryFilter;
      return !p.isArchived && p.stock > 0 && matchesSearch && matchesCat;
    });
  }, [data.products, searchTerm, categoryFilter]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, discount: 0 }];
    });
    setIsCartOpen(true);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.sellPrice * item.quantity), 0);

  const handleInitiatePayment = () => {
      if (!customerName || !customerPhone || (deliveryMode === 'DELIVERY' && !address)) {
        alert('Please fill in all details.');
        return;
      }
      setCheckoutStep('PAYMENT');
  };

  const handleProcessPayment = async () => {
      if (!momoNumber || momoNumber.length < 10) {
          alert("Please enter a valid Mobile Money number.");
          return;
      }

      setCheckoutStep('PROCESSING');

      // SIMULATE PAYMENT GATEWAY API CALL
      await new Promise(resolve => setTimeout(resolve, 4000)); // 4 second delay to simulate USSD check

      // Success
      completeOrder();
  };

  const completeOrder = () => {
    const newTransaction: Transaction = {
      id: crypto.randomUUID(),
      type: 'SALE',
      source: 'ONLINE',
      status: 'PENDING', // Pending Delivery
      paymentStatus: 'PAID', // Money Received confirmed via Gateway
      date: new Date().toISOString(),
      paymentMethod: PaymentMethod.MOMO, 
      totalAmount: cartTotal,
      profit: cart.reduce((acc, item) => acc + ((item.sellPrice - item.buyPrice) * item.quantity), 0),
      deliveryMode: deliveryMode,
      momoDetails: {
          network: momoNetwork,
          number: momoNumber
      },
      deliveryDetails: {
        customerName,
        customerPhone,
        address: deliveryMode === 'PICKUP' ? 'Store Pickup' : address
      },
      items: cart.map(item => ({
        productId: item.id,
        productName: item.name,
        quantity: item.quantity,
        priceAtMoment: item.sellPrice,
        buyPriceAtMoment: item.buyPrice,
        discount: 0
      }))
    };

    // Update Data
    let updatedCustomers = [...(data.customers || [])];

    // CONSENT LOGIC: Only save to database if consent is true
    if (consentToPromotions) {
      const existingCustomerIndex = updatedCustomers.findIndex(c => c.phone === customerPhone);
      if (existingCustomerIndex > -1) {
        updatedCustomers[existingCustomerIndex] = {
          ...updatedCustomers[existingCustomerIndex],
          name: customerName, // Update name just in case
          totalSpent: updatedCustomers[existingCustomerIndex].totalSpent + cartTotal
        };
      } else {
        updatedCustomers.push({
          id: crypto.randomUUID(),
          name: customerName,
          phone: customerPhone,
          totalSpent: cartTotal,
          joinedDate: new Date().toISOString()
        });
      }
    }

    // Deduct Stock
    const updatedProducts = data.products.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: p.stock - cartItem.quantity };
      }
      return p;
    });

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: [newTransaction, ...data.transactions],
      customers: updatedCustomers
    });

    setCheckoutStep('SUCCESS');
    setCart([]);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans relative">
      {/* Navbar */}
      <nav className="bg-white shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
             <div className="bg-indigo-600 text-white p-2 rounded-lg">
                <ShoppingBag size={24} />
             </div>
             <div>
                <h1 className="text-xl font-bold text-slate-900">LinenLogic Shop</h1>
                <p className="text-xs text-slate-500">Premium Skincare Towels</p>
             </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-2 hover:bg-slate-100 rounded-full transition-colors"
            >
              <ShoppingCart size={24} className="text-slate-700"/>
              {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full">
                  {cart.reduce((a,b) => a + b.quantity, 0)}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <div className="bg-indigo-900 text-white py-12 px-4">
         <div className="max-w-4xl mx-auto text-center space-y-4">
            <h2 className="text-3xl md:text-5xl font-bold">Luxury for your Skin</h2>
            <p className="text-indigo-200 text-lg">Order premium salon and spa towels online. Delivered to your doorstep.</p>
         </div>
      </div>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 py-8">

         {/* Filters */}
         <div className="flex flex-col md:flex-row gap-4 mb-8 sticky top-20 z-20 bg-slate-50 py-2">
            <div className="flex-1 relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20}/>
                <input 
                  type="text" 
                  placeholder="Search products..."
                  className="w-full pl-10 p-3 rounded-xl border-none shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
            </div>
            <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0">
               <button 
                 onClick={() => setCategoryFilter('All')}
                 className={`px-4 py-2 rounded-full whitespace-nowrap transition-colors ${categoryFilter === 'All' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
               >
                 All
               </button>
               {settings.inventoryCategories.map(cat => (
                 <button 
                  key={cat}
                  onClick={() => setCategoryFilter(cat)}
                  className={`px-4 py-2 rounded-full whitespace-nowrap transition-colors ${categoryFilter === cat ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
                 >
                   {cat}
                 </button>
               ))}
            </div>
         </div>

         {/* Product Grid */}
         <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
            {filteredProducts.map(product => (
               <div key={product.id} className="bg-white rounded-2xl shadow-sm hover:shadow-xl transition-shadow overflow-hidden group border border-slate-100 flex flex-col">
                  <div className="aspect-square bg-slate-100 flex items-center justify-center relative">
                     {/* Placeholder Image */}
                     <span className="text-6xl font-bold text-slate-200 group-hover:scale-110 transition-transform select-none">
                        {product.name.charAt(0)}
                     </span>
                     {product.stock <= 5 && (
                        <span className="absolute top-2 left-2 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded">
                           Only {product.stock} left
                        </span>
                     )}
                  </div>
                  <div className="p-4 flex flex-col flex-1">
                     <div className="text-xs text-indigo-600 font-bold mb-1">{product.category}</div>
                     <h3 className="font-bold text-slate-800 text-lg leading-tight mb-1">{product.name}</h3>
                     <p className="text-slate-500 text-xs mb-4 line-clamp-2 flex-1">{product.description || 'Premium quality fabric.'}</p>

                     <div className="flex items-center justify-between mt-auto">
                        <span className="text-xl font-bold text-slate-900">{settings.currency}{product.sellPrice}</span>
                        <button 
                          onClick={() => addToCart(product)}
                          className="bg-slate-900 text-white p-2 rounded-lg hover:bg-indigo-600 transition-colors shadow-lg active:scale-95"
                        >
                           <Plus size={20}/>
                        </button>
                     </div>
                  </div>
               </div>
            ))}
         </div>
      </div>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
           {/* Backdrop */}
           <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>

           {/* Drawer */}
           <div className="relative bg-white w-full max-w-md h-full shadow-2xl flex flex-col animate-slide-in-right">
              <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                 <h2 className="text-xl font-bold text-slate-800">Your Cart ({cart.length})</h2>
                 <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-slate-200 rounded-full"><X size={20}/></button>
              </div>

              {checkoutStep === 'CART' && (
                <>
                  <div className="flex-1 overflow-y-auto p-4 space-y-4">
                     {cart.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-slate-400">
                           <ShoppingBag size={48} className="mb-2 opacity-50"/>
                           <p>Your cart is empty.</p>
                        </div>
                     ) : (
                        cart.map(item => (
                           <div key={item.id} className="flex gap-4 p-3 border border-slate-100 rounded-xl bg-white shadow-sm">
                              <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center font-bold text-slate-300">
                                 {item.name.charAt(0)}
                              </div>
                              <div className="flex-1">
                                 <h4 className="font-bold text-slate-800 text-sm line-clamp-1">{item.name}</h4>
                                 <div className="text-indigo-600 font-bold text-sm mt-1">{settings.currency}{item.sellPrice * item.quantity}</div>
                                 <div className="flex items-center gap-3 mt-2">
                                    <button onClick={() => updateQty(item.id, -1)} className="w-6 h-6 rounded bg-slate-100 flex items-center justify-center hover:bg-slate-200"><Minus size={12}/></button>
                                    <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                                    <button onClick={() => updateQty(item.id, 1)} className="w-6 h-6 rounded bg-slate-100 flex items-center justify-center hover:bg-slate-200"><Plus size={12}/></button>
                                    <button onClick={() => removeFromCart(item.id)} className="ml-auto text-red-400 hover:text-red-600 text-xs underline">Remove</button>
                                 </div>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
                  <div className="p-6 border-t border-slate-100 bg-slate-50">
                     <div className="flex justify-between items-center mb-4">
                        <span className="text-slate-500">Subtotal</span>
                        <span className="text-2xl font-bold text-slate-900">{settings.currency}{cartTotal}</span>
                     </div>
                     <button 
                        disabled={cart.length === 0}
                        onClick={() => setCheckoutStep('DETAILS')}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white py-4 rounded-xl font-bold shadow-lg transition-colors flex items-center justify-center gap-2"
                     >
                        Checkout <Truck size={20}/>
                     </button>
                  </div>
                </>
              )}

              {checkoutStep === 'DETAILS' && (
                  <div className="flex-1 flex flex-col bg-white">
                      <div className="p-6 flex-1 overflow-y-auto">
                         <button onClick={() => setCheckoutStep('CART')} className="text-slate-500 flex items-center gap-1 text-sm mb-6 hover:text-indigo-600">
                            <ArrowLeft size={16}/> Back to Cart
                         </button>
                         <h3 className="text-xl font-bold text-slate-800 mb-6">Delivery Options</h3>

                         <div className="space-y-4">
                            {/* Delivery Mode Toggle */}
                            <div className="grid grid-cols-2 gap-4 mb-6">
                                <button 
                                    onClick={() => setDeliveryMode('DELIVERY')}
                                    className={`p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${deliveryMode === 'DELIVERY' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 text-slate-500'}`}
                                >
                                    <Bike size={24}/>
                                    <span className="font-bold text-sm">Delivery (Rider)</span>
                                    <span className="text-[10px] opacity-70">You pay for delivery</span>
                                </button>
                                <button 
                                    onClick={() => setDeliveryMode('PICKUP')}
                                    className={`p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${deliveryMode === 'PICKUP' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 text-slate-500'}`}
                                >
                                    <Store size={24}/>
                                    <span className="font-bold text-sm">Self Pickup</span>
                                    <span className="text-[10px] opacity-70">Visit our shop</span>
                                </button>
                            </div>

                            <h4 className="font-bold text-slate-800 text-sm uppercase tracking-wide">Contact Details</h4>
                            <div>
                               <label className="block text-sm font-medium text-slate-600 mb-1">Full Name</label>
                               <input 
                                 type="text" 
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500"
                                 placeholder="e.g. Ama Ghana"
                                 value={customerName}
                                 onChange={e => setCustomerName(e.target.value)}
                               />
                            </div>
                            <div>
                               <label className="block text-sm font-medium text-slate-600 mb-1">Phone Number</label>
                               <input 
                                 type="tel" 
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500"
                                 placeholder="e.g. 024 123 4567"
                                 value={customerPhone}
                                 onChange={e => setCustomerPhone(e.target.value)}
                               />
                            </div>

                            {deliveryMode === 'DELIVERY' && (
                                <div className="animate-fade-in">
                                    <label className="block text-sm font-medium text-slate-600 mb-1">Delivery Location</label>
                                    <textarea 
                                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500 h-20 resize-none"
                                        placeholder="e.g. Near Shell filling station, Osu."
                                        value={address}
                                        onChange={e => setAddress(e.target.value)}
                                    />
                                </div>
                            )}

                            <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 mt-4">
                               <h4 className="font-bold text-indigo-900 text-sm flex items-center gap-2 mb-2">
                                  <ShieldCheck size={16}/> Save Info?
                               </h4>
                               <div className="flex gap-4">
                                  <label className="flex items-center gap-2 cursor-pointer">
                                     <input 
                                        type="checkbox" 
                                        checked={consentToPromotions}
                                        onChange={(e) => setConsentToPromotions(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600"
                                     />
                                     <span className="text-sm text-indigo-800">Yes, save for promotions.</span>
                                  </label>
                               </div>
                            </div>
                         </div>
                      </div>
                      <div className="p-6 border-t border-slate-100 bg-white">
                         <button 
                            onClick={handleInitiatePayment}
                            className="w-full bg-slate-900 hover:bg-slate-800 text-white py-4 rounded-xl font-bold shadow-lg transition-colors flex items-center justify-center gap-2"
                         >
                            Proceed to Payment <ArrowRight size={18}/>
                         </button>
                      </div>
                  </div>
              )}

              {checkoutStep === 'PAYMENT' && (
                  <div className="flex-1 flex flex-col bg-white">
                      <div className="p-6 flex-1 overflow-y-auto">
                         <button onClick={() => setCheckoutStep('DETAILS')} className="text-slate-500 flex items-center gap-1 text-sm mb-6 hover:text-indigo-600">
                            <ArrowLeft size={16}/> Back to Details
                         </button>
                         <h3 className="text-xl font-bold text-slate-800 mb-2">Secure Payment</h3>
                         <p className="text-sm text-slate-500 mb-6">We accept Mobile Money only. Please ensure you have sufficient funds.</p>

                         {/* Gateway Selector */}
                         <div className="grid grid-cols-3 gap-3 mb-6">
                             <button 
                                onClick={() => setMomoNetwork('MTN')}
                                className={`p-3 rounded-xl border-2 flex flex-col items-center gap-1 transition-all ${momoNetwork === 'MTN' ? 'border-yellow-400 bg-yellow-50' : 'border-slate-100'}`}
                             >
                                 <div className="w-8 h-8 rounded-full bg-yellow-400 flex items-center justify-center font-bold text-slate-800 text-xs">MTN</div>
                                 <span className="text-xs font-bold text-slate-700">MTN</span>
                             </button>
                             <button 
                                onClick={() => setMomoNetwork('TELECEL')}
                                className={`p-3 rounded-xl border-2 flex flex-col items-center gap-1 transition-all ${momoNetwork === 'TELECEL' ? 'border-red-500 bg-red-50' : 'border-slate-100'}`}
                             >
                                 <div className="w-8 h-8 rounded-full bg-red-600 flex items-center justify-center font-bold text-white text-xs">T</div>
                                 <span className="text-xs font-bold text-slate-700">Telecel</span>
                             </button>
                             <button 
                                onClick={() => setMomoNetwork('AT')}
                                className={`p-3 rounded-xl border-2 flex flex-col items-center gap-1 transition-all ${momoNetwork === 'AT' ? 'border-blue-600 bg-blue-50' : 'border-slate-100'}`}
                             >
                                 <div className="w-8 h-8 rounded-full bg-blue-700 flex items-center justify-center font-bold text-white text-xs">AT</div>
                                 <span className="text-xs font-bold text-slate-700">AT</span>
                             </button>
                         </div>

                         <div className="space-y-4">
                             <div>
                                 <label className="block text-sm font-bold text-slate-700 mb-1">Mobile Money Number</label>
                                 <div className="relative">
                                     <Smartphone className="absolute left-3 top-3 text-slate-400" size={18}/>
                                     <input 
                                        type="tel" 
                                        className="w-full pl-10 p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500 text-lg font-mono tracking-widest"
                                        placeholder="024XXXXXXX"
                                        value={momoNumber}
                                        onChange={e => setMomoNumber(e.target.value)}
                                        maxLength={10}
                                     />
                                 </div>
                             </div>
                             <div className="bg-slate-50 p-4 rounded-xl text-xs text-slate-500 leading-relaxed border border-slate-100">
                                 <p className="font-bold mb-1 text-slate-700">Instructions:</p>
                                 1. Click "Pay Now" below.<br/>
                                 2. Check your phone for a payment prompt.<br/>
                                 3. Enter your MoMo PIN to authorize <strong>{settings.currency}{cartTotal}</strong>.<br/>
                                 4. Wait for confirmation on this screen.
                             </div>
                         </div>
                      </div>
                      <div className="p-6 border-t border-slate-100 bg-white">
                         <button 
                            onClick={handleProcessPayment}
                            className="w-full bg-slate-900 hover:bg-slate-800 text-white py-4 rounded-xl font-bold shadow-lg transition-colors flex items-center justify-center gap-2"
                         >
                            Pay {settings.currency}{cartTotal}
                         </button>
                      </div>
                  </div>
              )}

              {checkoutStep === 'PROCESSING' && (
                  <div className="flex-1 flex flex-col items-center justify-center p-8 text-center bg-white space-y-6">
                      <div className="relative">
                          <div className="w-20 h-20 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                          <div className="absolute inset-0 flex items-center justify-center">
                              <Smartphone size={32} className="text-indigo-600"/>
                          </div>
                      </div>
                      <div>
                          <h3 className="text-xl font-bold text-slate-800">Waiting for Confirmation...</h3>
                          <p className="text-slate-500 mt-2">Please check your phone ({momoNumber}) and enter your PIN.</p>
                      </div>
                      <div className="bg-yellow-50 text-yellow-800 text-xs px-4 py-2 rounded-full font-bold">
                          Do not close this window
                      </div>
                  </div>
              )}

              {checkoutStep === 'SUCCESS' && (
                 <div className="flex-1 flex flex-col items-center justify-center p-8 text-center bg-white">
                    <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 animate-bounce">
                       <CheckCircle size={40}/>
                    </div>
                    <h3 className="text-2xl font-bold text-slate-900 mb-2">Payment Received!</h3>
                    <p className="text-slate-500 mb-8">Order confirmed. We will contact you at <strong>{customerPhone}</strong> regarding your {deliveryMode === 'DELIVERY' ? 'delivery' : 'pickup'}.</p>
                    <button 
                       onClick={() => {
                          setCheckoutStep('CART');
                          setIsCartOpen(false);
                          setCustomerName('');
                          setCustomerPhone('');
                          setAddress('');
                          setMomoNumber('');
                       }}
                       className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-colors"
                    >
                       Continue Shopping
                    </button>
                 </div>
              )}
           </div>
        </div>
      )}

      {/* Admin Back Button (Floating) */}
      <button 
        onClick={onBackToAdmin}
        className="fixed bottom-4 left-4 z-40 bg-slate-900 text-white px-4 py-2 rounded-full shadow-xl text-xs font-bold opacity-50 hover:opacity-100 transition-opacity flex items-center gap-2"
      >
        <ArrowLeft size={14}/> Admin Panel
      </button>

    </div>
  );
};

export default Storefront;

import React, { useState, useMemo } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings, Customer } from '../types';
import { ShoppingBag, Search, ShoppingCart, Plus, Minus, X, CheckCircle, ArrowLeft, ArrowRight, Truck, ShieldCheck, MapPin, User, Phone, Smartphone, Bike, Store, Loader2, Gift, Clock, Sparkles, TrendingDown } from 'lucide-react';

interface StorefrontProps {
  data: AppData;
  settings: Settings;
  onUpdate: (data: AppData) => void;
  onBackToAdmin: () => void;
}

const Storefront: React.FC<StorefrontProps> = ({ data, settings, onUpdate, onBackToAdmin }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [checkoutStep, setCheckoutStep] = useState<'CART' | 'DETAILS' | 'PAYMENT' | 'PROCESSING' | 'SUCCESS'>('CART');

  // Checkout Form
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [address, setAddress] = useState('');
  const [deliveryMode, setDeliveryMode] = useState<'DELIVERY' | 'PICKUP'>('DELIVERY');
  const [consentToPromotions, setConsentToPromotions] = useState(false);

  // Payment Form
  const [momoNetwork, setMomoNetwork] = useState<'MTN' | 'TELECEL' | 'AT'>('MTN');
  const [momoNumber, setMomoNumber] = useState('');

  // --- Logic ---
  const filteredProducts = useMemo(() => {
    return data.products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCat = categoryFilter === 'All' || p.category === categoryFilter;
      return !p.isArchived && p.stock > 0 && matchesSearch && matchesCat;
    });
  }, [data.products, searchTerm, categoryFilter]);

  // Active Bundles Logic
  const activeBundles = useMemo(() => {
    const now = new Date();
    return (data.promotions || []).filter(p => {
        const start = new Date(p.startDate);
        const end = new Date(p.endDate);
        // Check active and dates
        return p.isActive && now >= start && now <= end;
    }).map(promo => {
        // Calculate dynamic properties
        let originalPrice = 0;
        let maxStock = 9999;

        promo.items.forEach(item => {
            const product = data.products.find(p => p.id === item.productId);
            if (product) {
                originalPrice += (product.sellPrice * item.quantity);
                const itemStockLimit = Math.floor(product.stock / item.quantity);
                if (itemStockLimit < maxStock) maxStock = itemStockLimit;
            }
        });

        // Determine days remaining
        const end = new Date(promo.endDate);
        const diffTime = Math.abs(end.getTime() - now.getTime());
        const daysRemaining = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

        return {
            ...promo,
            originalPrice,
            savings: originalPrice - promo.price,
            stock: maxStock,
            daysRemaining
        };
    }).filter(b => b.stock > 0); // Hide if stock components are depleted
  }, [data.promotions, data.products]);

  const addToCart = (product: Product, isPromo = false, promoItems: {productId: string, quantity: number}[] = []) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { 
          ...product, 
          quantity: 1, 
          discount: 0,
          isPromotion: isPromo,
          promotionItems: promoItems
      }];
    });
    setIsCartOpen(true);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.sellPrice * item.quantity), 0);

  const handleInitiatePayment = () => {
      if (!customerName || !customerPhone || (deliveryMode === 'DELIVERY' && !address)) {
        alert('Please fill in all details.');
        return;
      }
      setCheckoutStep('PAYMENT');
  };

  const handleProcessPayment = async () => {
      if (!momoNumber || momoNumber.length < 10) {
          alert("Please enter a valid Mobile Money number.");
          return;
      }

      setCheckoutStep('PROCESSING');

      // SIMULATE PAYMENT GATEWAY API CALL
      await new Promise(resolve => setTimeout(resolve, 4000)); // 4 second delay to simulate USSD check

      // Success
      completeOrder();
  };

  const completeOrder = () => {
    // Calculate costs correctly handling bundles
    const orderItems = cart.map(item => {
        let buyPriceAtMoment = item.buyPrice;

        // If it's a bundle, calculate the composite cost
        if (item.isPromotion && item.promotionItems) {
            let totalCost = 0;
            item.promotionItems.forEach(pi => {
                const p = data.products.find(prod => prod.id === pi.productId);
                if (p) totalCost += (p.buyPrice * pi.quantity);
            });
            buyPriceAtMoment = totalCost; // Unit cost of the bundle
        }

        return {
            productId: item.id,
            productName: item.name,
            quantity: item.quantity,
            priceAtMoment: item.sellPrice,
            buyPriceAtMoment: buyPriceAtMoment,
            discount: 0,
            isPromotion: item.isPromotion
        };
    });

    const totalProfit = orderItems.reduce((acc, item) => acc + ((item.priceAtMoment - item.buyPriceAtMoment) * item.quantity), 0);

    const newTransaction: Transaction = {
      id: crypto.randomUUID(),
      type: 'SALE',
      source: 'ONLINE',
      status: 'PENDING', // Pending Delivery
      paymentStatus: 'PAID', // Money Received confirmed via Gateway
      date: new Date().toISOString(),
      paymentMethod: PaymentMethod.MOMO, 
      totalAmount: cartTotal,
      profit: totalProfit,
      deliveryMode: deliveryMode,
      momoDetails: {
          network: momoNetwork,
          number: momoNumber
      },
      deliveryDetails: {
        customerName,
        customerPhone,
        address: deliveryMode === 'PICKUP' ? 'Store Pickup' : address
      },
      items: orderItems
    };

    // Update Data
    let updatedCustomers = [...(data.customers || [])];

    // CONSENT LOGIC: Only save to database if consent is true
    if (consentToPromotions) {
      const existingCustomerIndex = updatedCustomers.findIndex(c => c.phone === customerPhone);
      if (existingCustomerIndex > -1) {
        updatedCustomers[existingCustomerIndex] = {
          ...updatedCustomers[existingCustomerIndex],
          name: customerName, // Update name just in case
          totalSpent: updatedCustomers[existingCustomerIndex].totalSpent + cartTotal
        };
      } else {
        updatedCustomers.push({
          id: crypto.randomUUID(),
          name: customerName,
          phone: customerPhone,
          totalSpent: cartTotal,
          joinedDate: new Date().toISOString()
        });
      }
    }

    // Deduct Stock
    const updatedProducts = [...data.products];
    cart.forEach(cartItem => {
        if (cartItem.isPromotion && cartItem.promotionItems) {
            cartItem.promotionItems.forEach(promoItem => {
                 const pIndex = updatedProducts.findIndex(p => p.id === promoItem.productId);
                 if (pIndex > -1) {
                     updatedProducts[pIndex] = {
                         ...updatedProducts[pIndex],
                         stock: updatedProducts[pIndex].stock - (promoItem.quantity * cartItem.quantity)
                     };
                 }
            });
        } else {
            const pIndex = updatedProducts.findIndex(p => p.id === cartItem.id);
            if (pIndex > -1) {
                updatedProducts[pIndex] = {
                    ...updatedProducts[pIndex],
                    stock: updatedProducts[pIndex].stock - cartItem.quantity
                };
            }
        }
    });

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: [newTransaction, ...data.transactions],
      customers: updatedCustomers
    });

    setCheckoutStep('SUCCESS');
    setCart([]);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans relative">
      {/* Navbar */}
      <nav className="bg-white shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
             <div className="bg-indigo-600 text-white p-2 rounded-lg">
                <ShoppingBag size={24} />
             </div>
             <div>
                <h1 className="text-xl font-bold text-slate-900">LinenLogic Shop</h1>
                <p className="text-xs text-slate-500">Premium Skincare Towels</p>
             </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-2 hover:bg-slate-100 rounded-full transition-colors"
            >
              <ShoppingCart size={24} className="text-slate-700"/>
              {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full">
                  {cart.reduce((a,b) => a + b.quantity, 0)}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <div className="bg-indigo-900 text-white py-12 px-4">
         <div className="max-w-4xl mx-auto text-center space-y-4">
            <h2 className="text-3xl md:text-5xl font-bold">Luxury for your Skin</h2>
            <p className="text-indigo-200 text-lg">Order premium salon and spa towels online. Delivered to your doorstep.</p>
         </div>
      </div>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 py-8 space-y-12">

         {/* --- BUNDLES SHOWCASE (New Section) --- */}
         {activeBundles.length > 0 && (
             <div className="animate-fade-in">
                 <div className="flex items-center gap-2 mb-6">
                     <Sparkles className="text-purple-600" size={24}/>
                     <h2 className="text-2xl font-bold text-slate-900">Special Offers & Bundles</h2>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                     {activeBundles.map(bundle => (
                         <div key={bundle.id} className="bg-gradient-to-br from-purple-50 to-indigo-50 border border-purple-100 rounded-2xl p-6 shadow-sm hover:shadow-lg transition-shadow relative overflow-hidden group">
                             {/* Badge */}
                             <div className="absolute top-4 right-4 bg-red-500 text-white text-xs font-bold px-3 py-1 rounded-full shadow-md animate-pulse">
                                 Save {settings.currency}{bundle.savings.toFixed(0)}
                             </div>

                             <h3 className="text-xl font-bold text-slate-800 mb-2">{bundle.name}</h3>
                             <p className="text-sm text-slate-600 mb-4 h-10 line-clamp-2">{bundle.description || 'Limited time seasonal offer.'}</p>

                             {/* Contents */}
                             <div className="bg-white/60 rounded-xl p-3 mb-4 text-sm border border-purple-100">
                                 <p className="font-bold text-purple-900 text-xs uppercase mb-2">Includes:</p>
                                 <ul className="space-y-1">
                                     {bundle.items.map((item, i) => {
                                         const pName = data.products.find(p => p.id === item.productId)?.name || 'Unknown Item';
                                         return (
                                             <li key={i} className="flex items-center gap-2 text-slate-700">
                                                 <CheckCircle size={12} className="text-green-600"/>
                                                 <span>{item.quantity}x {pName}</span>
                                             </li>
                                         )
                                     })}
                                 </ul>
                             </div>

                             {/* Price Breakdown */}
                             <div className="flex items-end justify-between mb-4">
                                 <div>
                                     <div className="text-slate-400 text-sm line-through flex items-center gap-1">
                                         {settings.currency}{bundle.originalPrice.toFixed(2)}
                                     </div>
                                     <div className="text-2xl font-bold text-purple-700 leading-none">
                                         {settings.currency}{bundle.price.toFixed(2)}
                                     </div>
                                 </div>
                                 <div className="text-right">
                                     <div className="text-xs text-slate-500 flex items-center justify-end gap-1 mb-1">
                                         <Clock size={12}/> Ends in {bundle.daysRemaining} days
                                     </div>
                                     <div className="text-xs font-bold text-green-600 bg-green-100 px-2 py-1 rounded">
                                         {Math.round((bundle.savings / bundle.originalPrice) * 100)}% Off
                                     </div>
                                 </div>
                             </div>

                             <button 
                                onClick={() => addToCart({
                                    id: bundle.id,
                                    name: bundle.name,
                                    buyPrice: 0, // Calculated later
                                    sellPrice: bundle.price,
                                    stock: bundle.stock,
                                    minStock: 0,
                                    category: 'Bundle',
                                    description: bundle.description,
                                    isArchived: false
                                }, true, bundle.items)}
                                className="w-full bg-purple-600 hover:bg-purple-700 text-white py-3 rounded-xl font-bold shadow-lg flex items-center justify-center gap-2 transition-transform active:scale-95"
                             >
                                 <Gift size={18}/> Grab Deal
                             </button>
                         </div>
                     ))}
                 </div>
             </div>
         )}

         {/* Filters */}
         <div className="flex flex-col md:flex-row gap-4 sticky top-20 z-20 bg-slate-50 py-2 rounded-xl">
            <div className="flex-1 relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20}/>
                <input 
                  type="text" 
                  placeholder="Search individual products..."
                  className="w-full pl-10 p-3 rounded-xl border-none shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
            </div>
            <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0">
               <button 
                 onClick={() => setCategoryFilter('All')}
                 className={`px-4 py-2 rounded-full whitespace-nowrap transition-colors ${categoryFilter === 'All' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
               >
                 All
               </button>
               {settings.inventoryCategories.map(cat => (
                 <button 
                  key={cat}
                  onClick={() => setCategoryFilter(cat)}
                  className={`px-4 py-2 rounded-full whitespace-nowrap transition-colors ${categoryFilter === cat ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
                 >
                   {cat}
                 </button>
               ))}
            </div>
         </div>

         {/* Product Grid */}
         <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
            {filteredProducts.map(product => (
               <div key={product.id} className="bg-white rounded-2xl shadow-sm hover:shadow-xl transition-shadow overflow-hidden group border border-slate-100 flex flex-col">
                  <div className="aspect-square bg-slate-100 flex items-center justify-center relative">
                     {/* Placeholder Image */}
                     <span className="text-6xl font-bold text-slate-200 group-hover:scale-110 transition-transform select-none">
                        {product.name.charAt(0)}
                     </span>
                     {product.stock <= 5 && (
                        <span className="absolute top-2 left-2 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded">
                           Only {product.stock} left
                        </span>
                     )}
                  </div>
                  <div className="p-4 flex flex-col flex-1">
                     <div className="text-xs text-indigo-600 font-bold mb-1">{product.category}</div>
                     <h3 className="font-bold text-slate-800 text-lg leading-tight mb-1">{product.name}</h3>
                     <p className="text-slate-500 text-xs mb-4 line-clamp-2 flex-1">{product.description || 'Premium quality fabric.'}</p>

                     <div className="flex items-center justify-between mt-auto">
                        <span className="text-xl font-bold text-slate-900">{settings.currency}{product.sellPrice}</span>
                        <button 
                          onClick={() => addToCart(product)}
                          className="bg-slate-900 text-white p-2 rounded-lg hover:bg-indigo-600 transition-colors shadow-lg active:scale-95"
                        >
                           <Plus size={20}/>
                        </button>
                     </div>
                  </div>
               </div>
            ))}
         </div>
      </div>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
           {/* Backdrop */}
           <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>

           {/* Drawer */}
           <div className="relative bg-white w-full max-w-md h-full shadow-2xl flex flex-col animate-slide-in-right">
              <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                 <h2 className="text-xl font-bold text-slate-800">Your Cart ({cart.length})</h2>
                 <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-slate-200 rounded-full"><X size={20}/></button>
              </div>

              {checkoutStep === 'CART' && (
                <>
                  <div className="flex-1 overflow-y-auto p-4 space-y-4">
                     {cart.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-slate-400">
                           <ShoppingBag size={48} className="mb-2 opacity-50"/>
                           <p>Your cart is empty.</p>
                        </div>
                     ) : (
                        cart.map(item => (
                           <div key={item.id} className={`flex gap-4 p-3 border rounded-xl bg-white shadow-sm ${item.isPromotion ? 'border-purple-200 bg-purple-50/20' : 'border-slate-100'}`}>
                              <div className={`w-16 h-16 rounded-lg flex items-center justify-center font-bold ${item.isPromotion ? 'bg-purple-100 text-purple-400' : 'bg-slate-100 text-slate-300'}`}>
                                 {item.isPromotion ? <Gift size={24}/> : item.name.charAt(0)}
                              </div>
                              <div className="flex-1">
                                 <h4 className={`font-bold text-sm line-clamp-1 ${item.isPromotion ? 'text-purple-900' : 'text-slate-800'}`}>
                                     {item.isPromotion && <span className="text-xs bg-purple-200 text-purple-800 px-1 rounded mr-1">BUNDLE</span>}
                                     {item.name}
                                 </h4>
                                 <div className="text-indigo-600 font-bold text-sm mt-1">{settings.currency}{item.sellPrice * item.quantity}</div>
                                 <div className="flex items-center gap-3 mt-2">
                                    <button onClick={() => updateQty(item.id, -1)} className="w-6 h-6 rounded bg-slate-100 flex items-center justify-center hover:bg-slate-200"><Minus size={12}/></button>
                                    <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                                    <button onClick={() => updateQty(item.id, 1)} className="w-6 h-6 rounded bg-slate-100 flex items-center justify-center hover:bg-slate-200"><Plus size={12}/></button>
                                    <button onClick={() => removeFromCart(item.id)} className="ml-auto text-red-400 hover:text-red-600 text-xs underline">Remove</button>
                                 </div>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
                  <div className="p-6 border-t border-slate-100 bg-slate-50">
                     <div className="flex justify-between items-center mb-4">
                        <span className="text-slate-500">Subtotal</span>
                        <span className="text-2xl font-bold text-slate-900">{settings.currency}{cartTotal.toFixed(2)}</span>
                     </div>
                     <button 
                        disabled={cart.length === 0}
                        onClick={() => setCheckoutStep('DETAILS')}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white py-4 rounded-xl font-bold shadow-lg transition-colors flex items-center justify-center gap-2"
                     >
                        Checkout <Truck size={20}/>
                     </button>
                  </div>
                </>
              )}

              {checkoutStep === 'DETAILS' && (
                  <div className="flex-1 flex flex-col bg-white">
                      <div className="p-6 flex-1 overflow-y-auto">
                         <button onClick={() => setCheckoutStep('CART')} className="text-slate-500 flex items-center gap-1 text-sm mb-6 hover:text-indigo-600">
                            <ArrowLeft size={16}/> Back to Cart
                         </button>
                         <h3 className="text-xl font-bold text-slate-800 mb-6">Delivery Options</h3>

                         <div className="space-y-4">
                            {/* Delivery Mode Toggle */}
                            <div className="grid grid-cols-2 gap-4 mb-6">
                                <button 
                                    onClick={() => setDeliveryMode('DELIVERY')}
                                    className={`p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${deliveryMode === 'DELIVERY' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 text-slate-500'}`}
                                >
                                    <Bike size={24}/>
                                    <span className="font-bold text-sm">Delivery (Rider)</span>
                                    <span className="text-[10px] opacity-70">You pay for delivery</span>
                                </button>
                                <button 
                                    onClick={() => setDeliveryMode('PICKUP')}
                                    className={`p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${deliveryMode === 'PICKUP' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-200 text-slate-500'}`}
                                >
                                    <Store size={24}/>
                                    <span className="font-bold text-sm">Self Pickup</span>
                                    <span className="text-[10px] opacity-70">Visit our shop</span>
                                </button>
                            </div>

                            <h4 className="font-bold text-slate-800 text-sm uppercase tracking-wide">Contact Details</h4>
                            <div>
                               <label className="block text-sm font-medium text-slate-600 mb-1">Full Name</label>
                               <input 
                                 type="text" 
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500"
                                 placeholder="e.g. Ama Ghana"
                                 value={customerName}
                                 onChange={e => setCustomerName(e.target.value)}
                               />
                            </div>
                            <div>
                               <label className="block text-sm font-medium text-slate-600 mb-1">Phone Number</label>
                               <input 
                                 type="tel" 
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500"
                                 placeholder="e.g. 024 123 4567"
                                 value={customerPhone}
                                 onChange={e => setCustomerPhone(e.target.value)}
                               />
                            </div>

                            {deliveryMode === 'DELIVERY' && (
                                <div className="animate-fade-in">
                                    <label className="block text-sm font-medium text-slate-600 mb-1">Delivery Location</label>
                                    <textarea 
                                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-indigo-500 h-20 resize-none"
                                        placeholder="e.g. Near Shell filling station, Osu."
                                        value={address}
                                        onChange={e => setAddress(e.target.value)}
                                    />
                                </div>
                            )}

                            <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 mt-4">
                               <h4 className="font-bold text-indigo-900 text-sm flex items-center gap-2 mb-2">
                                  <ShieldCheck size={16}/> Save Info?
                               </h4>
                               <div className="flex gap-4">
                                  <label className="flex items-center gap-2 cursor-pointer">
                                     <input 
                                        type="checkbox" 
                                        checked={consentToPromotions}
                                        onChange={(e) => setConsentToPromotions(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600"
                                     />
                                     <span className="text-sm text-indigo-800">Yes, save for promotions.</span>
                                  </label>
                               </div>
                            </div>
                         </div>
                      </div>
                      <div className="p-6 border-t border-slate-100 bg-white">
                         <button 
                            onClick={handleInitiatePayment}
                            className="w-full bg-slate-900 hover:bg-slate-800 text-white py-4 rounded-xl font-bold shadow-lg transition-colors flex items-center justify-center gap-2"
                         >
                            Proceed to Payment <ArrowRight size={18}/>
                         </button>
                      </div>
                  </div>
              )}

              {checkoutStep === 'PAYMENT' && (
                  <div className="flex-1 flex flex-col bg-white">
                      <div className="p-6 flex-1 overflow-y-auto">
                         <button onClick={() => setCheckoutStep('DETAILS')} className="text-slate-500 flex items-center gap-1 text-sm mb-6 hover:text-indigo-600">
                            <ArrowLeft size={16}/> Back to Details
                         </button>
                         <h3 className="text-xl font-bold text-slate-800 mb-2">Secure Payment</h3>
                         <p className="text-sm text-slate-500 mb-6">We accept Mobile Money only. Please ensure you have sufficient funds.</p>

                         {/* Gateway Selector */}
                         <div className="grid grid-cols-3 gap-3 mb-6">
                             <button 
                                onClick={() => setMomoNetwork('MTN')}
                                className={`p-3 rounded-xl border-2 flex flex-col items-center gap-1 transition-all ${momoNetwork === 'MTN' ? 'border-yellow-400 bg-yellow-50' : 'border-slate-100'}`}
                             >
                                 <div className="w-8 h-8 rounded-full bg-yellow-400 flex items-center justify-center font-bold text-slate-800 text-xs">MTN</div>
