export const generateBusinessInsight = async (data: AppData, apiKey: string): Promise<string> => {
    return chatWithBusinessCoach("Generate a general business report based on my current data.", data, apiKey);
};

export const chatWithBusinessCoach = async (question: string, data: AppData, apiKey: string): Promise<string> => {
    if (!apiKey) {
        return "Please configure your Google Gemini API Key in Settings to use AI features.";
    }

    try {
        const ai = new GoogleGenAI({ apiKey });

        // Prepare a summary to reduce token usage
        const productSummary = data.products.map(p => 
          `- ${p.name} (${p.category}): Stock ${p.stock}, Buy ${p.buyPrice}, Sell ${p.sellPrice}`
        ).join('\n');

        const recentSales = data.transactions
          .filter(t => t.type === 'SALE')
          .slice(0, 15)
          .map(t => `- ${t.date.split('T')[0]}: ${t.items.map(i => i.productName).join(', ')} (${t.totalAmount})`)
          .join('\n');

        const activePromos = (data.promotions || []).filter(p => p.isActive).map(p => p.name).join(', ');

        const systemPrompt = `
          You are an experienced Product Manager and Business Strategist advising a Skincare Towel Business in Ghana (LinenLogic).

          **Your Persona:**
          - **Expertise:** Retail strategy, inventory optimization, customer psychology, and local Ghanaian market trends.
          - **Context:** Ghana (Accra/Kumasi dynamics, Harmattan season, Rainy season, Wedding seasons, 'December in Gh', etc).
          - **Tone:** Professional, encouraging, forward-thinking, and practical. Global outlook with local execution.

          **Current Business Data:**
          - Inventory: 
          ${productSummary}
          - Recent Sales: 
          ${recentSales}
          - Active Promotions: ${activePromos || 'None'}

          **Task:**
          Answer the user's question deeply and strategically. 
          If they ask for marketing ideas, suggest things relevant to Ghana (e.g., WhatsApp Status bundles, Influencer boxes).
          If they ask about pricing, analyze their margins.
          Always format your response with clear Markdown (bolding, lists) for readability.
        `;

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: activePromos ? `Question: ${question}` : `Question: ${question}`, 
          config: {
            systemInstruction: systemPrompt,
          }
        });

        return response.text || "No insights generated.";

      } catch (error) {
        console.error("Gemini Error:", error);
        return "Unable to connect to AI Advisor. Please check your internet connection or API Key.";
      }
}

export const chatWithStoreAssistant = async (question: string, products: Product[], apiKey: string): Promise<string> => {
    if (!apiKey) {
        return "Our AI assistant is currently offline. Please contact us via WhatsApp.";
    }

    try {
        const ai = new GoogleGenAI({ apiKey });

        // Filter out of stock items to avoid recommending them
        const availableProducts = products
            .filter(p => p.stock > 0 && !p.isArchived)
            .map(p => `- ${p.name} (${p.category}, ${p.size}): ${p.sellPrice} GHS. Desc: ${p.description}`)
            .join('\n');

        const systemPrompt = `
          You are "LinenLogic AI", a helpful and sophisticated shopping assistant for a premium skincare towel boutique.

          **Your Goal:** Help customers choose the right towel based on their skin type, needs, or budget.

          **Available Inventory:**
          ${availableProducts}

          **Guidelines:**
          1. Be polite, concise, and use a "spa-like" calming tone.
          2. ONLY recommend products from the Available Inventory list above.
          3. If a customer asks about a specific skin concern (acne, sensitive skin), recommend softer textures (like Microfiber or Bamboo if available, or Premium Cotton).
          4. Mention the price in GHS.
          5. Keep responses short (under 50 words) unless asked for details.
        `;

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: question, 
          config: {
            systemInstruction: systemPrompt,
          }
        });

        return response.text || "I'm having trouble thinking right now.";

      } catch (error) {
        console.error("Gemini Storefront Error:", error);
        return "I'm currently offline. Please try again later.";
      }
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { AppData, Product, CartItem, PaymentMethod, Transaction, Settings, Customer, AIChat } from '../types';
import { chatWithStoreAssistant } from '../services/gemini';
import { ShoppingBag, Search, ShoppingCart, Plus, Minus, X, CheckCircle, ArrowLeft, ArrowRight, Truck, ShieldCheck, MapPin, User, Phone, Smartphone, Bike, Store, Loader2, Gift, Clock, Sparkles, TrendingDown, MessageCircle, Bot, Send, Zap, Heart } from 'lucide-react';

interface StorefrontProps {
  data: AppData;
  settings: Settings;
  onUpdate: (data: AppData) => void;
  onBackToAdmin: () => void;
}

const Storefront: React.FC<StorefrontProps> = ({ data, settings, onUpdate, onBackToAdmin }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Filters
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [sizeFilter, setSizeFilter] = useState('All');

  // Checkout State
  const [checkoutStep, setCheckoutStep] = useState<'CART' | 'DETAILS' | 'PAYMENT' | 'PROCESSING' | 'SUCCESS'>('CART');
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [address, setAddress] = useState('');
  const [deliveryMode, setDeliveryMode] = useState<'DELIVERY' | 'PICKUP'>('DELIVERY');
  const [consentToPromotions, setConsentToPromotions] = useState(false);
  const [momoNetwork, setMomoNetwork] = useState<'MTN' | 'TELECEL' | 'AT'>('MTN');
  const [momoNumber, setMomoNumber] = useState('');

  // AI Chat State
  const [isAiChatOpen, setIsAiChatOpen] = useState(false);
  const [aiChatHistory, setAiChatHistory] = useState<{sender: 'user' | 'bot', text: string}[]>([
      {sender: 'bot', text: "Hello! I'm your LinenLogic skincare assistant. Looking for something specific for your skin type?"}
  ]);
  const [aiInput, setAiInput] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const chatScrollRef = useRef<HTMLDivElement>(null);

  // Scroll to bottom of chat
  useEffect(() => {
      chatScrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [aiChatHistory, isAiChatOpen]);

  // --- Logic ---
  const filteredProducts = useMemo(() => {
    return data.products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCat = categoryFilter === 'All' || p.category === categoryFilter;
      const matchesSize = sizeFilter === 'All' || p.size === sizeFilter;
      return !p.isArchived && p.stock > 0 && matchesSearch && matchesCat && matchesSize;
    });
  }, [data.products, searchTerm, categoryFilter, sizeFilter]);

  // Active Bundles Logic
  const activeBundles = useMemo(() => {
    const now = new Date();
    return (data.promotions || []).filter(p => {
        const start = new Date(p.startDate);
        const end = new Date(p.endDate);
        return p.isActive && now >= start && now <= end;
    }).map(promo => {
        let originalPrice = 0;
        let maxStock = 9999;

        promo.items.forEach(item => {
            const product = data.products.find(p => p.id === item.productId);
            if (product) {
                originalPrice += (product.sellPrice * item.quantity);
                const itemStockLimit = Math.floor(product.stock / item.quantity);
                if (itemStockLimit < maxStock) maxStock = itemStockLimit;
            }
        });

        const end = new Date(promo.endDate);
        const diffTime = Math.abs(end.getTime() - now.getTime());
        const daysRemaining = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

        return {
            ...promo,
            originalPrice,
            savings: originalPrice - promo.price,
            stock: maxStock,
            daysRemaining
        };
    }).filter(b => b.stock > 0);
  }, [data.promotions, data.products]);

  const addToCart = (product: Product, isPromo = false, promoItems: {productId: string, quantity: number}[] = []) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, discount: 0, isPromotion: isPromo, promotionItems }];
    });
    setIsCartOpen(true);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.sellPrice * item.quantity), 0);

  // --- Payment & Order Logic ---
  const handleProcessPayment = async () => {
      if (!momoNumber || momoNumber.length < 10) {
          alert("Please enter a valid Mobile Money number.");
          return;
      }
      setCheckoutStep('PROCESSING');
      // Simulate API
      await new Promise(resolve => setTimeout(resolve, 3000));
      completeOrder();
  };

  const completeOrder = () => {
    const orderItems = cart.map(item => {
        let buyPriceAtMoment = item.buyPrice;
        if (item.isPromotion && item.promotionItems) {
            let totalCost = 0;
            item.promotionItems.forEach(pi => {
                const p = data.products.find(prod => prod.id === pi.productId);
                if (p) totalCost += (p.buyPrice * pi.quantity);
            });
            buyPriceAtMoment = totalCost;
        }
        return {
            productId: item.id,
            productName: item.name,
            quantity: item.quantity,
            priceAtMoment: item.sellPrice,
            buyPriceAtMoment: buyPriceAtMoment,
            discount: 0,
            isPromotion: item.isPromotion
        };
    });

    const totalProfit = orderItems.reduce((acc, item) => acc + ((item.priceAtMoment - item.buyPriceAtMoment) * item.quantity), 0);

    const newTransaction: Transaction = {
      id: crypto.randomUUID(),
      type: 'SALE',
      source: 'ONLINE',
      status: 'PENDING',
      paymentStatus: 'PAID',
      date: new Date().toISOString(),
      paymentMethod: PaymentMethod.MOMO, 
      totalAmount: cartTotal,
      profit: totalProfit,
      deliveryMode: deliveryMode,
      momoDetails: { network: momoNetwork, number: momoNumber },
      deliveryDetails: {
        customerName,
        customerPhone,
        address: deliveryMode === 'PICKUP' ? 'Store Pickup' : address
      },
      items: orderItems
    };

    let updatedCustomers = [...(data.customers || [])];
    if (consentToPromotions) {
      const existingCustomerIndex = updatedCustomers.findIndex(c => c.phone === customerPhone);
      if (existingCustomerIndex > -1) {
        updatedCustomers[existingCustomerIndex] = {
          ...updatedCustomers[existingCustomerIndex],
          name: customerName,
          totalSpent: updatedCustomers[existingCustomerIndex].totalSpent + cartTotal
        };
      } else {
        updatedCustomers.push({
          id: crypto.randomUUID(),
          name: customerName,
          phone: customerPhone,
          totalSpent: cartTotal,
          joinedDate: new Date().toISOString()
        });
      }
    }

    const updatedProducts = [...data.products];
    cart.forEach(cartItem => {
        if (cartItem.isPromotion && cartItem.promotionItems) {
            cartItem.promotionItems.forEach(promoItem => {
                 const pIndex = updatedProducts.findIndex(p => p.id === promoItem.productId);
                 if (pIndex > -1) updatedProducts[pIndex] = { ...updatedProducts[pIndex], stock: updatedProducts[pIndex].stock - (promoItem.quantity * cartItem.quantity) };
            });
        } else {
            const pIndex = updatedProducts.findIndex(p => p.id === cartItem.id);
            if (pIndex > -1) updatedProducts[pIndex] = { ...updatedProducts[pIndex], stock: updatedProducts[pIndex].stock - cartItem.quantity };
        }
    });

    onUpdate({
      ...data,
      products: updatedProducts,
      transactions: [newTransaction, ...data.transactions],
      customers: updatedCustomers
    });

    setCheckoutStep('SUCCESS');
    setCart([]);
  };

  // --- AI Chat Logic ---
  const handleAiSend = async () => {
      if (!aiInput.trim()) return;

      const userMsg = aiInput;
      setAiChatHistory(prev => [...prev, {sender: 'user', text: userMsg}]);
      setAiInput('');
      setAiLoading(true);

      const apiKey = process.env.API_KEY || ''; // In real app, secure backend proxy
      const response = await chatWithStoreAssistant(userMsg, data.products, apiKey);

      setAiChatHistory(prev => [...prev, {sender: 'bot', text: response}]);
      setAiLoading(false);
  };

  const handleWhatsApp = () => {
      const msg = "Hello LinenLogic! I'm browsing your website and have some questions about your towels.";
      window.open(`https://wa.me/233240000000?text=${encodeURIComponent(msg)}`, '_blank'); // Replace with real number
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans relative overflow-x-hidden selection:bg-purple-200">

      {/* --- ARTISTIC HERO SECTION --- */}
      <div className="relative bg-slate-900 text-white pb-32 overflow-hidden">
         {/* Abstract Shapes */}
         <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-purple-600 rounded-full mix-blend-multiply filter blur-[128px] opacity-20 animate-pulse"></div>
         <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-indigo-600 rounded-full mix-blend-multiply filter blur-[128px] opacity-20"></div>

         <nav className="relative z-10 max-w-7xl mx-auto px-6 py-6 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-white/10 backdrop-blur-md rounded-lg flex items-center justify-center border border-white/20">
                    <Sparkles size={16} className="text-purple-300"/>
                </div>
                <span className="text-xl font-bold tracking-tight">LinenLogic</span>
            </div>
            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-3 hover:bg-white/10 rounded-full transition-all group"
            >
              <ShoppingBag size={24} className="text-white group-hover:scale-110 transition-transform"/>
              {cart.length > 0 && (
                <span className="absolute top-1 right-1 bg-purple-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-slate-900">
                  {cart.reduce((a,b) => a + b.quantity, 0)}
                </span>
              )}
            </button>
         </nav>

         <div className="relative z-10 max-w-4xl mx-auto text-center mt-12 px-4 space-y-6">
            <span className="inline-block px-4 py-1 rounded-full border border-white/20 bg-white/5 backdrop-blur-sm text-xs font-medium tracking-wider uppercase text-purple-200">Premium Skincare Essentials</span>
            <h1 className="text-5xl md:text-7xl font-bold leading-tight tracking-tight">
               Experience the Art of <br/> <span className="text-transparent bg-clip-text bg-gradient-to-r from-purple-300 to-indigo-300">Softness.</span>
            </h1>
            <p className="text-lg text-slate-300 max-w-xl mx-auto font-light leading-relaxed">
               Elevate your daily routine with our curated collection of ultra-absorbent, gentle towels designed specifically for skincare enthusiasts.
            </p>
