              </div>

              {/* Chat Body */}
              <div className="flex-1 bg-slate-50 overflow-y-auto p-4 space-y-4">
                  {aiChatHistory.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
