            const pIndex = updatedProducts.findIndex(p => p.id === cartItem.id);
            if (pIndex > -1) updatedProducts[pIndex] = { ...updatedProducts[pIndex], stock: updatedProducts[pIndex].stock - cartItem.quantity };
        }
    });

